export enum AppView {
  DASHBOARD = 'DASHBOARD',
  SIGN_DOC = 'SIGN_DOC',
  RENT_RECEIPT = 'RENT_RECEIPT',
  VIEW_DOC = 'VIEW_DOC'
}

export interface UserSignature {
  id: string;
  dataUrl: string;
  label: string;
  createdAt: string;
}

export interface DocumentRecord {
  id: string;
  name: string;
  type: 'PDF' | 'IMAGE' | 'RECEIPT';
  status: 'SIGNED' | 'PENDING' | 'DRAFT';
  date: string;
