        <button onClick={() => setCurrentView(AppView.DASHBOARD)} className={`flex flex-col items-center gap-1 ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">🏠</span>
