    { id: '2', name: 'Office Agreement.pdf', type: 'PDF', status: 'PENDING', date: '05 Jan 2024' },
  ]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);

  const docContainerRef = useRef<HTMLDivElement>(null);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
  };

  const startNewSignWorkflow = () => {
    resetSigningState();
    setCurrentView(AppView.SIGN_DOC);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
      };
      reader.readAsDataURL(file);
    }
  };

  const saveSignature = (dataUrl: string) => {
    const newSign: UserSignature = {
      id: Date.now().toString(),
      dataUrl,
      label: 'My Signature',
      createdAt: new Date().toISOString()
    };
    setSignatures([newSign, ...signatures]);
    setShowSignaturePad(false);
  };

  const handleReceiptComplete = (data: any) => {
    const newDoc: DocumentRecord = {
      id: Date.now().toString(),
      name: `Rent Receipt ${data.month} ${data.year}`,
      type: 'RECEIPT',
      status: 'PENDING',
      date: new Date().toLocaleDateString('en-IN')
    };
    setDocuments([newDoc, ...documents]);
    setActiveDoc(newDoc);
    setCurrentView(AppView.SIGN_DOC);
  };

  const handleSignFinish = () => {
    if (activeDoc) {
      setDocuments(docs => docs.map(d => d.id === activeDoc.id ? { 
        ...d, 
        status: 'SIGNED', 
        placedSignatures: [...placedSignatures] 
      } : d));
    } else {
      const newDoc: DocumentRecord = {
        id: Date.now().toString(),
        name: 'Signed Document',
        type: 'IMAGE',
        status: 'SIGNED',
        date: new Date().toLocaleDateString('en-IN'),
        placedSignatures: [...placedSignatures]
      };
      setDocuments([newDoc, ...documents]);
    }
    setShowSuccessScreen(true);
  };

  const handleDeleteDoc = (id: string) => {
    setDocuments(prev => prev.filter(d => d.id !== id));
    if (activeDoc?.id === id) {
      resetSigningState();
      setCurrentView(AppView.DASHBOARD);
    }
  };

  const handleDiscardDraft = () => {
    if (window.confirm("Are you sure you want to discard this draft? All placed signatures will be lost.")) {
      resetSigningState();
      setCurrentView(AppView.DASHBOARD);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 40, 
      y: 70,
      w: 25 // Default width %
    };
    setPlacedSignatures([...placedSignatures, newPlaced]);
  };

  const removePlacedSignature = (id: string) => {
    if (activeDoc?.status === 'SIGNED') return;
    setPlacedSignatures(placedSignatures.filter(ps => ps.id !== id));
  };

  const handleDrag = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    if (activeDoc?.status === 'SIGNED') return;
    const container = docContainerRef.current;
    if (!container) return;

    const rect = container.getBoundingClientRect();

    const moveHandler = (moveEvent: MouseEvent | TouchEvent) => {
      const clientX = 'touches' in moveEvent ? moveEvent.touches[0].clientX : (moveEvent as MouseEvent).clientX;
      const clientY = 'touches' in moveEvent ? moveEvent.touches[0].clientY : (moveEvent as MouseEvent).clientY;

      let xPercent = ((clientX - rect.left) / rect.width) * 100;
      let yPercent = ((clientY - rect.top) / rect.height) * 100;

      xPercent = Math.max(0, Math.min(90, xPercent));
      yPercent = Math.max(0, Math.min(95, yPercent));

      setPlacedSignatures(prev => prev.map(ps => ps.id === id ? { ...ps, x: xPercent, y: yPercent } : ps));
    };

    const stopHandler = () => {
      window.removeEventListener('mousemove', moveHandler);
      window.removeEventListener('mouseup', stopHandler);
      window.removeEventListener('touchmove', moveHandler);
      window.removeEventListener('touchend', stopHandler);
    };

    window.addEventListener('mousemove', moveHandler);
    window.addEventListener('mouseup', stopHandler);
    window.addEventListener('touchmove', moveHandler, { passive: false });
    window.addEventListener('touchend', stopHandler);
  };

  const handleResize = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    e.stopPropagation();
    if (activeDoc?.status === 'SIGNED') return;

    const container = docContainerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();

    const initialX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const targetSig = placedSignatures.find(s => s.id === id);
    if (!targetSig) return;

    const initialW = targetSig.w || 25;

    const moveHandler = (moveEvent: MouseEvent | TouchEvent) => {
      const currentX = 'touches' in moveEvent ? moveEvent.touches[0].clientX : (moveEvent as MouseEvent).clientX;
      const deltaX = currentX - initialX;
      const deltaWPercent = (deltaX / rect.width) * 100;

      let newW = initialW + deltaWPercent;
      newW = Math.max(5, Math.min(80, newW)); 

      setPlacedSignatures(prev => prev.map(ps => ps.id === id ? { ...ps, w: newW } : ps));
    };

    const stopHandler = () => {
      window.removeEventListener('mousemove', moveHandler);
      window.removeEventListener('mouseup', stopHandler);
      window.removeEventListener('touchmove', moveHandler);
      window.removeEventListener('touchend', stopHandler);
    };

    window.addEventListener('mousemove', moveHandler);
    window.addEventListener('mouseup', stopHandler);
    window.addEventListener('touchmove', moveHandler, { passive: false });
    window.addEventListener('touchend', stopHandler);
  };

  const handleDownload = async () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Set dimensions based on standard A4-ish ratio for receipts or the original image
    canvas.width = 1240;
    canvas.height = 1754;

    // Fill background
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const drawSignatures = async () => {
      for (const sig of placedSignatures) {
        const sigImg = new Image();
        sigImg.src = sig.dataUrl;
        await new Promise(resolve => { sigImg.onload = resolve; });

        const sigW = (canvas.width * (sig.w || 25)) / 100;
        const sigRatio = sigImg.height / sigImg.width;
        const sigH = sigW * sigRatio;
        const sigX = (canvas.width * sig.x) / 100;
        const sigY = (canvas.height * sig.y) / 100;

        ctx.drawImage(sigImg, sigX, sigY, sigW, sigH);
      }
    };

    if (uploadFile) {
      const bgImg = new Image();
      bgImg.src = uploadFile;
      await new Promise(resolve => { bgImg.onload = resolve; });

      // Adjust canvas to match image ratio
      const ratio = bgImg.height / bgImg.width;
      canvas.height = canvas.width * ratio;
      ctx.drawImage(bgImg, 0, 0, canvas.width, canvas.height);
      await drawSignatures();
    } else if (activeDoc?.type === 'RECEIPT') {
      // Draw professional Receipt template
      ctx.fillStyle = '#000000';
      ctx.textAlign = 'center';
      ctx.font = 'bold 60px Inter, Arial';
      ctx.fillText('RENT RECEIPT', canvas.width / 2, 150);

      ctx.beginPath();
      ctx.moveTo(100, 180);
      ctx.lineTo(canvas.width - 100, 180);
      ctx.stroke();

      ctx.textAlign = 'left';
      ctx.font = '40px Inter, Arial';
      const name = activeDoc.name.split('Receipt ')[1] || 'Valued Tenant';
      const lines = [
        `Received with thanks from: ${name}`,
        `Sum of: ₹ 15,000/- (Rupees Fifteen Thousand Only)`,
        `Towards Rent for: ${activeDoc.date || new Date().toLocaleDateString('en-IN')}`,
        `Property Address: H-Block, Sector 62, Noida, UP`,
        `Dated: ${activeDoc.date || new Date().toLocaleDateString('en-IN')}`,
      ];

      lines.forEach((line, i) => {
        ctx.fillText(line, 150, 350 + (i * 120));
      });

      ctx.font = 'italic 30px Inter, Arial';
      ctx.fillText('This is a computer generated document, HRA compliant.', 150, canvas.height - 150);

      await drawSignatures();
    }

    // Trigger Download
    const dataUrl = canvas.toDataURL('image/png');
    const link = document.createElement('a');
    link.download = `${activeDoc?.name || 'signed-doc'}.png`;
    link.href = dataUrl;
    link.click();
  };

  const isViewOnly = activeDoc?.status === 'SIGNED';

  return (
    <div className="min-h-screen pb-20 md:pb-0">
      <header className="bg-white border-b border-gray-100 sticky top-0 z-40 px-4 py-4 md:px-8">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-indigo-200">
              S
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900 tracking-tight">SignEase</h1>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Digital India</p>
            </div>
          </div>

          <div className="hidden md:flex gap-6">
            <button 
              onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}
              className={`text-sm font-semibold transition-colors ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-gray-500 hover:text-gray-900'}`}
            >
              Dashboard
            </button>
            <button className="text-sm font-semibold text-gray-500 hover:text-gray-900">Documents</button>
            <button className="text-sm font-semibold text-gray-500 hover:text-gray-900">Settings</button>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => setShowSignaturePad(true)}
              className="hidden md:block text-sm font-bold text-indigo-600 bg-indigo-50 px-4 py-2 rounded-lg hover:bg-indigo-100 transition-colors"
            >
              My Signatures
            </button>
            <div className="w-10 h-10 rounded-full bg-slate-200 overflow-hidden ring-2 ring-indigo-100">
              <img src="https://picsum.photos/40/40" alt="Avatar" />
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8">
        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-12 px-6 bg-white rounded-3xl shadow-xl border border-indigo-50 mt-10">
            <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6 animate-bounce">
              ✓
            </div>
            <h2 className="text-2xl font-bold text-gray-800 mb-2">Document Signed!</h2>
            <p className="text-gray-500 mb-8">Your document has been securely signed and moved to the completed list.</p>

            <div className="space-y-3">
              <button 
                onClick={handleDownload}
                className="w-full bg-indigo-600 text-white font-bold py-3 rounded-xl hover:bg-indigo-700 transition-all shadow-lg flex items-center justify-center gap-2"
              >
                <span>⬇️</span> Download Signed Copy
              </button>
              <button 
                onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}
                className="w-full bg-gray-100 text-gray-700 font-bold py-3 rounded-xl hover:bg-gray-200 transition-all"
              >
                Go to Dashboard
              </button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard 
                documents={documents} 
                onAction={(view) => {
                  if (view === AppView.SIGN_DOC) startNewSignWorkflow();
                  else setCurrentView(view);
                }} 
                onViewDoc={(doc) => {
                  setActiveDoc(doc);
                  setPlacedSignatures(doc.placedSignatures || []);
                  setCurrentView(AppView.SIGN_DOC);
                }} 
                onDeleteDoc={handleDeleteDoc}
              />
            )}

            {currentView === AppView.RENT_RECEIPT && (
              <RentReceiptCreator 
                onComplete={handleReceiptComplete}
                onCancel={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}
              />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="max-w-4xl mx-auto">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-bold text-gray-800">
                    {isViewOnly ? `View: ${activeDoc?.name}` : activeDoc ? `Signing: ${activeDoc.name}` : 'Sign Document'}
                  </h2>
                  <div className="flex gap-3">
                    {isViewOnly ? (
                      <button 
                        onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}
                        className="text-gray-500 font-semibold hover:text-gray-700 transition-colors flex items-center gap-2"
                      >
                        ✕ Close
                      </button>
                    ) : (
                      <button 
                        onClick={handleDiscardDraft}
                        className="text-red-500 font-semibold hover:text-red-700 transition-colors flex items-center gap-2"
                      >
                        <span>🗑️</span> <span className="hidden sm:inline">Discard Draft</span>
                      </button>
                    )}
                  </div>
                </div>

                {!uploadFile && !activeDoc && (
                  <div className="border-2 border-dashed border-gray-200 rounded-3xl p-12 text-center bg-white">
                    <div className="text-6xl mb-6">📁</div>
                    <h3 className="text-xl font-bold text-gray-800 mb-2">Upload File to Sign</h3>
                    <p className="text-gray-500 mb-8 max-w-sm mx-auto">
                      Drag and drop your PDF or Image here. We support all Indian legal documents.
                    </p>
                    <label className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold cursor-pointer hover:bg-indigo-700 shadow-xl transition-all inline-block">
                      Browse Files
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="bg-white rounded-3xl shadow-sm border border-gray-100 p-4 min-h-[500px] flex flex-col">
                    <div 
                      ref={docContainerRef}
                      className="flex-1 flex items-center justify-center bg-gray-50 rounded-2xl relative overflow-hidden select-none"
                    >
                      {uploadFile ? (
                        <img src={uploadFile} alt="Preview" className="max-h-full object-contain shadow-lg" />
                      ) : activeDoc?.type === 'RECEIPT' ? (
                        <div className="p-10 bg-white shadow-lg w-full max-w-md min-h-[400px] relative">
                           <h1 className="text-xl font-bold text-center border-b pb-4 mb-4 uppercase tracking-tighter">Rent Receipt</h1>
                           <div className="space-y-4 text-sm text-gray-700">
                              <p>Received with thanks from <strong>{activeDoc?.name.split('Receipt ')[1]}</strong></p>
                              <p>the sum of <strong>₹ 15,000/-</strong> (Rupees Fifteen Thousand Only)</p>
                              <p>towards rent for the property at: <strong>H-Block, Sector 62, Noida, UP</strong></p>
                              <p className="mt-8 pt-8">Dated: {activeDoc?.date || new Date().toLocaleDateString('en-IN')}</p>
                           </div>
                        </div>
                      ) : (
                        <div className="p-20 text-center text-gray-400">
                          <p>Document preview unavailable for this type.</p>
                        </div>
                      )}

                      {placedSignatures.map(ps => (
                        <div 
                          key={ps.id}
                          style={{ 
                            left: `${ps.x}%`, 
                            top: `${ps.y}%`, 
                            width: `${ps.w || 25}%` 
                          }}
                          className={`absolute group ${isViewOnly ? 'pointer-events-none' : 'cursor-move touch-none'} z-10`}
                          onMouseDown={(e) => handleDrag(ps.id, e)}
                          onTouchStart={(e) => handleDrag(ps.id, e)}
                        >
                          <div className="relative">
                             <img 
                              src={ps.dataUrl} 
                              alt="Signature" 
                              className={`w-full h-auto mix-blend-multiply border border-dashed ${isViewOnly ? 'border-transparent' : 'border-indigo-400 group-hover:border-indigo-600'} bg-transparent p-1 pointer-events-none transition-all`} 
                            />
                            {!isViewOnly && (
                              <>
                                <button 
                                  onClick={(e) => { e.stopPropagation(); removePlacedSignature(ps.id); }}
                                  className="absolute -top-3 -right-3 bg-red-500 text-white w-6 h-6 rounded-full flex items-center justify-center text-[10px] shadow-md opacity-0 group-hover:opacity-100 transition-opacity z-20"
                                >
                                  ✕
                                </button>
                                <div 
                                  className="absolute -bottom-2 -right-2 w-5 h-5 bg-indigo-600 border-2 border-white rounded-full cursor-nwse-resize shadow-md opacity-0 group-hover:opacity-100 transition-opacity z-20"
                                  onMouseDown={(e) => handleResize(ps.id, e)}
                                  onTouchStart={(e) => handleResize(ps.id, e)}
                                />
                              </>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>

                    <div className="mt-6 flex flex-col md:flex-row gap-4 items-center justify-between border-t pt-6">
                      {isViewOnly ? (
                        <div className="w-full flex justify-between items-center">
                          <p className="text-sm text-gray-500">Document finalized on {activeDoc?.date}</p>
                          <div className="flex gap-3">
                            <button 
                              onClick={handleDownload}
                              className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg flex items-center gap-2"
                            >
                              <span>⬇️</span> Download Signed Doc
                            </button>
                          </div>
                        </div>
                      ) : (
                        <>
                          <div className="w-full md:w-auto overflow-hidden">
                            <p className="text-xs font-bold text-gray-400 uppercase mb-2">Click signature to place</p>
                            <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                              {signatures.length === 0 && (
                                <p className="text-xs text-gray-400 italic">No saved signatures yet.</p>
                              )}
                              {signatures.map(s => (
                                <button 
                                  key={s.id} 
                                  onClick={() => placeSignature(s)}
                                  className="flex-shrink-0 w-24 h-12 bg-slate-50 border border-gray-100 rounded-lg hover:border-indigo-400 hover:bg-indigo-50 transition-all flex items-center justify-center p-1"
                                >
                                  <img src={s.dataUrl} alt="Sign" className="max-h-full mix-blend-multiply" />
                                </button>
                              ))}
                              <button 
                                onClick={() => setShowSignaturePad(true)}
                                className="flex-shrink-0 w-12 h-12 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center border border-dashed border-indigo-200 hover:bg-indigo-100"
                              >
                                +
                              </button>
                            </div>
                          </div>

                          <div className="flex gap-3 w-full md:w-auto">
                            <button 
                              className="flex-1 md:flex-none px-6 py-3 bg-white border border-gray-200 rounded-xl font-bold text-gray-700 hover:bg-gray-50 flex items-center justify-center gap-2"
                              onClick={() => {
                                const link = "https://signease.in/s/req-" + Math.floor(Math.random() * 10000);
                                alert(`Sharing request link to WhatsApp...`);
                                window.open(`https://wa.me/?text=Please sign this document on SignEase: ${link}`, '_blank');
                              }}
                            >
                              <span>🔗</span> Share Link
                            </button>
                            <button 
                              onClick={handleSignFinish}
                              className="flex-1 md:flex-none px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100 disabled:opacity-50 disabled:cursor-not-allowed"
                              disabled={placedSignatures.length === 0}
                            >
                              Finish & Save
                            </button>
                          </div>
                        </>
                      )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && (
        <SignaturePad 
          onSave={saveSignature}
          onCancel={() => setShowSignaturePad(false)}
        />
      )}

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 flex justify-around items-center py-3 md:hidden z-50">
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className={`flex flex-col items-center gap-1 ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">🏠</span>
          <span className="text-[10px] font-bold">Home</span>
        </button>
        <button onClick={startNewSignWorkflow} className={`flex flex-col items-center gap-1 ${currentView === AppView.SIGN_DOC ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">✍️</span>
          <span className="text-[10px] font-bold">Sign</span>
        </button>
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.RENT_RECEIPT); }} className={`flex flex-col items-center gap-1 ${currentView === AppView.RENT_RECEIPT ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">📜</span>
          <span className="text-[10px] font-bold">Receipt</span>
        </button>
        <button className="flex flex-col items-center gap-1 text-gray-400">
          <span className="text-xl">👤</span>
          <span className="text-[10px] font-bold">Profile</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import RentReceiptCreator from './components/RentReceiptCreator';
import SignaturePad from './components/SignaturePad';

// Add type declaration for jsPDF since we're using CDN
declare const jspdf: any;

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([
    { id: '1', name: 'Rent Receipt Jan 2024', type: 'RECEIPT', status: 'SIGNED', date: '12 Jan 2024', placedSignatures: [{ id: 's1', dataUrl: 'data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8/5+hHgAHggJ/PchI7wAAAABJRU5ErkJggg==', x: 50, y: 80, w: 20 }] },
    { id: '2', name: 'Office Agreement.pdf', type: 'PDF', status: 'PENDING', date: '05 Jan 2024' },
  ]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);

  const docContainerRef = useRef<HTMLDivElement>(null);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
  };

  const startNewSignWorkflow = () => {
    resetSigningState();
    setCurrentView(AppView.SIGN_DOC);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
      };
      reader.readAsDataURL(file);
    }
  };

  const saveSignature = (dataUrl: string) => {
    const newSign: UserSignature = {
      id: Date.now().toString(),
      dataUrl,
      label: 'My Signature',
      createdAt: new Date().toISOString()
    };
    setSignatures([newSign, ...signatures]);
    setShowSignaturePad(false);
  };

  const handleReceiptComplete = (data: any) => {
    const newDoc: DocumentRecord = {
      id: Date.now().toString(),
      name: `Rent Receipt ${data.month} ${data.year}`,
      type: 'RECEIPT',
      status: 'PENDING',
      date: new Date().toLocaleDateString('en-IN')
    };
    setDocuments([newDoc, ...documents]);
    setActiveDoc(newDoc);
    setCurrentView(AppView.SIGN_DOC);
  };

  const handleSignFinish = () => {
    if (activeDoc) {
      setDocuments(docs => docs.map(d => d.id === activeDoc.id ? { 
        ...d, 
        status: 'SIGNED', 
        placedSignatures: [...placedSignatures] 
      } : d));
    } else {
      const newDoc: DocumentRecord = {
        id: Date.now().toString(),
        name: 'Signed Document',
        type: 'IMAGE',
        status: 'SIGNED',
        date: new Date().toLocaleDateString('en-IN'),
        placedSignatures: [...placedSignatures]
      };
      setDocuments([newDoc, ...documents]);
    }
    setShowSuccessScreen(true);
  };

  const handleDeleteDoc = (id: string) => {
    setDocuments(prev => prev.filter(d => d.id !== id));
    if (activeDoc?.id === id) {
      resetSigningState();
      setCurrentView(AppView.DASHBOARD);
    }
  };

  const handleDiscardDraft = () => {
    if (window.confirm("Are you sure you want to discard this draft? All placed signatures will be lost.")) {
      resetSigningState();
      setCurrentView(AppView.DASHBOARD);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 40, 
      y: 70,
      w: 25 
    };
    setPlacedSignatures([...placedSignatures, newPlaced]);
  };

  const removePlacedSignature = (id: string) => {
    if (activeDoc?.status === 'SIGNED') return;
    setPlacedSignatures(placedSignatures.filter(ps => ps.id !== id));
  };

  const handleDrag = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    if (activeDoc?.status === 'SIGNED') return;
    const container = docContainerRef.current;
    if (!container) return;

    const rect = container.getBoundingClientRect();

    const moveHandler = (moveEvent: MouseEvent | TouchEvent) => {
      const clientX = 'touches' in moveEvent ? moveEvent.touches[0].clientX : (moveEvent as MouseEvent).clientX;
      const clientY = 'touches' in moveEvent ? moveEvent.touches[0].clientY : (moveEvent as MouseEvent).clientY;

      let xPercent = ((clientX - rect.left) / rect.width) * 100;
      let yPercent = ((clientY - rect.top) / rect.height) * 100;

      xPercent = Math.max(0, Math.min(90, xPercent));
      yPercent = Math.max(0, Math.min(95, yPercent));

      setPlacedSignatures(prev => prev.map(ps => ps.id === id ? { ...ps, x: xPercent, y: yPercent } : ps));
    };

    const stopHandler = () => {
      window.removeEventListener('mousemove', moveHandler);
      window.removeEventListener('mouseup', stopHandler);
      window.removeEventListener('touchmove', moveHandler);
      window.removeEventListener('touchend', stopHandler);
    };

    window.addEventListener('mousemove', moveHandler);
    window.addEventListener('mouseup', stopHandler);
    window.addEventListener('touchmove', moveHandler, { passive: false });
    window.addEventListener('touchend', stopHandler);
  };

  const handleResize = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    e.stopPropagation();
    if (activeDoc?.status === 'SIGNED') return;

    const container = docContainerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();

    const initialX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const targetSig = placedSignatures.find(s => s.id === id);
    if (!targetSig) return;

    const initialW = targetSig.w || 25;

    const moveHandler = (moveEvent: MouseEvent | TouchEvent) => {
      const currentX = 'touches' in moveEvent ? moveEvent.touches[0].clientX : (moveEvent as MouseEvent).clientX;
      const deltaX = currentX - initialX;
      const deltaWPercent = (deltaX / rect.width) * 100;

      let newW = initialW + deltaWPercent;
      newW = Math.max(5, Math.min(80, newW)); 

      setPlacedSignatures(prev => prev.map(ps => ps.id === id ? { ...ps, w: newW } : ps));
    };

    const stopHandler = () => {
      window.removeEventListener('mousemove', moveHandler);
      window.removeEventListener('mouseup', stopHandler);
      window.removeEventListener('touchmove', moveHandler);
      window.removeEventListener('touchend', stopHandler);
    };

    window.addEventListener('mousemove', moveHandler);
    window.addEventListener('mouseup', stopHandler);
    window.addEventListener('touchmove', moveHandler, { passive: false });
    window.addEventListener('touchend', stopHandler);
  };

  const handleDownload = async () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // A4 resolution at 150 DPI approx (1240 x 1754)
    canvas.width = 1240;
    canvas.height = 1754;

    // Fill background
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const drawSignatures = async () => {
      for (const sig of placedSignatures) {
        const sigImg = new Image();
        sigImg.src = sig.dataUrl;
        await new Promise(resolve => { sigImg.onload = resolve; });

        const sigW = (canvas.width * (sig.w || 25)) / 100;
        const sigRatio = sigImg.height / sigImg.width;
        const sigH = sigW * sigRatio;
        const sigX = (canvas.width * sig.x) / 100;
        const sigY = (canvas.height * sig.y) / 100;

        ctx.drawImage(sigImg, sigX, sigY, sigW, sigH);
      }
    };

    if (uploadFile) {
      const bgImg = new Image();
      bgImg.src = uploadFile;
      await new Promise(resolve => { bgImg.onload = resolve; });

      // Adjust canvas to match image ratio
      const ratio = bgImg.height / bgImg.width;
      canvas.height = canvas.width * ratio;
      ctx.drawImage(bgImg, 0, 0, canvas.width, canvas.height);
      await drawSignatures();
    } else if (activeDoc?.type === 'RECEIPT') {
      ctx.fillStyle = '#000000';
      ctx.textAlign = 'center';
      ctx.font = 'bold 60px Inter, Arial';
      ctx.fillText('RENT RECEIPT', canvas.width / 2, 150);

      ctx.beginPath();
      ctx.moveTo(100, 180);
      ctx.lineTo(canvas.width - 100, 180);
      ctx.lineWidth = 2;
      ctx.stroke();

      ctx.textAlign = 'left';
      ctx.font = '40px Inter, Arial';
      const name = activeDoc.name.split('Receipt ')[1] || 'Valued Tenant';
      const lines = [
        `Received with thanks from: ${name}`,
        `Sum of: ₹ 15,000/- (Rupees Fifteen Thousand Only)`,
        `Towards Rent for: ${activeDoc.date || new Date().toLocaleDateString('en-IN')}`,
        `Property Address: H-Block, Sector 62, Noida, UP`,
        `Dated: ${activeDoc.date || new Date().toLocaleDateString('en-IN')}`,
      ];

      lines.forEach((line, i) => {
        ctx.fillText(line, 150, 350 + (i * 120));
      });

      ctx.font = 'italic 30px Inter, Arial';
      ctx.fillText('This is a computer generated document, HRA compliant.', 150, canvas.height - 150);

      await drawSignatures();
    }

    // PDF Generation
    const dataUrl = canvas.toDataURL('image/jpeg', 0.95);
    const pdf = new jspdf.jsPDF({
      orientation: canvas.width > canvas.height ? 'l' : 'p',
      unit: 'px',
      format: [canvas.width, canvas.height]
    });

    pdf.addImage(dataUrl, 'JPEG', 0, 0, canvas.width, canvas.height);
    pdf.save(`${activeDoc?.name || 'signed-document'}.pdf`);
  };

  const isViewOnly = activeDoc?.status === 'SIGNED';

  return (
    <div className="min-h-screen pb-20 md:pb-0">
      <header className="bg-white border-b border-gray-100 sticky top-0 z-40 px-4 py-4 md:px-8">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-indigo-200">
              S
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900 tracking-tight">SignEase</h1>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Digital India</p>
            </div>
          </div>

          <div className="hidden md:flex gap-6">
            <button 
              onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}
              className={`text-sm font-semibold transition-colors ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-gray-500 hover:text-gray-900'}`}
            >
              Dashboard
            </button>
            <button className="text-sm font-semibold text-gray-500 hover:text-gray-900">Documents</button>
            <button className="text-sm font-semibold text-gray-500 hover:text-gray-900">Settings</button>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => setShowSignaturePad(true)}
              className="hidden md:block text-sm font-bold text-indigo-600 bg-indigo-50 px-4 py-2 rounded-lg hover:bg-indigo-100 transition-colors"
            >
              My Signatures
            </button>
            <div className="w-10 h-10 rounded-full bg-slate-200 overflow-hidden ring-2 ring-indigo-100">
              <img src="https://picsum.photos/40/40" alt="Avatar" />
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8">
        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-12 px-6 bg-white rounded-3xl shadow-xl border border-indigo-50 mt-10">
            <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6 animate-bounce">
              ✓
            </div>
            <h2 className="text-2xl font-bold text-gray-800 mb-2">Document Signed!</h2>
            <p className="text-gray-500 mb-8">Your document has been securely signed and moved to the completed list.</p>

            <div className="space-y-3">
              <button 
                onClick={handleDownload}
                className="w-full bg-indigo-600 text-white font-bold py-3 rounded-xl hover:bg-indigo-700 transition-all shadow-lg flex items-center justify-center gap-2"
              >
                <span>⬇️</span> Download PDF
              </button>
              <button 
                onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}
                className="w-full bg-gray-100 text-gray-700 font-bold py-3 rounded-xl hover:bg-gray-200 transition-all"
              >
                Go to Dashboard
              </button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard 
                documents={documents} 
                onAction={(view) => {
                  if (view === AppView.SIGN_DOC) startNewSignWorkflow();
                  else setCurrentView(view);
                }} 
                onViewDoc={(doc) => {
                  setActiveDoc(doc);
                  setPlacedSignatures(doc.placedSignatures || []);
                  setCurrentView(AppView.SIGN_DOC);
                }} 
                onDeleteDoc={handleDeleteDoc}
              />
            )}

            {currentView === AppView.RENT_RECEIPT && (
              <RentReceiptCreator 
                onComplete={handleReceiptComplete}
                onCancel={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}
              />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="max-w-4xl mx-auto">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-bold text-gray-800">
                    {isViewOnly ? `View: ${activeDoc?.name}` : activeDoc ? `Signing: ${activeDoc.name}` : 'Sign Document'}
                  </h2>
                  <div className="flex gap-3">
                    {isViewOnly ? (
                      <button 
                        onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}
                        className="text-gray-500 font-semibold hover:text-gray-700 transition-colors flex items-center gap-2"
                      >
                        ✕ Close
                      </button>
                    ) : (
                      <button 
                        onClick={handleDiscardDraft}
                        className="text-red-500 font-semibold hover:text-red-700 transition-colors flex items-center gap-2"
                      >
                        <span>🗑️</span> <span className="hidden sm:inline">Discard Draft</span>
                      </button>
                    )}
                  </div>
                </div>

                {!uploadFile && !activeDoc && (
                  <div className="border-2 border-dashed border-gray-200 rounded-3xl p-12 text-center bg-white">
                    <div className="text-6xl mb-6">📁</div>
                    <h3 className="text-xl font-bold text-gray-800 mb-2">Upload File to Sign</h3>
                    <p className="text-gray-500 mb-8 max-w-sm mx-auto">
                      Drag and drop your PDF or Image here. We support all Indian legal documents.
                    </p>
                    <label className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold cursor-pointer hover:bg-indigo-700 shadow-xl transition-all inline-block">
                      Browse Files
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="bg-white rounded-3xl shadow-sm border border-gray-100 p-4 min-h-[500px] flex flex-col">
                    <div 
                      ref={docContainerRef}
                      className="flex-1 flex items-center justify-center bg-gray-50 rounded-2xl relative overflow-hidden select-none"
                    >
                      {uploadFile ? (
                        <img src={uploadFile} alt="Preview" className="max-h-full object-contain shadow-lg" />
                      ) : activeDoc?.type === 'RECEIPT' ? (
                        <div className="p-10 bg-white shadow-lg w-full max-w-md min-h-[400px] relative">
                           <h1 className="text-xl font-bold text-center border-b pb-4 mb-4 uppercase tracking-tighter">Rent Receipt</h1>
                           <div className="space-y-4 text-sm text-gray-700">
                              <p>Received with thanks from <strong>{activeDoc?.name.split('Receipt ')[1]}</strong></p>
                              <p>the sum of <strong>₹ 15,000/-</strong> (Rupees Fifteen Thousand Only)</p>
                              <p>towards rent for the property at: <strong>H-Block, Sector 62, Noida, UP</strong></p>
                              <p className="mt-8 pt-8">Dated: {activeDoc?.date || new Date().toLocaleDateString('en-IN')}</p>
                           </div>
                        </div>
                      ) : (
                        <div className="p-20 text-center text-gray-400">
                          <p>Document preview unavailable for this type.</p>
                        </div>
                      )}

                      {placedSignatures.map(ps => (
                        <div 
                          key={ps.id}
                          style={{ 
                            left: `${ps.x}%`, 
                            top: `${ps.y}%`, 
                            width: `${ps.w || 25}%` 
                          }}
                          className={`absolute group ${isViewOnly ? 'pointer-events-none' : 'cursor-move touch-none'} z-10`}
                          onMouseDown={(e) => handleDrag(ps.id, e)}
                          onTouchStart={(e) => handleDrag(ps.id, e)}
                        >
                          <div className="relative">
                             <img 
                              src={ps.dataUrl} 
                              alt="Signature" 
                              className={`w-full h-auto mix-blend-multiply border border-dashed ${isViewOnly ? 'border-transparent' : 'border-indigo-400 group-hover:border-indigo-600'} bg-transparent p-1 pointer-events-none transition-all`} 
                            />
                            {!isViewOnly && (
                              <>
                                <button 
                                  onClick={(e) => { e.stopPropagation(); removePlacedSignature(ps.id); }}
                                  className="absolute -top-3 -right-3 bg-red-500 text-white w-6 h-6 rounded-full flex items-center justify-center text-[10px] shadow-md opacity-0 group-hover:opacity-100 transition-opacity z-20"
                                >
                                  ✕
                                </button>
                                <div 
                                  className="absolute -bottom-2 -right-2 w-5 h-5 bg-indigo-600 border-2 border-white rounded-full cursor-nwse-resize shadow-md opacity-0 group-hover:opacity-100 transition-opacity z-20"
                                  onMouseDown={(e) => handleResize(ps.id, e)}
                                  onTouchStart={(e) => handleResize(ps.id, e)}
                                />
                              </>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>

                    <div className="mt-6 flex flex-col md:flex-row gap-4 items-center justify-between border-t pt-6">
                      {isViewOnly ? (
                        <div className="w-full flex justify-between items-center">
                          <p className="text-sm text-gray-500">Document finalized on {activeDoc?.date}</p>
                          <div className="flex gap-3">
                            <button 
                              onClick={handleDownload}
                              className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg flex items-center gap-2"
                            >
                              <span>⬇️</span> Download PDF
                            </button>
                          </div>
                        </div>
                      ) : (
                        <>
                          <div className="w-full md:w-auto overflow-hidden">
                            <p className="text-xs font-bold text-gray-400 uppercase mb-2">Click signature to place</p>
                            <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                              {signatures.length === 0 && (
                                <p className="text-xs text-gray-400 italic">No saved signatures yet.</p>
                              )}
                              {signatures.map(s => (
                                <button 
                                  key={s.id} 
                                  onClick={() => placeSignature(s)}
                                  className="flex-shrink-0 w-24 h-12 bg-slate-50 border border-gray-100 rounded-lg hover:border-indigo-400 hover:bg-indigo-50 transition-all flex items-center justify-center p-1"
                                >
                                  <img src={s.dataUrl} alt="Sign" className="max-h-full mix-blend-multiply" />
                                </button>
                              ))}
                              <button 
                                onClick={() => setShowSignaturePad(true)}
                                className="flex-shrink-0 w-12 h-12 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center border border-dashed border-indigo-200 hover:bg-indigo-100"
                              >
                                +
                              </button>
                            </div>
                          </div>

                          <div className="flex gap-3 w-full md:w-auto">
                            <button 
                              className="flex-1 md:flex-none px-6 py-3 bg-white border border-gray-200 rounded-xl font-bold text-gray-700 hover:bg-gray-50 flex items-center justify-center gap-2"
                              onClick={() => {
                                const link = "https://signease.in/s/req-" + Math.floor(Math.random() * 10000);
                                alert(`Sharing request link to WhatsApp...`);
                                window.open(`https://wa.me/?text=Please sign this document on SignEase: ${link}`, '_blank');
                              }}
                            >
                              <span>🔗</span> Share Link
                            </button>
                            <button 
                              onClick={handleSignFinish}
                              className="flex-1 md:flex-none px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100 disabled:opacity-50 disabled:cursor-not-allowed"
                              disabled={placedSignatures.length === 0}
                            >
                              Finish & Save
                            </button>
                          </div>
                        </>
                      )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && (
        <SignaturePad 
          onSave={saveSignature}
          onCancel={() => setShowSignaturePad(false)}
        />
      )}

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 flex justify-around items-center py-3 md:hidden z-50">
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className={`flex flex-col items-center gap-1 ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">🏠</span>
          <span className="text-[10px] font-bold">Home</span>
        </button>
        <button onClick={startNewSignWorkflow} className={`flex flex-col items-center gap-1 ${currentView === AppView.SIGN_DOC ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">✍️</span>
          <span className="text-[10px] font-bold">Sign</span>
        </button>
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.RENT_RECEIPT); }} className={`flex flex-col items-center gap-1 ${currentView === AppView.RENT_RECEIPT ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">📜</span>
          <span className="text-[10px] font-bold">Receipt</span>
        </button>
        <button className="flex flex-col items-center gap-1 text-gray-400">
          <span className="text-xl">👤</span>
          <span className="text-[10px] font-bold">Profile</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import RentReceiptCreator from './components/RentReceiptCreator';
import SignaturePad from './components/SignaturePad';

// Add type declaration for jsPDF since we're using CDN
declare const jspdf: any;

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([
    { id: '1', name: 'Rent Receipt Jan 2024', type: 'RECEIPT', status: 'SIGNED', date: '12 Jan 2024', placedSignatures: [{ id: 's1', dataUrl: 'data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8/5+hHgAHggJ/PchI7wAAAABJRU5ErkJggg==', x: 50, y: 80, w: 20 }] },
    { id: '2', name: 'Office Agreement.pdf', type: 'PDF', status: 'PENDING', date: '05 Jan 2024' },
  ]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);

  const docContainerRef = useRef<HTMLDivElement>(null);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
  };

  const startNewSignWorkflow = () => {
    resetSigningState();
    setCurrentView(AppView.SIGN_DOC);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
      };
      reader.readAsDataURL(file);
    }
  };

  const saveSignature = (dataUrl: string) => {
    const newSign: UserSignature = {
      id: Date.now().toString(),
      dataUrl,
      label: 'My Signature',
      createdAt: new Date().toISOString()
    };
    setSignatures([newSign, ...signatures]);
    setShowSignaturePad(false);
  };

  const handleReceiptComplete = (data: any) => {
    const newDoc: DocumentRecord = {
      id: Date.now().toString(),
      name: `Rent Receipt ${data.month} ${data.year}`,
      type: 'RECEIPT',
      status: 'PENDING',
      date: new Date().toLocaleDateString('en-IN')
    };
    setDocuments([newDoc, ...documents]);
    setActiveDoc(newDoc);
    setCurrentView(AppView.SIGN_DOC);
  };

  const handleSignFinish = () => {
    if (activeDoc) {
      setDocuments(docs => docs.map(d => d.id === activeDoc.id ? { 
        ...d, 
        status: 'SIGNED', 
        placedSignatures: [...placedSignatures] 
      } : d));
    } else {
      const newDoc: DocumentRecord = {
        id: Date.now().toString(),
        name: 'Signed Document',
        type: 'IMAGE',
        status: 'SIGNED',
        date: new Date().toLocaleDateString('en-IN'),
        placedSignatures: [...placedSignatures]
      };
      setDocuments([newDoc, ...documents]);
    }
    setShowSuccessScreen(true);
  };

  const handleDeleteDoc = (id: string) => {
    setDocuments(prev => prev.filter(d => d.id !== id));
    if (activeDoc?.id === id) {
      resetSigningState();
      setCurrentView(AppView.DASHBOARD);
    }
  };

  const handleDiscardDraft = () => {
    if (window.confirm("Are you sure you want to discard this draft? All placed signatures will be lost.")) {
      resetSigningState();
      setCurrentView(AppView.DASHBOARD);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 40, 
      y: 70,
      w: 25 
    };
    setPlacedSignatures([...placedSignatures, newPlaced]);
  };

  const removePlacedSignature = (id: string) => {
    if (activeDoc?.status === 'SIGNED') return;
    setPlacedSignatures(placedSignatures.filter(ps => ps.id !== id));
  };

  const handleDrag = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    if (activeDoc?.status === 'SIGNED') return;
    const container = docContainerRef.current;
    if (!container) return;

    const rect = container.getBoundingClientRect();

    const moveHandler = (moveEvent: MouseEvent | TouchEvent) => {
      const clientX = 'touches' in moveEvent ? moveEvent.touches[0].clientX : (moveEvent as MouseEvent).clientX;
      const clientY = 'touches' in moveEvent ? moveEvent.touches[0].clientY : (moveEvent as MouseEvent).clientY;

      let xPercent = ((clientX - rect.left) / rect.width) * 100;
      let yPercent = ((clientY - rect.top) / rect.height) * 100;

      xPercent = Math.max(0, Math.min(90, xPercent));
      yPercent = Math.max(0, Math.min(95, yPercent));

      setPlacedSignatures(prev => prev.map(ps => ps.id === id ? { ...ps, x: xPercent, y: yPercent } : ps));
    };

    const stopHandler = () => {
      window.removeEventListener('mousemove', moveHandler);
      window.removeEventListener('mouseup', stopHandler);
      window.removeEventListener('touchmove', moveHandler);
      window.removeEventListener('touchend', stopHandler);
    };

    window.addEventListener('mousemove', moveHandler);
    window.addEventListener('mouseup', stopHandler);
    window.addEventListener('touchmove', moveHandler, { passive: false });
    window.addEventListener('touchend', stopHandler);
  };

  const handleResize = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    e.stopPropagation();
    if (activeDoc?.status === 'SIGNED') return;

    const container = docContainerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();

    const initialX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const targetSig = placedSignatures.find(s => s.id === id);
    if (!targetSig) return;

    const initialW = targetSig.w || 25;

    const moveHandler = (moveEvent: MouseEvent | TouchEvent) => {
      const currentX = 'touches' in moveEvent ? moveEvent.touches[0].clientX : (moveEvent as MouseEvent).clientX;
      const deltaX = currentX - initialX;
      const deltaWPercent = (deltaX / rect.width) * 100;

      let newW = initialW + deltaWPercent;
      newW = Math.max(5, Math.min(80, newW)); 

      setPlacedSignatures(prev => prev.map(ps => ps.id === id ? { ...ps, w: newW } : ps));
    };

    const stopHandler = () => {
      window.removeEventListener('mousemove', moveHandler);
      window.removeEventListener('mouseup', stopHandler);
      window.removeEventListener('touchmove', moveHandler);
      window.removeEventListener('touchend', stopHandler);
    };

    window.addEventListener('mousemove', moveHandler);
    window.addEventListener('mouseup', stopHandler);
    window.addEventListener('touchmove', moveHandler, { passive: false });
    window.addEventListener('touchend', stopHandler);
  };

  const handleDownload = async () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = 1240;
    canvas.height = 1754;

    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const drawSignatures = async () => {
      for (const sig of placedSignatures) {
        const sigImg = new Image();
        sigImg.src = sig.dataUrl;
        await new Promise(resolve => { sigImg.onload = resolve; });

        const sigW = (canvas.width * (sig.w || 25)) / 100;
        const sigRatio = sigImg.height / sigImg.width;
        const sigH = sigW * sigRatio;
        const sigX = (canvas.width * sig.x) / 100;
        const sigY = (canvas.height * sig.y) / 100;

        ctx.drawImage(sigImg, sigX, sigY, sigW, sigH);
      }
    };

    if (uploadFile) {
      const bgImg = new Image();
      bgImg.src = uploadFile;
      await new Promise(resolve => { bgImg.onload = resolve; });

      const ratio = bgImg.height / bgImg.width;
      canvas.height = canvas.width * ratio;
      ctx.drawImage(bgImg, 0, 0, canvas.width, canvas.height);
      await drawSignatures();
    } else if (activeDoc?.type === 'RECEIPT') {
      ctx.fillStyle = '#000000';
      ctx.textAlign = 'center';
      ctx.font = 'bold 60px Inter, Arial';
      ctx.fillText('RENT RECEIPT', canvas.width / 2, 150);

      ctx.beginPath();
      ctx.moveTo(100, 180);
      ctx.lineTo(canvas.width - 100, 180);
      ctx.lineWidth = 2;
      ctx.stroke();

      ctx.textAlign = 'left';
      ctx.font = '40px Inter, Arial';
      const name = activeDoc.name.split('Receipt ')[1] || 'Valued Tenant';
      const lines = [
        `Received with thanks from: ${name}`,
        `Sum of: ₹ 15,000/- (Rupees Fifteen Thousand Only)`,
        `Towards Rent for: ${activeDoc.date || new Date().toLocaleDateString('en-IN')}`,
        `Property Address: H-Block, Sector 62, Noida, UP`,
        `Dated: ${activeDoc.date || new Date().toLocaleDateString('en-IN')}`,
      ];

      lines.forEach((line, i) => {
        ctx.fillText(line, 150, 350 + (i * 120));
      });

      ctx.font = 'italic 30px Inter, Arial';
      ctx.fillText('This is a computer generated document, HRA compliant.', 150, canvas.height - 150);

      await drawSignatures();
    }

    const dataUrl = canvas.toDataURL('image/jpeg', 0.95);
    const pdf = new jspdf.jsPDF({
      orientation: canvas.width > canvas.height ? 'l' : 'p',
      unit: 'px',
      format: [canvas.width, canvas.height]
    });

    pdf.addImage(dataUrl, 'JPEG', 0, 0, canvas.width, canvas.height);
    pdf.save(`${activeDoc?.name || 'signed-document'}.pdf`);
  };

  const isViewOnly = activeDoc?.status === 'SIGNED';

  return (
    <div className="min-h-screen pb-20 md:pb-0">
      <header className="bg-white border-b border-gray-100 sticky top-0 z-40 px-4 py-4 md:px-8">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-indigo-200">
              S
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900 tracking-tight">SignEase</h1>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Digital India</p>
            </div>
          </div>

          <div className="hidden md:flex gap-6">
            <button 
              onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}
              className={`text-sm font-semibold transition-colors ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-gray-500 hover:text-gray-900'}`}
            >
              Dashboard
            </button>
            {/* Documents and Settings removed as requested */}
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => setShowSignaturePad(true)}
              className="hidden md:block text-sm font-bold text-indigo-600 bg-indigo-50 px-4 py-2 rounded-lg hover:bg-indigo-100 transition-colors"
            >
              My Signatures
            </button>
            <div className="w-10 h-10 rounded-full bg-slate-200 overflow-hidden ring-2 ring-indigo-100">
              <img src="https://picsum.photos/40/40" alt="Avatar" />
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8">
        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-12 px-6 bg-white rounded-3xl shadow-xl border border-indigo-50 mt-10">
            <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6 animate-bounce">
              ✓
            </div>
            <h2 className="text-2xl font-bold text-gray-800 mb-2">Document Signed!</h2>
            <p className="text-gray-500 mb-8">Your document has been securely signed and moved to the completed list.</p>

            <div className="space-y-3">
              <button 
                onClick={handleDownload}
                className="w-full bg-indigo-600 text-white font-bold py-3 rounded-xl hover:bg-indigo-700 transition-all shadow-lg flex items-center justify-center gap-2"
              >
                <span>⬇️</span> Download PDF
              </button>
              <button 
                onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}
                className="w-full bg-gray-100 text-gray-700 font-bold py-3 rounded-xl hover:bg-gray-200 transition-all"
              >
                Go to Dashboard
              </button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard 
                documents={documents} 
                onAction={(view) => {
                  if (view === AppView.SIGN_DOC) startNewSignWorkflow();
                  else setCurrentView(view);
                }} 
                onViewDoc={(doc) => {
                  setActiveDoc(doc);
                  setPlacedSignatures(doc.placedSignatures || []);
                  setCurrentView(AppView.SIGN_DOC);
                }} 
                onDeleteDoc={handleDeleteDoc}
              />
            )}

            {currentView === AppView.RENT_RECEIPT && (
              <RentReceiptCreator 
                onComplete={handleReceiptComplete}
                onCancel={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}
              />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="max-w-4xl mx-auto">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-bold text-gray-800">
                    {isViewOnly ? `View: ${activeDoc?.name}` : activeDoc ? `Signing: ${activeDoc.name}` : 'Sign Document'}
                  </h2>
                  <div className="flex gap-3">
                    {isViewOnly ? (
                      <button 
                        onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}
                        className="text-gray-500 font-semibold hover:text-gray-700 transition-colors flex items-center gap-2"
                      >
                        ✕ Close
                      </button>
                    ) : (
                      <button 
                        onClick={handleDiscardDraft}
                        className="text-red-500 font-semibold hover:text-red-700 transition-colors flex items-center gap-2"
                      >
                        <span>🗑️</span> <span className="hidden sm:inline">Discard Draft</span>
                      </button>
                    )}
                  </div>
                </div>

                {!uploadFile && !activeDoc && (
                  <div className="border-2 border-dashed border-gray-200 rounded-3xl p-12 text-center bg-white">
                    <div className="text-6xl mb-6">📁</div>
                    <h3 className="text-xl font-bold text-gray-800 mb-2">Upload File to Sign</h3>
                    <p className="text-gray-500 mb-8 max-w-sm mx-auto">
                      Drag and drop your PDF or Image here. We support all Indian legal documents.
                    </p>
                    <label className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold cursor-pointer hover:bg-indigo-700 shadow-xl transition-all inline-block">
                      Browse Files
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="bg-white rounded-3xl shadow-sm border border-gray-100 p-4 min-h-[500px] flex flex-col">
                    <div 
                      ref={docContainerRef}
                      className="flex-1 flex items-center justify-center bg-gray-50 rounded-2xl relative overflow-hidden select-none"
                    >
                      {uploadFile ? (
                        <img src={uploadFile} alt="Preview" className="max-h-full object-contain shadow-lg" />
                      ) : activeDoc?.type === 'RECEIPT' ? (
                        <div className="p-10 bg-white shadow-lg w-full max-w-md min-h-[400px] relative">
                           <h1 className="text-xl font-bold text-center border-b pb-4 mb-4 uppercase tracking-tighter">Rent Receipt</h1>
                           <div className="space-y-4 text-sm text-gray-700">
                              <p>Received with thanks from <strong>{activeDoc?.name.split('Receipt ')[1]}</strong></p>
                              <p>the sum of <strong>₹ 15,000/-</strong> (Rupees Fifteen Thousand Only)</p>
                              <p>towards rent for the property at: <strong>H-Block, Sector 62, Noida, UP</strong></p>
                              <p className="mt-8 pt-8">Dated: {activeDoc?.date || new Date().toLocaleDateString('en-IN')}</p>
                           </div>
                        </div>
                      ) : (
                        <div className="p-20 text-center text-gray-400">
                          <p>Document preview unavailable for this type.</p>
                        </div>
                      )}

                      {placedSignatures.map(ps => (
                        <div 
                          key={ps.id}
                          style={{ 
                            left: `${ps.x}%`, 
                            top: `${ps.y}%`, 
                            width: `${ps.w || 25}%` 
                          }}
                          className={`absolute group ${isViewOnly ? 'pointer-events-none' : 'cursor-move touch-none'} z-10`}
                          onMouseDown={(e) => handleDrag(ps.id, e)}
                          onTouchStart={(e) => handleDrag(ps.id, e)}
                        >
                          <div className="relative">
                             <img 
                              src={ps.dataUrl} 
                              alt="Signature" 
                              className={`w-full h-auto mix-blend-multiply border border-dashed ${isViewOnly ? 'border-transparent' : 'border-indigo-400 group-hover:border-indigo-600'} bg-transparent p-1 pointer-events-none transition-all`} 
                            />
                            {!isViewOnly && (
                              <>
                                <button 
                                  onClick={(e) => { e.stopPropagation(); removePlacedSignature(ps.id); }}
                                  className="absolute -top-3 -right-3 bg-red-500 text-white w-6 h-6 rounded-full flex items-center justify-center text-[10px] shadow-md opacity-0 group-hover:opacity-100 transition-opacity z-20"
                                >
                                  ✕
                                </button>
                                <div 
                                  className="absolute -bottom-2 -right-2 w-5 h-5 bg-indigo-600 border-2 border-white rounded-full cursor-nwse-resize shadow-md opacity-0 group-hover:opacity-100 transition-opacity z-20"
                                  onMouseDown={(e) => handleResize(ps.id, e)}
                                  onTouchStart={(e) => handleResize(ps.id, e)}
                                />
                              </>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>

                    <div className="mt-6 flex flex-col md:flex-row gap-4 items-center justify-between border-t pt-6">
                      {isViewOnly ? (
                        <div className="w-full flex justify-between items-center">
                          <p className="text-sm text-gray-500">Document finalized on {activeDoc?.date}</p>
                          <div className="flex gap-3">
                            <button 
                              onClick={handleDownload}
                              className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg flex items-center gap-2"
                            >
                              <span>⬇️</span> Download PDF
                            </button>
                          </div>
                        </div>
                      ) : (
                        <>
                          <div className="w-full md:w-auto overflow-hidden">
                            <p className="text-xs font-bold text-gray-400 uppercase mb-2">Click signature to place</p>
                            <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                              {signatures.length === 0 && (
                                <p className="text-xs text-gray-400 italic">No saved signatures yet.</p>
                              )}
                              {signatures.map(s => (
                                <button 
                                  key={s.id} 
                                  onClick={() => placeSignature(s)}
                                  className="flex-shrink-0 w-24 h-12 bg-slate-50 border border-gray-100 rounded-lg hover:border-indigo-400 hover:bg-indigo-50 transition-all flex items-center justify-center p-1"
                                >
                                  <img src={s.dataUrl} alt="Sign" className="max-h-full mix-blend-multiply" />
                                </button>
                              ))}
                              <button 
                                onClick={() => setShowSignaturePad(true)}
                                className="flex-shrink-0 w-12 h-12 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center border border-dashed border-indigo-200 hover:bg-indigo-100"
                              >
                                +
                              </button>
                            </div>
                          </div>

                          <div className="flex gap-3 w-full md:w-auto">
                            <button 
                              className="flex-1 md:flex-none px-6 py-3 bg-white border border-gray-200 rounded-xl font-bold text-gray-700 hover:bg-gray-50 flex items-center justify-center gap-2"
                              onClick={() => {
                                const link = "https://signease.in/s/req-" + Math.floor(Math.random() * 10000);
                                alert(`Sharing request link to WhatsApp...`);
                                window.open(`https://wa.me/?text=Please sign this document on SignEase: ${link}`, '_blank');
                              }}
                            >
                              <span>🔗</span> Share Link
                            </button>
                            <button 
                              onClick={handleSignFinish}
                              className="flex-1 md:flex-none px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100 disabled:opacity-50 disabled:cursor-not-allowed"
                              disabled={placedSignatures.length === 0}
                            >
                              Finish & Save
                            </button>
                          </div>
                        </>
                      )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && (
        <SignaturePad 
          onSave={saveSignature}
          onCancel={() => setShowSignaturePad(false)}
        />
      )}

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 flex justify-around items-center py-3 md:hidden z-50">
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className={`flex flex-col items-center gap-1 ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">🏠</span>
          <span className="text-[10px] font-bold">Home</span>
        </button>
        <button onClick={startNewSignWorkflow} className={`flex flex-col items-center gap-1 ${currentView === AppView.SIGN_DOC ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">✍️</span>
          <span className="text-[10px] font-bold">Sign</span>
        </button>
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.RENT_RECEIPT); }} className={`flex flex-col items-center gap-1 ${currentView === AppView.RENT_RECEIPT ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">📜</span>
          <span className="text-[10px] font-bold">Receipt</span>
        </button>
        <button className="flex flex-col items-center gap-1 text-gray-400">
          <span className="text-xl">👤</span>
          <span className="text-[10px] font-bold">Profile</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

export enum AppView {
  DASHBOARD = 'DASHBOARD',
  SIGN_DOC = 'SIGN_DOC',
  VIEW_DOC = 'VIEW_DOC'
}

export interface PlacedSignature {
  id: string;
  dataUrl: string;
  x: number; // percentage 0-100
  y: number; // percentage 0-100
  w?: number; // width percentage 5-100
}

export interface UserSignature {
  id: string;
  dataUrl: string;
  label: string;
  createdAt: string;
}

export interface DocumentRecord {
  id: string;
  name: string;
  type: 'PDF' | 'IMAGE';
  status: 'SIGNED' | 'PENDING';
  date: string;
  fileData?: string; // base64 data
  placedSignatures?: PlacedSignature[];
}

import React, { useState, useRef, useEffect } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';

declare const jspdf: any;

const STORAGE_KEYS = {
  DOCUMENTS: 'signease_docs_v1',
  SIGNATURES: 'signease_sigs_v1'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);

  const docContainerRef = useRef<HTMLDivElement>(null);

  // Load from local storage
  useEffect(() => {
    const savedDocs = localStorage.getItem(STORAGE_KEYS.DOCUMENTS);
    const savedSigs = localStorage.getItem(STORAGE_KEYS.SIGNATURES);

    if (savedDocs) {
      try {
        setDocuments(JSON.parse(savedDocs));
      } catch (e) {
        console.error("Failed to parse docs", e);
      }
    }

    if (savedSigs) {
      try {
        setSignatures(JSON.parse(savedSigs));
      } catch (e) {
        console.error("Failed to parse signatures", e);
      }
    }
  }, []);

  // Save to local storage
  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.DOCUMENTS, JSON.stringify(documents));
  }, [documents]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.SIGNATURES, JSON.stringify(signatures));
  }, [signatures]);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const fileData = reader.result as string;
        setUploadFile(fileData);
        setCurrentView(AppView.SIGN_DOC);
      };
      reader.readAsDataURL(file);
    }
  };

  const saveSignature = (dataUrl: string) => {
    const newSign: UserSignature = {
      id: Date.now().toString(),
      dataUrl,
      label: 'My Signature',
      createdAt: new Date().toISOString()
    };
    setSignatures([newSign, ...signatures]);
    setShowSignaturePad(false);
  };

  const handleSignFinish = () => {
    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || (uploadFile?.startsWith('data:application/pdf') ? 'Document.pdf' : 'Image.png'),
      type: (activeDoc?.type || (uploadFile?.startsWith('data:application/pdf') ? 'PDF' : 'IMAGE')) as 'PDF' | 'IMAGE',
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: uploadFile || activeDoc?.fileData,
      placedSignatures: [...placedSignatures]
    };

    if (activeDoc) {
      setDocuments(prev => prev.map(d => d.id === activeDoc.id ? newDoc : d));
    } else {
      setDocuments([newDoc, ...documents]);
    }
    setShowSuccessScreen(true);
  };

  const handleDeleteDoc = (id: string) => {
    setDocuments(prev => prev.filter(d => d.id !== id));
    if (activeDoc?.id === id) {
      resetSigningState();
      setCurrentView(AppView.DASHBOARD);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 40, 
      y: 70,
      w: 25 
    };
    setPlacedSignatures([...placedSignatures, newPlaced]);
  };

  const removePlacedSignature = (id: string) => {
    setPlacedSignatures(placedSignatures.filter(ps => ps.id !== id));
  };

  const handleDrag = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    if (activeDoc?.status === 'SIGNED') return;
    const container = docContainerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();

    const moveHandler = (moveEvent: MouseEvent | TouchEvent) => {
      const clientX = 'touches' in moveEvent ? moveEvent.touches[0].clientX : (moveEvent as MouseEvent).clientX;
      const clientY = 'touches' in moveEvent ? moveEvent.touches[0].clientY : (moveEvent as MouseEvent).clientY;

      let xPercent = ((clientX - rect.left) / rect.width) * 100;
      let yPercent = ((clientY - rect.top) / rect.height) * 100;

      xPercent = Math.max(0, Math.min(90, xPercent));
      yPercent = Math.max(0, Math.min(95, yPercent));

      setPlacedSignatures(prev => prev.map(ps => ps.id === id ? { ...ps, x: xPercent, y: yPercent } : ps));
    };

    const stopHandler = () => {
      window.removeEventListener('mousemove', moveHandler);
      window.removeEventListener('mouseup', stopHandler);
      window.removeEventListener('touchmove', moveHandler);
      window.removeEventListener('touchend', stopHandler);
    };

    window.addEventListener('mousemove', moveHandler);
    window.addEventListener('mouseup', stopHandler);
    window.addEventListener('touchmove', moveHandler, { passive: false });
    window.addEventListener('touchend', stopHandler);
  };

  const handleResize = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    e.stopPropagation();
    if (activeDoc?.status === 'SIGNED') return;
    const container = docContainerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();

    const initialX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const targetSig = placedSignatures.find(s => s.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;

    const moveHandler = (moveEvent: MouseEvent | TouchEvent) => {
      const currentX = 'touches' in moveEvent ? moveEvent.touches[0].clientX : (moveEvent as MouseEvent).clientX;
      const deltaX = currentX - initialX;
      const deltaWPercent = (deltaX / rect.width) * 100;
      let newW = initialW + deltaWPercent;
      newW = Math.max(5, Math.min(80, newW)); 
      setPlacedSignatures(prev => prev.map(ps => ps.id === id ? { ...ps, w: newW } : ps));
    };

    const stopHandler = () => {
      window.removeEventListener('mousemove', moveHandler);
      window.removeEventListener('mouseup', stopHandler);
      window.removeEventListener('touchmove', moveHandler);
      window.removeEventListener('touchend', stopHandler);
    };

    window.addEventListener('mousemove', moveHandler);
    window.addEventListener('mouseup', stopHandler);
    window.addEventListener('touchmove', moveHandler, { passive: false });
    window.addEventListener('touchend', stopHandler);
  };

  const handleDownload = async () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = 1240;
    canvas.height = 1754;
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const drawSignatures = async () => {
      for (const sig of placedSignatures) {
        const sigImg = new Image();
        sigImg.src = sig.dataUrl;
        await new Promise(resolve => { sigImg.onload = resolve; });
        const sigW = (canvas.width * (sig.w || 25)) / 100;
        const sigRatio = sigImg.height / sigImg.width;
        const sigH = sigW * sigRatio;
        const sigX = (canvas.width * sig.x) / 100;
        const sigY = (canvas.height * sig.y) / 100;
        ctx.drawImage(sigImg, sigX, sigY, sigW, sigH);
      }
    };

    const fileToUse = uploadFile || activeDoc?.fileData;
    if (fileToUse) {
      if (fileToUse.startsWith('data:image')) {
        const bgImg = new Image();
        bgImg.src = fileToUse;
        await new Promise(resolve => { bgImg.onload = resolve; });
        const ratio = bgImg.height / bgImg.width;
        canvas.height = canvas.width * ratio;
        ctx.drawImage(bgImg, 0, 0, canvas.width, canvas.height);
      } else {
        // Simple fallback for PDF: treat canvas as the background
        ctx.fillStyle = '#f8fafc';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.fillStyle = '#000000';
        ctx.font = '40px Arial';
        ctx.fillText("PDF Content Overlay (Signed Version)", 100, 100);
      }
      await drawSignatures();
    }

    const dataUrl = canvas.toDataURL('image/jpeg', 0.95);
    const pdf = new jspdf.jsPDF({
      orientation: canvas.width > canvas.height ? 'l' : 'p',
      unit: 'px',
      format: [canvas.width, canvas.height]
    });
    pdf.addImage(dataUrl, 'JPEG', 0, 0, canvas.width, canvas.height);
    pdf.save(`${activeDoc?.name || 'signed-doc'}.pdf`);
  };

  const isViewOnly = activeDoc?.status === 'SIGNED';

  return (
    <div className="min-h-screen pb-20 md:pb-0">
      <header className="bg-white border-b border-gray-100 sticky top-0 z-40 px-4 py-4 md:px-8">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-indigo-200">
              S
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900 tracking-tight">SignEase</h1>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Digital India</p>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => setShowSignaturePad(true)}
              className="hidden md:block text-sm font-bold text-indigo-600 bg-indigo-50 px-4 py-2 rounded-lg hover:bg-indigo-100 transition-colors"
            >
              My Signatures
            </button>
            <div className="w-10 h-10 rounded-full bg-slate-200 overflow-hidden ring-2 ring-indigo-100">
              <img src="https://picsum.photos/40/40" alt="Avatar" />
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8">
        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-12 px-6 bg-white rounded-3xl shadow-xl border border-indigo-50 mt-10">
            <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6 animate-bounce">✓</div>
            <h2 className="text-2xl font-bold text-gray-800 mb-2">Document Signed!</h2>
            <p className="text-gray-500 mb-8">Your document has been securely stored locally.</p>
            <div className="space-y-3">
              <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-bold py-3 rounded-xl hover:bg-indigo-700 transition-all shadow-lg flex items-center justify-center gap-2">
                <span>⬇️</span> Download PDF
              </button>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-gray-100 text-gray-700 font-bold py-3 rounded-xl hover:bg-gray-200 transition-all">
                Go to Dashboard
              </button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard 
                documents={documents} 
                onAction={(view) => {
                  if (view === AppView.SIGN_DOC) resetSigningState();
                  setCurrentView(view);
                }} 
                onViewDoc={(doc) => {
                  setActiveDoc(doc);
                  setUploadFile(doc.fileData || null);
                  setPlacedSignatures(doc.placedSignatures || []);
                  setCurrentView(AppView.SIGN_DOC);
                }} 
                onDeleteDoc={handleDeleteDoc}
              />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="max-w-4xl mx-auto">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-bold text-gray-800">
                    {isViewOnly ? `View: ${activeDoc?.name}` : 'Sign Document'}
                  </h2>
                  <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="text-gray-500 font-semibold hover:text-gray-700 transition-colors">✕ Close</button>
                </div>

                {!uploadFile && (
                  <div className="border-2 border-dashed border-gray-200 rounded-3xl p-12 text-center bg-white">
                    <div className="text-6xl mb-6">📁</div>
                    <h3 className="text-xl font-bold text-gray-800 mb-2">Upload File to Sign</h3>
                    <p className="text-gray-500 mb-8 max-w-sm mx-auto">Upload any PDF or Image to add your digital signature.</p>
                    <label className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold cursor-pointer hover:bg-indigo-700 shadow-xl transition-all inline-block">
                      Browse Files
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {uploadFile && (
                  <div className="bg-white rounded-3xl shadow-sm border border-gray-100 p-4 flex flex-col min-h-[600px]">
                    <div ref={docContainerRef} className="flex-1 flex items-center justify-center bg-gray-50 rounded-2xl relative overflow-auto select-none min-h-[400px]">
                      {uploadFile.startsWith('data:application/pdf') ? (
                        <iframe src={uploadFile} className="w-full h-full min-h-[500px] border-none" title="PDF Preview" />
                      ) : (
                        <img src={uploadFile} alt="Preview" className="max-h-full object-contain shadow-lg" />
                      )}

                      {!uploadFile.startsWith('data:application/pdf') && placedSignatures.map(ps => (
                        <div key={ps.id} style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} className={`absolute group ${isViewOnly ? 'pointer-events-none' : 'cursor-move touch-none'} z-10`} onMouseDown={(e) => handleDrag(ps.id, e)} onTouchStart={(e) => handleDrag(ps.id, e)}>
                          <div className="relative">
                            <img src={ps.dataUrl} alt="Signature" className={`w-full h-auto mix-blend-multiply border border-dashed ${isViewOnly ? 'border-transparent' : 'border-indigo-400 group-hover:border-indigo-600'} bg-transparent p-1 pointer-events-none transition-all`} />
                            {!isViewOnly && (
                              <>
                                <button onClick={(e) => { e.stopPropagation(); removePlacedSignature(ps.id); }} className="absolute -top-3 -right-3 bg-red-500 text-white w-6 h-6 rounded-full flex items-center justify-center text-[10px] opacity-0 group-hover:opacity-100 transition-opacity">✕</button>
                                <div className="absolute -bottom-2 -right-2 w-5 h-5 bg-indigo-600 border-2 border-white rounded-full cursor-nwse-resize shadow-md opacity-0 group-hover:opacity-100 transition-opacity" onMouseDown={(e) => handleResize(ps.id, e)} onTouchStart={(e) => handleResize(ps.id, e)} />
                              </>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>

                    <div className="mt-6 flex flex-col md:flex-row gap-4 items-center justify-between border-t pt-6">
                      {isViewOnly ? (
                        <button onClick={handleDownload} className="w-full md:w-auto px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg flex items-center justify-center gap-2">
                          <span>⬇️</span> Download PDF
                        </button>
                      ) : (
                        <>
                          <div className="w-full md:w-auto overflow-hidden">
                            <p className="text-xs font-bold text-gray-400 uppercase mb-2">Click to place</p>
                            <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-24 h-12 bg-slate-50 border border-gray-100 rounded-lg hover:border-indigo-400 transition-all flex items-center justify-center p-1">
                                  <img src={s.dataUrl} alt="Sign" className="max-h-full mix-blend-multiply" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-12 h-12 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center border border-dashed border-indigo-200 hover:bg-indigo-100">+</button>
                            </div>
                          </div>
                          <div className="flex gap-3 w-full md:w-auto">
                            <button onClick={handleSignFinish} className="flex-1 px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg disabled:opacity-50" disabled={placedSignatures.length === 0 && !uploadFile.startsWith('data:application/pdf')}>
                              Finish & Save
                            </button>
                          </div>
                        </>
                      )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 flex justify-around items-center py-3 md:hidden z-50">
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className={`flex flex-col items-center gap-1 ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">🏠</span>
          <span className="text-[10px] font-bold">Home</span>
        </button>
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.SIGN_DOC); }} className={`flex flex-col items-center gap-1 ${currentView === AppView.SIGN_DOC ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">✍️</span>
          <span className="text-[10px] font-bold">Sign</span>
        </button>
        <button className="flex flex-col items-center gap-1 text-gray-400">
          <span className="text-xl">👤</span>
          <span className="text-[10px] font-bold">Profile</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { DocumentRecord, AppView } from '../types';

interface DashboardProps {
  documents: DocumentRecord[];
  onAction: (view: AppView) => void;
  onViewDoc: (doc: DocumentRecord) => void;
  onDeleteDoc: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ documents, onAction, onViewDoc, onDeleteDoc }) => {
  const [filter, setFilter] = useState<'ALL' | 'PENDING' | 'SIGNED'>('ALL');

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (window.confirm("Delete this document forever?")) {
      onDeleteDoc(id);
    }
  };

  const filteredDocs = useMemo(() => {
    if (filter === 'ALL') return documents;
    return documents.filter(d => d.status === filter);
  }, [documents, filter]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-gradient-to-br from-indigo-500 to-indigo-700 p-8 rounded-3xl text-white shadow-xl">
          <h2 className="text-4xl font-bold mb-2">{documents.length}</h2>
          <p className="text-indigo-100 font-medium">Total Documents Stored</p>
          <button 
            onClick={() => onAction(AppView.SIGN_DOC)}
            className="mt-6 bg-white text-indigo-600 px-6 py-2 rounded-xl font-bold hover:bg-indigo-50 transition-all shadow-lg"
          >
            + Sign New File
          </button>
        </div>

        <div className="bg-white border border-gray-100 p-8 rounded-3xl shadow-sm flex flex-col justify-center">
          <div className="flex gap-4">
             <div className="flex-1">
                <p className="text-gray-400 text-sm font-bold uppercase tracking-wider">Signed</p>
                <h3 className="text-2xl font-bold text-gray-800">{documents.filter(d => d.status === 'SIGNED').length}</h3>
             </div>
             <div className="flex-1">
                <p className="text-gray-400 text-sm font-bold uppercase tracking-wider">Pending</p>
                <h3 className="text-2xl font-bold text-gray-800">{documents.filter(d => d.status === 'PENDING').length}</h3>
             </div>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="px-6 py-5 border-b border-gray-100 flex justify-between items-center bg-slate-50/30">
          <h4 className="text-lg font-bold text-gray-800">Your Local Storage</h4>
          <div className="flex gap-2">
            {(['ALL', 'PENDING', 'SIGNED'] as const).map(f => (
              <button 
                key={f}
                onClick={() => setFilter(f)}
                className={`text-[10px] px-3 py-1 rounded-lg font-bold transition-all ${filter === f ? 'bg-indigo-600 text-white' : 'bg-gray-100 text-gray-500 hover:bg-gray-200'}`}
              >
                {f}
              </button>
            ))}
          </div>
        </div>
        <div className="divide-y divide-gray-100">
          {filteredDocs.length > 0 ? filteredDocs.map(doc => (
            <div 
              key={doc.id} 
              onClick={() => onViewDoc(doc)}
              className="px-6 py-4 flex items-center justify-between transition-colors hover:bg-indigo-50/30 cursor-pointer group"
            >
              <div className="flex items-center gap-4">
                <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-lg shadow-sm ${
                  doc.type === 'PDF' ? 'bg-red-50 text-red-500' : 'bg-gray-50 text-gray-500'
                }`}>
                  {doc.type === 'PDF' ? '📄' : '🖼️'}
                </div>
                <div>
                  <h5 className="text-sm font-bold text-gray-800 group-hover:text-indigo-600 transition-colors">{doc.name}</h5>
                  <p className="text-xs text-gray-400">{doc.date} • {doc.type}</p>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${
                  doc.status === 'SIGNED' ? 'bg-emerald-100 text-emerald-700' : 'bg-orange-100 text-orange-700'
                }`}>
                  {doc.status}
                </span>
                <button 
                  onClick={(e) => handleDelete(e, doc.id)}
                  className="p-2 hover:bg-red-50 text-red-500 rounded-lg transition-colors"
                  title="Delete Forever"
                >
                  🗑️
                </button>
              </div>
            </div>
          )) : (
            <div className="p-16 text-center">
              <div className="text-6xl mb-4 opacity-30">📂</div>
              <h5 className="text-gray-800 font-bold text-lg">No documents here</h5>
              <p className="text-gray-400 mt-1">Files you sign will be stored on this device.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useRef, useEffect } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';

declare const jspdf: any;

const STORAGE_KEYS = {
  DOCUMENTS: 'signease_docs_v1',
  SIGNATURES: 'signease_sigs_v1'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [pdfBlobUrl, setPdfBlobUrl] = useState<string | null>(null);

  const docContainerRef = useRef<HTMLDivElement>(null);

  // Load from local storage on mount
  useEffect(() => {
    const savedDocs = localStorage.getItem(STORAGE_KEYS.DOCUMENTS);
    const savedSigs = localStorage.getItem(STORAGE_KEYS.SIGNATURES);

    if (savedDocs) {
      try {
        setDocuments(JSON.parse(savedDocs));
      } catch (e) {
        console.error("Failed to load documents", e);
      }
    }

    if (savedSigs) {
      try {
        setSignatures(JSON.parse(savedSigs));
      } catch (e) {
        console.error("Failed to load signatures", e);
      }
    }
  }, []);

  // Save to local storage when state changes
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEYS.DOCUMENTS, JSON.stringify(documents));
    } catch (e) {
      console.error("Storage full: Could not save documents", e);
      if (documents.length > 0) {
        alert("Warning: Local storage is full. Some documents may not be saved. Try deleting old files.");
      }
    }
  }, [documents]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.SIGNATURES, JSON.stringify(signatures));
  }, [signatures]);

  // Handle PDF Preview URL generation to avoid "Blocked" errors
  useEffect(() => {
    const dataUrl = uploadFile || activeDoc?.fileData;
    if (dataUrl && dataUrl.startsWith('data:application/pdf')) {
      // Convert base64 to Blob to avoid Chrome blocking large Data URIs in iframes
      const base64Data = dataUrl.split(',')[1];
      const byteCharacters = atob(base64Data);
      const byteNumbers = new Array(byteCharacters.length);
      for (let i = 0; i < byteCharacters.length; i++) {
        byteNumbers[i] = byteCharacters.charCodeAt(i);
      }
      const byteArray = new Uint8Array(byteNumbers);
      const blob = new Blob([byteArray], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);

      setPdfBlobUrl(url);

      // Cleanup
      return () => {
        URL.revokeObjectURL(url);
      };
    } else {
      setPdfBlobUrl(null);
    }
  }, [uploadFile, activeDoc]);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setPdfBlobUrl(null);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const fileData = reader.result as string;
        setUploadFile(fileData);
        setCurrentView(AppView.SIGN_DOC);
      };
      reader.readAsDataURL(file);
    }
  };

  const saveSignature = (dataUrl: string) => {
    const newSign: UserSignature = {
      id: Date.now().toString(),
      dataUrl,
      label: 'My Signature',
      createdAt: new Date().toISOString()
    };
    setSignatures([newSign, ...signatures]);
    setShowSignaturePad(false);
  };

  const handleSignFinish = () => {
    const isPdf = (uploadFile || activeDoc?.fileData)?.startsWith('data:application/pdf');
    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || (isPdf ? 'Document.pdf' : 'Image.png'),
      type: (isPdf ? 'PDF' : 'IMAGE') as 'PDF' | 'IMAGE',
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: uploadFile || activeDoc?.fileData,
      placedSignatures: [...placedSignatures]
    };

    if (activeDoc) {
      setDocuments(prev => prev.map(d => d.id === activeDoc.id ? newDoc : d));
    } else {
      setDocuments(prev => [newDoc, ...prev]);
    }
    setShowSuccessScreen(true);
  };

  const handleDeleteDoc = (id: string) => {
    setDocuments(prev => prev.filter(d => d.id !== id));
    // If the doc we are currently viewing/signing is deleted, go home
    if (activeDoc?.id === id) {
      resetSigningState();
      setCurrentView(AppView.DASHBOARD);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (isViewOnly) return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 40, 
      y: 70,
      w: 25 
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const removePlacedSignature = (id: string) => {
    setPlacedSignatures(prev => prev.filter(ps => ps.id !== id));
  };

  const handleDrag = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    if (isViewOnly) return;
    const container = docContainerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();

    const moveHandler = (moveEvent: MouseEvent | TouchEvent) => {
      const clientX = 'touches' in moveEvent ? (moveEvent as TouchEvent).touches[0].clientX : (moveEvent as MouseEvent).clientX;
      const clientY = 'touches' in moveEvent ? (moveEvent as TouchEvent).touches[0].clientY : (moveEvent as MouseEvent).clientY;

      let xPercent = ((clientX - rect.left) / rect.width) * 100;
      let yPercent = ((clientY - rect.top) / rect.height) * 100;

      xPercent = Math.max(0, Math.min(90, xPercent));
      yPercent = Math.max(0, Math.min(95, yPercent));

      setPlacedSignatures(prev => prev.map(ps => ps.id === id ? { ...ps, x: xPercent, y: yPercent } : ps));
    };

    const stopHandler = () => {
      window.removeEventListener('mousemove', moveHandler);
      window.removeEventListener('mouseup', stopHandler);
      window.removeEventListener('touchmove', moveHandler);
      window.removeEventListener('touchend', stopHandler);
    };

    window.addEventListener('mousemove', moveHandler);
    window.addEventListener('mouseup', stopHandler);
    window.addEventListener('touchmove', moveHandler, { passive: false });
    window.addEventListener('touchend', stopHandler);
  };

  const handleResize = (id: string, e: React.MouseEvent | React.TouchEvent) => {
    e.stopPropagation();
    if (isViewOnly) return;
    const container = docContainerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();

    const initialX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const targetSig = placedSignatures.find(s => s.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;

    const moveHandler = (moveEvent: MouseEvent | TouchEvent) => {
      const currentX = 'touches' in moveEvent ? (moveEvent as TouchEvent).touches[0].clientX : (moveEvent as MouseEvent).clientX;
      const deltaX = currentX - initialX;
      const deltaWPercent = (deltaX / rect.width) * 100;
      let newW = initialW + deltaWPercent;
      newW = Math.max(5, Math.min(80, newW)); 
      setPlacedSignatures(prev => prev.map(ps => ps.id === id ? { ...ps, w: newW } : ps));
    };

    const stopHandler = () => {
      window.removeEventListener('mousemove', moveHandler);
      window.removeEventListener('mouseup', stopHandler);
      window.removeEventListener('touchmove', moveHandler);
      window.removeEventListener('touchend', stopHandler);
    };

    window.addEventListener('mousemove', moveHandler);
    window.addEventListener('mouseup', stopHandler);
    window.addEventListener('touchmove', moveHandler, { passive: false });
    window.addEventListener('touchend', stopHandler);
  };

  const handleDownload = async () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    canvas.width = 1240;
    canvas.height = 1754;
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    const drawSignatures = async () => {
      for (const sig of placedSignatures) {
        const sigImg = new Image();
        sigImg.src = sig.dataUrl;
        await new Promise(resolve => { sigImg.onload = resolve; });
        const sigW = (canvas.width * (sig.w || 25)) / 100;
        const sigRatio = sigImg.height / sigImg.width;
        const sigH = sigW * sigRatio;
        const sigX = (canvas.width * sig.x) / 100;
        const sigY = (canvas.height * sig.y) / 100;
        ctx.drawImage(sigImg, sigX, sigY, sigW, sigH);
      }
    };

    const fileToUse = uploadFile || activeDoc?.fileData;
    if (fileToUse) {
      if (fileToUse.startsWith('data:image')) {
        const bgImg = new Image();
        bgImg.src = fileToUse;
        await new Promise(resolve => { bgImg.onload = resolve; });
        const ratio = bgImg.height / bgImg.width;
        canvas.height = canvas.width * ratio;
        ctx.drawImage(bgImg, 0, 0, canvas.width, canvas.height);
      } else {
        // Overlay for PDF
        ctx.fillStyle = '#f8fafc';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
        ctx.fillStyle = '#1e293b';
        ctx.font = 'bold 32px Arial';
        ctx.fillText("Signed PDF Content Overlay", 100, 100);
      }
      await drawSignatures();
    }

    const dataUrl = canvas.toDataURL('image/jpeg', 0.9);
    const pdf = new jspdf.jsPDF({
      orientation: canvas.width > canvas.height ? 'l' : 'p',
      unit: 'px',
      format: [canvas.width, canvas.height]
    });
    pdf.addImage(dataUrl, 'JPEG', 0, 0, canvas.width, canvas.height);
    pdf.save(`${activeDoc?.name || 'signed-doc'}.pdf`);
  };

  const isViewOnly = activeDoc?.status === 'SIGNED';

  return (
    <div className="min-h-screen pb-20 md:pb-0">
      <header className="bg-white border-b border-gray-100 sticky top-0 z-40 px-4 py-4 md:px-8">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-lg shadow-indigo-200">
              S
            </div>
            <div>
              <h1 className="text-xl font-bold text-gray-900 tracking-tight">SignEase</h1>
              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Digital India</p>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => setShowSignaturePad(true)}
              className="hidden md:block text-sm font-bold text-indigo-600 bg-indigo-50 px-4 py-2 rounded-lg hover:bg-indigo-100 transition-colors"
            >
              My Signatures
            </button>
            <div className="w-10 h-10 rounded-full bg-slate-200 overflow-hidden ring-2 ring-indigo-100">
              <img src="https://picsum.photos/40/40" alt="Avatar" />
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 md:p-8">
        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-12 px-6 bg-white rounded-3xl shadow-xl border border-indigo-50 mt-10">
            <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6 animate-bounce">✓</div>
            <h2 className="text-2xl font-bold text-gray-800 mb-2">Document Signed!</h2>
            <p className="text-gray-500 mb-8">Your document has been securely stored locally.</p>
            <div className="space-y-3">
              <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-bold py-3 rounded-xl hover:bg-indigo-700 transition-all shadow-lg flex items-center justify-center gap-2">
                <span>⬇️</span> Download PDF
              </button>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-gray-100 text-gray-700 font-bold py-3 rounded-xl hover:bg-gray-200 transition-all">
                Go to Dashboard
              </button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard 
                documents={documents} 
                onAction={(view) => {
                  if (view === AppView.SIGN_DOC) resetSigningState();
                  setCurrentView(view);
                }} 
                onViewDoc={(doc) => {
                  setActiveDoc(doc);
                  setUploadFile(null); // Clear manual upload to favor existing doc data
                  setPlacedSignatures(doc.placedSignatures || []);
                  setCurrentView(AppView.SIGN_DOC);
                }} 
                onDeleteDoc={handleDeleteDoc}
              />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="max-w-4xl mx-auto">
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-bold text-gray-800">
                    {isViewOnly ? `Viewing: ${activeDoc?.name}` : 'Sign Document'}
                  </h2>
                  <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="text-gray-500 font-semibold hover:text-gray-700 transition-colors">✕ Close</button>
                </div>

                {!uploadFile && !activeDoc && (
                  <div className="border-2 border-dashed border-gray-200 rounded-3xl p-12 text-center bg-white">
                    <div className="text-6xl mb-6">📁</div>
                    <h3 className="text-xl font-bold text-gray-800 mb-2">Upload File to Sign</h3>
                    <p className="text-gray-500 mb-8 max-w-sm mx-auto">Upload any PDF or Image to add your digital signature.</p>
                    <label className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold cursor-pointer hover:bg-indigo-700 shadow-xl transition-all inline-block">
                      Browse Files
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="bg-white rounded-3xl shadow-sm border border-gray-100 p-4 flex flex-col min-h-[600px]">
                    <div ref={docContainerRef} className="flex-1 flex items-center justify-center bg-gray-50 rounded-2xl relative overflow-auto select-none min-h-[500px]">
                      {pdfBlobUrl ? (
                        <iframe src={pdfBlobUrl} className="w-full h-full min-h-[600px] border-none rounded-xl bg-white" title="PDF Preview" />
                      ) : (
                        <img src={uploadFile || activeDoc?.fileData} alt="Preview" className="max-h-full object-contain shadow-lg" />
                      )}

                      {!pdfBlobUrl && placedSignatures.map(ps => (
                        <div key={ps.id} style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} className={`absolute group ${isViewOnly ? 'pointer-events-none' : 'cursor-move touch-none'} z-10`} onMouseDown={(e) => handleDrag(ps.id, e)} onTouchStart={(e) => handleDrag(ps.id, e)}>
                          <div className="relative">
                            <img src={ps.dataUrl} alt="Signature" className={`w-full h-auto mix-blend-multiply border border-dashed ${isViewOnly ? 'border-transparent' : 'border-indigo-400 group-hover:border-indigo-600'} bg-transparent p-1 pointer-events-none transition-all`} />
                            {!isViewOnly && (
                              <>
                                <button onClick={(e) => { e.stopPropagation(); removePlacedSignature(ps.id); }} className="absolute -top-3 -right-3 bg-red-500 text-white w-6 h-6 rounded-full flex items-center justify-center text-[10px] opacity-0 group-hover:opacity-100 transition-opacity">✕</button>
                                <div className="absolute -bottom-2 -right-2 w-5 h-5 bg-indigo-600 border-2 border-white rounded-full cursor-nwse-resize shadow-md opacity-0 group-hover:opacity-100 transition-opacity" onMouseDown={(e) => handleResize(ps.id, e)} onTouchStart={(e) => handleResize(ps.id, e)} />
                              </>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>

                    <div className="mt-6 flex flex-col md:flex-row gap-4 items-center justify-between border-t pt-6">
                      {isViewOnly ? (
                        <button onClick={handleDownload} className="w-full md:w-auto px-6 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg flex items-center justify-center gap-2">
                          <span>⬇️</span> Download PDF
                        </button>
                      ) : (
                        <>
                          <div className="w-full md:w-auto overflow-hidden">
                            <p className="text-xs font-bold text-gray-400 uppercase mb-2">Click your signature to place it</p>
                            <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-24 h-12 bg-slate-50 border border-gray-100 rounded-lg hover:border-indigo-400 transition-all flex items-center justify-center p-1">
                                  <img src={s.dataUrl} alt="Sign" className="max-h-full mix-blend-multiply" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-12 h-12 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center border border-dashed border-indigo-200 hover:bg-indigo-100">+</button>
                            </div>
                          </div>
                          <div className="flex gap-3 w-full md:w-auto">
                            <button onClick={handleSignFinish} className="flex-1 px-8 py-3 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 shadow-lg disabled:opacity-50" disabled={placedSignatures.length === 0 && !pdfBlobUrl}>
                              Save Signed Version
                            </button>
                          </div>
                        </>
                      )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-100 flex justify-around items-center py-3 md:hidden z-50">
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className={`flex flex-col items-center gap-1 ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">🏠</span>
          <span className="text-[10px] font-bold">Home</span>
        </button>
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.SIGN_DOC); }} className={`flex flex-col items-center gap-1 ${currentView === AppView.SIGN_DOC ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">✍️</span>
          <span className="text-[10px] font-bold">Sign</span>
        </button>
        <button className="flex flex-col items-center gap-1 text-gray-400">
          <span className="text-xl">👤</span>
          <span className="text-[10px] font-bold">Profile</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';

declare const jspdf: any;
declare const pdfjsLib: any;

// Set worker for pdf.js
if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const STORAGE_KEYS = {
  DOCUMENTS: 'signease_docs_v2',
  SIGNATURES: 'signease_sigs_v2'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const docContainerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);

  // Persistence
  useEffect(() => {
    const savedDocs = localStorage.getItem(STORAGE_KEYS.DOCUMENTS);
    const savedSigs = localStorage.getItem(STORAGE_KEYS.SIGNATURES);
    if (savedDocs) setDocuments(JSON.parse(savedDocs));
    if (savedSigs) setSignatures(JSON.parse(savedSigs));
  }, []);

  const saveToStorage = useCallback((docs: DocumentRecord[]) => {
    try {
      localStorage.setItem(STORAGE_KEYS.DOCUMENTS, JSON.stringify(docs));
    } catch (e) {
      console.error("Storage error", e);
      alert("Storage full! Please delete some old documents.");
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  // PDF Rendering Logic
  useEffect(() => {
    const renderPDF = async (dataUrl: string) => {
      if (!pdfCanvasRef.current) return;
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        const page = await pdf.getPage(1); // Render first page for signing
        const viewport = page.getViewport({ scale: 1.5 });
        const canvas = pdfCanvasRef.current;
        const context = canvas.getContext('2d');
        canvas.height = viewport.height;
        canvas.width = viewport.width;
        await page.render({ canvasContext: context, viewport }).promise;
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data?.startsWith('data:application/pdf')) {
      renderPDF(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    const updated = [newSign, ...signatures];
    setSignatures(updated);
    localStorage.setItem(STORAGE_KEYS.SIGNATURES, JSON.stringify(updated));
    setShowSignaturePad(false);
  };

  const handleSignFinish = () => {
    const isPdf = (uploadFile || activeDoc?.fileData)?.startsWith('data:application/pdf');
    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || (isPdf ? 'Signed_Doc.pdf' : 'Signed_Image.png'),
      type: (isPdf ? 'PDF' : 'IMAGE'),
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: uploadFile || activeDoc?.fileData,
      placedSignatures: [...placedSignatures]
    };

    let updatedDocs;
    if (activeDoc) {
      updatedDocs = documents.map(d => d.id === activeDoc.id ? newDoc : d);
    } else {
      updatedDocs = [newDoc, ...documents];
    }
    setDocuments(updatedDocs);
    saveToStorage(updatedDocs);
    setShowSuccessScreen(true);
  };

  const handleDeleteDoc = (id: string) => {
    const updatedDocs = documents.filter(d => d.id !== id);
    setDocuments(updatedDocs);
    saveToStorage(updatedDocs);
    if (activeDoc?.id === id) resetSigningState();
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 30, y: 30, w: 20 
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    const rect = docContainerRef.current?.getBoundingClientRect();
    if (!rect) return;
    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;
      const x = Math.max(0, Math.min(90, ((cx - rect.left) / rect.width) * 100));
      const y = Math.max(0, Math.min(95, ((cy - rect.top) / rect.height) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y } : p));
    };
    const end = () => { window.removeEventListener('mousemove', move); window.removeEventListener('touchmove', move); };
    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleDownload = async () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = 1240; canvas.height = 1754;
    ctx.fillStyle = '#fff'; ctx.fillRect(0,0,1240,1754);

    const fileToUse = uploadFile || activeDoc?.fileData;
    if (fileToUse?.startsWith('data:image')) {
      const img = new Image(); img.src = fileToUse;
      await new Promise(r => img.onload = r);
      canvas.height = canvas.width * (img.height/img.width);
      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    } else {
      ctx.fillStyle = '#000'; ctx.font = '30px Inter';
      ctx.fillText("Signed PDF Content", 100, 100);
    }

    for (const s of placedSignatures) {
      const si = new Image(); si.src = s.dataUrl;
      await new Promise(r => si.onload = r);
      const sw = (canvas.width * (s.w || 20)) / 100;
      ctx.drawImage(si, (canvas.width * s.x)/100, (canvas.height * s.y)/100, sw, sw * (si.height/si.width));
    }

    const pdf = new jspdf.jsPDF({ format: [canvas.width, canvas.height], unit: 'px' });
    pdf.addImage(canvas.toDataURL('image/jpeg', 0.9), 'JPEG', 0, 0, canvas.width, canvas.height);
    pdf.save(`${activeDoc?.name || 'Signed_Document'}.pdf`);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl">S</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignEase</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest">Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowSignaturePad(true)} className="text-sm font-bold text-indigo-600 bg-indigo-50 px-4 py-2 rounded-xl hover:bg-indigo-100 transition-colors">My Signs</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/80 z-[60] flex items-center justify-center flex-col gap-4">
            <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-bold text-gray-600">Processing document...</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-12 px-6 bg-white rounded-3xl shadow-xl border mt-10">
            <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">✓</div>
            <h2 className="text-2xl font-bold text-gray-800 mb-2">Signed Successfully!</h2>
            <p className="text-gray-500 mb-8">Stored safely on your device storage.</p>
            <div className="space-y-3">
              <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-bold py-4 rounded-2xl hover:bg-indigo-700 shadow-lg flex items-center justify-center gap-2">⬇️ Download PDF</button>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-gray-700 font-bold py-4 rounded-2xl hover:bg-slate-200">Go to Dashboard</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard 
                documents={documents} 
                onAction={() => { resetSigningState(); setCurrentView(AppView.SIGN_DOC); }}
                onViewDoc={(doc) => { setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }}
                onDeleteDoc={handleDeleteDoc}
              />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-4 duration-300">
                <div className="flex justify-between items-center mb-6">
                   <h2 className="text-xl font-bold text-gray-800">{activeDoc?.status === 'SIGNED' ? 'Viewing' : 'Sign Document'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-2 bg-white rounded-full shadow-sm">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                  <div className="bg-white border-2 border-dashed border-slate-200 rounded-3xl p-16 text-center">
                    <div className="text-5xl mb-4">📄</div>
                    <h3 className="text-lg font-bold text-gray-800 mb-2">Select a Document</h3>
                    <p className="text-sm text-gray-500 mb-8">PDF or Images supported</p>
                    <label className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-bold cursor-pointer hover:bg-indigo-700 shadow-xl inline-block transition-transform active:scale-95">
                      Choose File
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="bg-white rounded-3xl shadow-sm border p-4 flex flex-col gap-4">
                    <div ref={docContainerRef} className="bg-slate-100 rounded-2xl min-h-[400px] flex items-center justify-center relative overflow-hidden">
                      {(uploadFile || activeDoc?.fileData)?.startsWith('data:application/pdf') ? (
                        <canvas ref={pdfCanvasRef} className="pdf-canvas" />
                      ) : (
                        <img src={uploadFile || activeDoc?.fileData} className="max-h-[70vh] object-contain shadow-xl" alt="Preview" />
                      )}

                      {placedSignatures.map(ps => (
                        <div key={ps.id} style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 20}%` }} className="absolute z-10 cursor-move touch-none" onMouseDown={(e) => handleDrag(ps.id, e)} onTouchStart={(e) => handleDrag(ps.id, e)}>
                          <div className="relative group">
                            <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-400'} p-1`} />
                            {activeDoc?.status !== 'SIGNED' && (
                              <button onClick={() => setPlacedSignatures(prev => prev.filter(x => x.id !== ps.id))} className="absolute -top-3 -right-3 bg-red-500 text-white w-6 h-6 rounded-full text-[10px]">✕</button>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>

                    <div className="pt-4 border-t">
                       {activeDoc?.status === 'SIGNED' ? (
                         <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-bold py-4 rounded-2xl">Download PDF</button>
                       ) : (
                         <div className="space-y-4">
                            <p className="text-xs font-bold text-gray-400 uppercase">Tap signature to place</p>
                            <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-24 h-12 bg-white border border-slate-200 rounded-xl flex items-center justify-center p-1 shadow-sm active:bg-indigo-50">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-12 h-12 bg-indigo-50 text-indigo-600 rounded-xl border border-dashed border-indigo-200 font-bold">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-bold py-4 rounded-2xl shadow-lg disabled:opacity-50 transition-all">Finish & Save Locally</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t flex justify-around py-3 md:hidden z-40">
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className={`flex flex-col items-center gap-1 ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">🏠</span>
          <span className="text-[10px] font-bold">Home</span>
        </button>
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.SIGN_DOC); }} className={`flex flex-col items-center gap-1 ${currentView === AppView.SIGN_DOC ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">✍️</span>
          <span className="text-[10px] font-bold">Sign</span>
        </button>
        <button className="flex flex-col items-center gap-1 text-gray-400 opacity-50">
          <span className="text-xl">👤</span>
          <span className="text-[10px] font-bold">Profile</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { DocumentRecord, AppView } from '../types';

interface DashboardProps {
  documents: DocumentRecord[];
  onAction: (view: AppView) => void;
  onViewDoc: (doc: DocumentRecord) => void;
  onDeleteDoc: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ documents, onAction, onViewDoc, onDeleteDoc }) => {
  const [filter, setFilter] = useState<'ALL' | 'PENDING' | 'SIGNED'>('ALL');

  const filteredDocs = useMemo(() => {
    if (filter === 'ALL') return documents;
    return documents.filter(d => d.status === filter);
  }, [documents, filter]);

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    // Using custom-looking browser confirm for now, 
    // but ensured it correctly triggers the state removal.
    if (window.confirm("Are you sure? This document will be permanently deleted from this device.")) {
      onDeleteDoc(id);
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl shadow-indigo-100 relative overflow-hidden">
        <div className="relative z-10">
          <p className="text-indigo-100 text-sm font-bold uppercase tracking-widest mb-1">Welcome to SignEase</p>
          <h2 className="text-3xl font-black mb-6">Manage Your Documents</h2>
          <div className="flex gap-4">
             <div className="bg-white/10 backdrop-blur-md px-4 py-2 rounded-2xl border border-white/20">
                <span className="block text-2xl font-black">{documents.length}</span>
                <span className="text-[10px] uppercase font-bold opacity-70">Saved Files</span>
             </div>
             <button 
                onClick={() => onAction(AppView.SIGN_DOC)}
                className="bg-white text-indigo-600 px-6 py-4 rounded-2xl font-bold hover:shadow-lg transition-all active:scale-95 flex items-center gap-2"
              >
                <span className="text-xl">+</span> Sign New
              </button>
          </div>
        </div>
        <div className="absolute -right-10 -bottom-10 w-40 h-40 bg-white/10 rounded-full blur-3xl"></div>
      </div>

      <div className="flex items-center justify-between px-2">
         <h3 className="font-bold text-gray-800">Your Documents</h3>
         <div className="flex bg-white p-1 rounded-xl shadow-sm border">
            {(['ALL', 'SIGNED'] as const).map(f => (
              <button 
                key={f}
                onClick={() => setFilter(f)}
                className={`text-[10px] px-4 py-1.5 rounded-lg font-black transition-all ${filter === f ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-400'}`}
              >
                {f}
              </button>
            ))}
         </div>
      </div>

      <div className="space-y-3">
        {filteredDocs.length > 0 ? filteredDocs.map((doc, idx) => (
          <div 
            key={doc.id} 
            onClick={() => onViewDoc(doc)}
            className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center justify-between active:bg-slate-50 transition-colors animate-in fade-in slide-in-from-bottom-2 duration-300"
            style={{ animationDelay: `${idx * 50}ms` }}
          >
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-xl ${doc.type === 'PDF' ? 'bg-red-50 text-red-500' : 'bg-blue-50 text-blue-500'}`}>
                {doc.type === 'PDF' ? '📄' : '🖼️'}
              </div>
              <div className="overflow-hidden">
                <h4 className="text-sm font-bold text-gray-800 truncate max-w-[150px]">{doc.name}</h4>
                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">{doc.date} • {doc.type}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <span className={`text-[9px] font-black px-2 py-1 rounded-lg uppercase tracking-wider ${doc.status === 'SIGNED' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>
                {doc.status}
              </span>
              <button 
                onClick={(e) => handleDelete(e, doc.id)}
                className="p-2.5 bg-slate-50 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
              >
                🗑️
              </button>
            </div>
          </div>
        )) : (
          <div className="py-20 text-center bg-white rounded-[2rem] border-2 border-dashed border-slate-100">
             <div className="text-4xl mb-4 grayscale opacity-50">📂</div>
             <p className="text-gray-400 text-sm font-bold">No documents found locally.</p>
             <button onClick={() => onAction(AppView.SIGN_DOC)} className="mt-4 text-indigo-600 text-xs font-black uppercase tracking-widest">+ Add your first file</button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';

declare const jspdf: any;
declare const pdfjsLib: any;

// Set worker for pdf.js
if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const STORAGE_KEYS = {
  DOCUMENTS: 'signease_docs_v2',
  SIGNATURES: 'signease_sigs_v2'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const docContainerRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);

  // Persistence
  useEffect(() => {
    const savedDocs = localStorage.getItem(STORAGE_KEYS.DOCUMENTS);
    const savedSigs = localStorage.getItem(STORAGE_KEYS.SIGNATURES);
    if (savedDocs) setDocuments(JSON.parse(savedDocs));
    if (savedSigs) setSignatures(JSON.parse(savedSigs));
  }, []);

  const saveToStorage = useCallback((docs: DocumentRecord[]) => {
    try {
      localStorage.setItem(STORAGE_KEYS.DOCUMENTS, JSON.stringify(docs));
    } catch (e) {
      console.error("Storage error", e);
      alert("Storage full! Please delete some old documents.");
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  // PDF Rendering Logic
  useEffect(() => {
    const renderPDF = async (dataUrl: string) => {
      if (!pdfCanvasRef.current) return;
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        const page = await pdf.getPage(1); // Render first page for signing
        const viewport = page.getViewport({ scale: 1.5 });
        const canvas = pdfCanvasRef.current;
        const context = canvas.getContext('2d');
        canvas.height = viewport.height;
        canvas.width = viewport.width;
        await page.render({ canvasContext: context, viewport }).promise;
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data?.startsWith('data:application/pdf')) {
      renderPDF(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    const updated = [newSign, ...signatures];
    setSignatures(updated);
    localStorage.setItem(STORAGE_KEYS.SIGNATURES, JSON.stringify(updated));
    setShowSignaturePad(false);
  };

  const handleSignFinish = () => {
    const isPdf = (uploadFile || activeDoc?.fileData)?.startsWith('data:application/pdf');
    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || (isPdf ? 'Signed_Doc.pdf' : 'Signed_Image.png'),
      type: (isPdf ? 'PDF' : 'IMAGE'),
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: uploadFile || activeDoc?.fileData,
      placedSignatures: [...placedSignatures]
    };

    setDocuments(prev => {
      let updatedDocs;
      if (activeDoc) {
        updatedDocs = prev.map(d => d.id === activeDoc.id ? newDoc : d);
      } else {
        updatedDocs = [newDoc, ...prev];
      }
      saveToStorage(updatedDocs);
      return updatedDocs;
    });
    setShowSuccessScreen(true);
  };

  const handleDeleteDoc = (id: string) => {
    setDocuments(prev => {
      const updatedDocs = prev.filter(d => d.id !== id);
      saveToStorage(updatedDocs);
      return updatedDocs;
    });

    // Using a microtask to check activeDoc after state might have changed or just checking against id
    if (activeDoc?.id === id) {
      resetSigningState();
      setCurrentView(AppView.DASHBOARD);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 30, y: 30, w: 20 
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    const rect = docContainerRef.current?.getBoundingClientRect();
    if (!rect) return;
    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;
      const x = Math.max(0, Math.min(90, ((cx - rect.left) / rect.width) * 100));
      const y = Math.max(0, Math.min(95, ((cy - rect.top) / rect.height) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y } : p));
    };
    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };
    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleDownload = async () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = 1240; canvas.height = 1754;
    ctx.fillStyle = '#fff'; ctx.fillRect(0,0,1240,1754);

    const fileToUse = uploadFile || activeDoc?.fileData;
    if (fileToUse?.startsWith('data:image')) {
      const img = new Image(); img.src = fileToUse;
      await new Promise(r => img.onload = r);
      canvas.height = canvas.width * (img.height/img.width);
      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    } else {
      ctx.fillStyle = '#000'; ctx.font = '30px Inter';
      ctx.fillText("Signed PDF Content", 100, 100);
    }

    for (const s of placedSignatures) {
      const si = new Image(); si.src = s.dataUrl;
      await new Promise(r => si.onload = r);
      const sw = (canvas.width * (s.w || 20)) / 100;
      ctx.drawImage(si, (canvas.width * s.x)/100, (canvas.height * s.y)/100, sw, sw * (si.height/si.width));
    }

    const pdf = new jspdf.jsPDF({ format: [canvas.width, canvas.height], unit: 'px' });
    pdf.addImage(canvas.toDataURL('image/jpeg', 0.9), 'JPEG', 0, 0, canvas.width, canvas.height);
    pdf.save(`${activeDoc?.name || 'Signed_Document'}.pdf`);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl">S</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignEase</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest">Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowSignaturePad(true)} className="text-sm font-bold text-indigo-600 bg-indigo-50 px-4 py-2 rounded-xl hover:bg-indigo-100 transition-colors">My Signs</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/80 z-[60] flex items-center justify-center flex-col gap-4">
            <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-bold text-gray-600">Processing document...</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-12 px-6 bg-white rounded-3xl shadow-xl border mt-10">
            <div className="w-20 h-20 bg-emerald-100 text-emerald-600 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">✓</div>
            <h2 className="text-2xl font-bold text-gray-800 mb-2">Signed Successfully!</h2>
            <p className="text-gray-500 mb-8">Stored safely on your device storage.</p>
            <div className="space-y-3">
              <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-bold py-4 rounded-2xl hover:bg-indigo-700 shadow-lg flex items-center justify-center gap-2">⬇️ Download PDF</button>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-gray-700 font-bold py-4 rounded-2xl hover:bg-slate-200">Go to Dashboard</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard 
                documents={documents} 
                onAction={() => { resetSigningState(); setCurrentView(AppView.SIGN_DOC); }}
                onViewDoc={(doc) => { 
                  resetSigningState();
                  setActiveDoc(doc); 
                  setPlacedSignatures(doc.placedSignatures || []); 
                  setCurrentView(AppView.SIGN_DOC); 
                }}
                onDeleteDoc={handleDeleteDoc}
              />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-4 duration-300">
                <div className="flex justify-between items-center mb-6">
                   <h2 className="text-xl font-bold text-gray-800">{activeDoc?.status === 'SIGNED' ? 'Viewing' : 'Sign Document'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-2 bg-white rounded-full shadow-sm">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                  <div className="bg-white border-2 border-dashed border-slate-200 rounded-3xl p-16 text-center">
                    <div className="text-5xl mb-4">📄</div>
                    <h3 className="text-lg font-bold text-gray-800 mb-2">Select a Document</h3>
                    <p className="text-sm text-gray-500 mb-8">PDF or Images supported</p>
                    <label className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-bold cursor-pointer hover:bg-indigo-700 shadow-xl inline-block transition-transform active:scale-95">
                      Choose File
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="bg-white rounded-3xl shadow-sm border p-4 flex flex-col gap-4">
                    <div ref={docContainerRef} className="bg-slate-100 rounded-2xl min-h-[400px] flex items-center justify-center relative overflow-hidden">
                      {(uploadFile || activeDoc?.fileData)?.startsWith('data:application/pdf') ? (
                        <canvas ref={pdfCanvasRef} className="pdf-canvas" />
                      ) : (
                        <img src={uploadFile || activeDoc?.fileData} className="max-h-[70vh] object-contain shadow-xl" alt="Preview" />
                      )}

                      {placedSignatures.map(ps => (
                        <div key={ps.id} style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 20}%` }} className="absolute z-10 cursor-move touch-none" onMouseDown={(e) => handleDrag(ps.id, e)} onTouchStart={(e) => handleDrag(ps.id, e)}>
                          <div className="relative group">
                            <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-400'} p-1`} />
                            {activeDoc?.status !== 'SIGNED' && (
                              <button onClick={() => setPlacedSignatures(prev => prev.filter(x => x.id !== ps.id))} className="absolute -top-3 -right-3 bg-red-500 text-white w-6 h-6 rounded-full text-[10px] flex items-center justify-center shadow-md">✕</button>
                            )}
                          </div>
                        </div>
                      ))}
                    </div>

                    <div className="pt-4 border-t">
                       {activeDoc?.status === 'SIGNED' ? (
                         <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-bold py-4 rounded-2xl">Download PDF</button>
                       ) : (
                         <div className="space-y-4">
                            <p className="text-xs font-bold text-gray-400 uppercase">Tap signature to place</p>
                            <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-24 h-12 bg-white border border-slate-200 rounded-xl flex items-center justify-center p-1 shadow-sm active:bg-indigo-50">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-12 h-12 bg-indigo-50 text-indigo-600 rounded-xl border border-dashed border-indigo-200 font-bold">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-bold py-4 rounded-2xl shadow-lg disabled:opacity-50 transition-all">Finish & Save Locally</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}

      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t flex justify-around py-3 md:hidden z-40">
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className={`flex flex-col items-center gap-1 ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">🏠</span>
          <span className="text-[10px] font-bold">Home</span>
        </button>
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.SIGN_DOC); }} className={`flex flex-col items-center gap-1 ${currentView === AppView.SIGN_DOC ? 'text-indigo-600' : 'text-gray-400'}`}>
          <span className="text-xl">✍️</span>
          <span className="text-[10px] font-bold">Sign</span>
        </button>
        <button className="flex flex-col items-center gap-1 text-gray-400 opacity-50">
          <span className="text-xl">👤</span>
          <span className="text-[10px] font-bold">Profile</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { DocumentRecord, AppView } from '../types';

interface DashboardProps {
  documents: DocumentRecord[];
  onAction: (view: AppView) => void;
  onViewDoc: (doc: DocumentRecord) => void;
  onDeleteDoc: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ documents, onAction, onViewDoc, onDeleteDoc }) => {
  const [filter, setFilter] = useState<'ALL' | 'SIGNED'>('ALL');
  const [docToDelete, setDocToDelete] = useState<string | null>(null);

  const filteredDocs = useMemo(() => {
    if (filter === 'ALL') return documents;
    return documents.filter(d => d.status === filter);
  }, [documents, filter]);

  const confirmDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setDocToDelete(id);
  };

  const handleFinalDelete = () => {
    if (docToDelete) {
      onDeleteDoc(docToDelete);
      setDocToDelete(null);
    }
  };

  return (
    <div className="space-y-6">
      {/* Custom Confirmation Modal */}
      {docToDelete && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 p-6 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="w-full max-w-sm bg-white rounded-[2.5rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center text-3xl mx-auto mb-6">🗑️</div>
            <h3 className="text-xl font-black text-gray-900 text-center mb-2">Delete Document?</h3>
            <p className="text-gray-500 text-center text-sm leading-relaxed mb-8">
              This will permanently remove the document from your device. This action cannot be undone.
            </p>
            <div className="flex flex-col gap-3">
              <button 
                onClick={handleFinalDelete}
                className="w-full py-4 bg-red-500 text-white font-black rounded-2xl hover:bg-red-600 transition-all active:scale-95"
              >
                Yes, Delete Forever
              </button>
              <button 
                onClick={() => setDocToDelete(null)}
                className="w-full py-4 bg-slate-100 text-gray-700 font-bold rounded-2xl hover:bg-slate-200 transition-all"
              >
                No, Keep it
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl shadow-indigo-100 relative overflow-hidden">
        <div className="relative z-10">
          <p className="text-indigo-100 text-sm font-bold uppercase tracking-widest mb-1">Welcome to SignEase</p>
          <h2 className="text-3xl font-black mb-6">Manage Your Documents</h2>
          <div className="flex gap-4">
             <div className="bg-white/10 backdrop-blur-md px-4 py-2 rounded-2xl border border-white/20">
                <span className="block text-2xl font-black">{documents.length}</span>
                <span className="text-[10px] uppercase font-bold opacity-70">Saved Files</span>
             </div>
             <button 
                onClick={() => onAction(AppView.SIGN_DOC)}
                className="bg-white text-indigo-600 px-6 py-4 rounded-2xl font-bold hover:shadow-lg transition-all active:scale-95 flex items-center gap-2"
              >
                <span className="text-xl">+</span> Sign New
              </button>
          </div>
        </div>
        <div className="absolute -right-10 -bottom-10 w-40 h-40 bg-white/10 rounded-full blur-3xl"></div>
      </div>

      <div className="flex items-center justify-between px-2">
         <h3 className="font-bold text-gray-800">Your Documents</h3>
         <div className="flex bg-white p-1 rounded-xl shadow-sm border">
            {(['ALL', 'SIGNED'] as const).map(f => (
              <button 
                key={f}
                onClick={() => setFilter(f)}
                className={`text-[10px] px-4 py-1.5 rounded-lg font-black transition-all ${filter === f ? 'bg-indigo-600 text-white shadow-md' : 'text-gray-400'}`}
              >
                {f}
              </button>
            ))}
         </div>
      </div>

      <div className="space-y-3">
        {filteredDocs.length > 0 ? filteredDocs.map((doc, idx) => (
          <div 
            key={doc.id} 
            onClick={() => onViewDoc(doc)}
            className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm flex items-center justify-between active:bg-slate-50 transition-colors animate-in fade-in slide-in-from-bottom-2 duration-300"
            style={{ animationDelay: `${idx * 50}ms` }}
          >
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-xl ${doc.type === 'PDF' ? 'bg-red-50 text-red-500' : 'bg-blue-50 text-blue-500'}`}>
                {doc.type === 'PDF' ? '📄' : '🖼️'}
              </div>
              <div className="overflow-hidden">
                <h4 className="text-sm font-bold text-gray-800 truncate max-w-[150px]">{doc.name}</h4>
                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">{doc.date} • {doc.type}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <span className={`text-[9px] font-black px-2 py-1 rounded-lg uppercase tracking-wider ${doc.status === 'SIGNED' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>
                {doc.status}
              </span>
              <button 
                onClick={(e) => confirmDelete(e, doc.id)}
                className="p-2.5 bg-slate-50 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
