      const x = Math.max(-5, Math.min(95, ((cx - rect.left) / rect.width) * 100));
      const y = Math.max(-5, Math.min(95, ((cy - rect.top) / rect.height) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y } : p));
    };
    const end = () => { window.removeEventListener('mousemove', move); window.removeEventListener('touchmove', move); };
    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, e: any) => {
    e.stopPropagation();
    if (activeDoc?.status === 'SIGNED') return;
    const rect = docWrapperRef.current?.getBoundingClientRect();
    if (!rect) return;
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;
    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(8, Math.min(80, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };
    const end = () => { window.removeEventListener('mousemove', move); window.removeEventListener('touchmove', move); };
    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleDownload = async () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = 1240; canvas.height = 1754;
    ctx.fillStyle = '#fff'; ctx.fillRect(0,0,1240,1754);
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (fileToUse?.startsWith('data:image')) {
      const img = new Image(); img.src = fileToUse;
      await new Promise(r => img.onload = r);
      canvas.height = canvas.width * (img.height/img.width);
      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    } else {
      ctx.fillStyle = '#000'; ctx.font = 'bold 40px Inter';
      ctx.fillText("Signed PDF Rendering Layer", 100, 100);
      ctx.font = '24px Inter'; ctx.fillText(`Name: ${activeDoc?.name || 'Document'}`, 100, 140);
    }
    for (const s of placedSignatures) {
      const si = new Image(); si.src = s.dataUrl;
      await new Promise(r => si.onload = r);
      const sw = (canvas.width * (s.w || 25)) / 100;
      ctx.drawImage(si, (canvas.width * s.x)/100, (canvas.height * s.y)/100, sw, sw * (si.height/si.width));
    }
    const pdf = new jspdf.jsPDF({ format: [canvas.width, canvas.height], unit: 'px' });
    pdf.addImage(canvas.toDataURL('image/jpeg', 0.85), 'JPEG', 0, 0, canvas.width, canvas.height);
    pdf.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-100 transition-transform active:scale-95">S</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignEase</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest">Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowSignaturePad(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/90 z-[70] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-14 h-14 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-800 tracking-tight">Preparing your document...</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Done!</h2>
            <p className="text-gray-500 font-medium mb-10">Your signed document is ready.</p>
            <div className="space-y-4">
              <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl hover:bg-indigo-700 shadow-xl shadow-indigo-100 transition-all active:scale-95 flex items-center justify-center gap-2">⬇️ Download PDF</button>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Back to Home</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard documents={documents} onAction={() => { resetSigningState(); setCurrentView(AppView.SIGN_DOC); }} onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} onDeleteDoc={handleDeleteDoc} />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'Viewing' : 'Sign Now'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                  <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload Document</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">We support PDF, JPEG, and PNG</p>
                    <label className="bg-indigo-600 text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-indigo-700 shadow-2xl shadow-indigo-100 inline-block transition-transform active:scale-95">
                      Select File
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-6">
                    <div className="bg-slate-200/50 rounded-[2.5rem] p-4 flex items-center justify-center overflow-auto min-h-[60vh] scrollbar-hide">
                      <div ref={docWrapperRef} className="relative shadow-2xl bg-white leading-[0] transition-transform duration-300 origin-center">
                        {(uploadFile || activeDoc?.fileData)?.startsWith('data:application/pdf') ? (
                          <canvas ref={pdfCanvasRef} className="max-w-full h-auto" />
                        ) : (
                          <img src={uploadFile || activeDoc?.fileData} className="max-w-full max-h-[85vh] object-contain" alt="Preview" />
                        )}

                        {placedSignatures.map(ps => (
                          <div key={ps.id} style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} className="absolute z-20 cursor-move touch-none" onMouseDown={(e) => handleDrag(ps.id, e)} onTouchStart={(e) => handleDrag(ps.id, e)}>
                            <div className="relative group">
                              <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-500/50'} p-0.5`} />
                              {activeDoc?.status !== 'SIGNED' && (
                                <>
                                  <button onClick={(e) => { e.stopPropagation(); setPlacedSignatures(p => p.filter(x => x.id !== ps.id)); }} className="absolute -top-4 -right-4 bg-red-500 text-white w-8 h-8 rounded-full text-xs flex items-center justify-center shadow-lg font-bold border-2 border-white z-30">✕</button>
                                  <div onMouseDown={(e) => handleResize(ps.id, e)} onTouchStart={(e) => handleResize(ps.id, e)} className="resize-handle absolute -bottom-4 -right-4 w-9 h-9 bg-indigo-600 border-4 border-white rounded-full cursor-nwse-resize shadow-xl flex items-center justify-center z-30">
                                    <div className="w-2.5 h-2.5 border-r-2 border-b-2 border-white rotate-45 mb-1 mr-1"></div>
                                  </div>
                                </>
                              )}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>

                    <div className="bg-white rounded-[2.5rem] p-6 shadow-xl border border-slate-100 sticky bottom-2">
                       {activeDoc?.status === 'SIGNED' ? (
                         <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download Signed PDF</button>
                       ) : (
                         <div className="space-y-6">
                            <div className="flex justify-between items-center px-1">
                              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Available Signatures</p>
                              <span className="text-[10px] font-bold text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded-md">Tap to place</span>
                            </div>
                            <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-28 h-16 bg-white border-2 border-slate-100 rounded-2xl flex items-center justify-center p-2 shadow-sm hover:border-indigo-300 transition-all active:scale-90">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-16 h-16 bg-slate-50 text-slate-400 rounded-2xl border-2 border-dashed border-slate-200 text-2xl font-bold flex items-center justify-center active:bg-indigo-50 transition-colors">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 disabled:opacity-30 disabled:shadow-none transition-all active:scale-95">Finish & Securely Save</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t flex justify-around py-4 md:hidden z-40">
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className={`flex flex-col items-center gap-1 transition-colors ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-slate-400'}`}>
          <span className="text-2xl">🏠</span>
          <span className="text-[9px] font-black uppercase tracking-tighter">Dashboard</span>
        </button>
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.SIGN_DOC); }} className={`flex flex-col items-center gap-1 transition-colors ${currentView === AppView.SIGN_DOC ? 'text-indigo-600' : 'text-slate-400'}`}>
          <span className="text-2xl">✍️</span>
          <span className="text-[9px] font-black uppercase tracking-tighter">Sign</span>
        </button>
        <button onClick={() => setShowSignaturePad(true)} className="flex flex-col items-center gap-1 text-slate-400">
          <span className="text-2xl">⚙️</span>
          <span className="text-[9px] font-black uppercase tracking-tighter">Manage</span>
        </button>
      </nav>
    </div>
  );
};

