import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';
import RentReceiptCreator from './components/RentReceiptCreator';

declare const jspdf: any;
declare const pdfjsLib: any;

if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const STORAGE_KEYS = {
  DOCUMENTS: 'signease_docs_v3',
  SIGNATURES: 'signease_sigs_v3'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [showReceiptCreator, setShowReceiptCreator] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const docWrapperRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const savedDocs = localStorage.getItem(STORAGE_KEYS.DOCUMENTS);
    const savedSigs = localStorage.getItem(STORAGE_KEYS.SIGNATURES);
    if (savedDocs) setDocuments(JSON.parse(savedDocs));
    if (savedSigs) setSignatures(JSON.parse(savedSigs));
  }, []);

  const saveToStorage = useCallback((docs: DocumentRecord[]) => {
    try {
      localStorage.setItem(STORAGE_KEYS.DOCUMENTS, JSON.stringify(docs));
    } catch (e) {
      console.error("Storage error", e);
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
    setShowReceiptCreator(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleReceiptGenerate = (data: any) => {
    setIsLoading(true);
    setShowReceiptCreator(false);
    // Simulate complex receipt generation
    setTimeout(() => {
      const receiptId = `REC-${Date.now()}`;
      setActiveDoc({
        id: receiptId,
        name: `Rent_${data.month.replace(' ', '_')}.pdf`,
        type: 'RECEIPT',
        status: 'PENDING',
        date: new Date().toLocaleDateString('en-IN'),
        fileData: JSON.stringify(data)
      });
      setCurrentView(AppView.SIGN_DOC);
      setIsLoading(false);
    }, 800);
  };

  useEffect(() => {
    const renderPDF = async (dataUrl: string) => {
      if (!pdfCanvasRef.current) return;
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        const page = await pdf.getPage(1); 
        const viewport = page.getViewport({ scale: 2 });
        const canvas = pdfCanvasRef.current;
        const context = canvas.getContext('2d');
        if (!context) return;
        canvas.height = viewport.height;
        canvas.width = viewport.width;
        await page.render({ canvasContext: context, viewport }).promise;
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data && data.startsWith('data:application/pdf')) {
      renderPDF(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    const updated = [newSign, ...signatures];
    setSignatures(updated);
    localStorage.setItem(STORAGE_KEYS.SIGNATURES, JSON.stringify(updated));
    setShowSignaturePad(false);
  };

  const handleSignFinish = () => {
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) return;
    const isPdf = fileToUse.startsWith('data:application/pdf');
    const isReceipt = activeDoc?.type === 'RECEIPT';

    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || (isPdf ? 'Signed_Doc.pdf' : 'Signed_Image.png'),
      type: isReceipt ? 'RECEIPT' : (isPdf ? 'PDF' : 'IMAGE'),
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: fileToUse,
      placedSignatures: [...placedSignatures]
    };

    setDocuments(prev => {
      const updatedDocs = activeDoc && !uploadFile ? prev.map(d => d.id === activeDoc.id ? newDoc : d) : [newDoc, ...prev];
      saveToStorage(updatedDocs);
      return updatedDocs;
    });
    setShowSuccessScreen(true);
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 40, y: 50, w: 25 
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    const rect = docWrapperRef.current?.getBoundingClientRect();
    if (!rect) return;
    if (e.target.closest('.resize-handle')) return;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;
      const x = Math.max(-10, Math.min(100, ((cx - rect.left) / rect.width) * 100));
      const y = Math.max(-10, Math.min(100, ((cy - rect.top) / rect.height) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y } : p));
    };
    const end = () => { window.removeEventListener('mousemove', move); window.removeEventListener('touchmove', move); };
    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, e: any) => {
    e.stopPropagation();
    const rect = docWrapperRef.current?.getBoundingClientRect();
    if (!rect) return;
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;
    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(10, Math.min(90, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };
    const end = () => { window.removeEventListener('mousemove', move); window.removeEventListener('touchmove', move); };
    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleDownload = async () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = 1240; canvas.height = 1754;
    ctx.fillStyle = '#fff'; ctx.fillRect(0,0,1240,1754);

    const fileToUse = uploadFile || activeDoc?.fileData;
    if (activeDoc?.type === 'RECEIPT') {
       const r = JSON.parse(fileToUse || '{}');
       ctx.fillStyle = '#000'; ctx.font = 'bold 60px Inter'; ctx.fillText("RENT RECEIPT", 400, 150);
       ctx.font = '30px Inter';
       ctx.fillText(`Date: ${new Date().toLocaleDateString('en-IN')}`, 100, 250);
       ctx.fillText(`Received with thanks from Mr./Ms. ${r.tenantName}`, 100, 320);
       ctx.fillText(`a sum of ₹${r.rentAmount} for the month of ${r.month}`, 100, 370);
       ctx.fillText(`towards rent of property at: ${r.address}`, 100, 420);
       ctx.fillText(`Landlord: ${r.landlordName}`, 100, 520);
       if (r.panNumber) ctx.fillText(`Landlord PAN: ${r.panNumber}`, 100, 570);
       ctx.strokeStyle = '#eee'; ctx.strokeRect(100, 650, 1040, 400);
    } else if (fileToUse?.startsWith('data:image')) {
      const img = new Image(); img.src = fileToUse;
      await new Promise(r => img.onload = r);
      canvas.height = canvas.width * (img.height/img.width);
      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    }

    for (const s of placedSignatures) {
      const si = new Image(); si.src = s.dataUrl;
      await new Promise(r => si.onload = r);
      const sw = (canvas.width * (s.w || 25)) / 100;
      ctx.drawImage(si, (canvas.width * s.x)/100, (canvas.height * s.y)/100, sw, sw * (si.height/si.width));
    }
    const pdf = new jspdf.jsPDF({ format: [canvas.width, canvas.height], unit: 'px' });
    pdf.addImage(canvas.toDataURL('image/jpeg', 0.85), 'JPEG', 0, 0, canvas.width, canvas.height);
    pdf.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
  };

  const handleShare = (platform: 'whatsapp' | 'email') => {
    const text = encodeURIComponent(`Hi, I have signed the document: ${activeDoc?.name}. Please find it on SignEase.`);
    if (platform === 'whatsapp') window.open(`https://wa.me/?text=${text}`, '_blank');
    else window.location.href = `mailto:?subject=Signed Document&body=${text}`;
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-100 transition-transform active:scale-95">S</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignEase</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest">Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowSignaturePad(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/90 z-[70] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-14 h-14 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-800 tracking-tight">Processing...</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Success!</h2>
            <p className="text-gray-500 font-medium mb-10">Document signed and secured.</p>
            <div className="space-y-3">
              <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                 <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">WhatsApp</button>
                 <button onClick={() => handleShare('email')} className="flex-1 bg-slate-800 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">Email</button>
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Home</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <>
                <Dashboard documents={documents} onAction={(v) => { resetSigningState(); v === AppView.RENT_RECEIPT ? setShowReceiptCreator(true) : setCurrentView(AppView.SIGN_DOC); }} onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} onDeleteDoc={handleDeleteDoc} />
                <div className="mt-8 bg-indigo-50 p-6 rounded-[2rem] border border-indigo-100 flex items-center justify-between">
                  <div>
                    <h4 className="font-black text-indigo-900">Need a Rent Receipt?</h4>
                    <p className="text-xs font-medium text-indigo-600">HRA compliant & ready for signature.</p>
                  </div>
                  <button onClick={() => setShowReceiptCreator(true)} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-black text-xs active:scale-95 transition-all">Create Now</button>
                </div>
              </>
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'View Document' : 'Place Signature'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                   <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload File</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">Select a document to sign</p>
                    <label className="bg-indigo-600 text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-indigo-700 shadow-2xl shadow-indigo-100 inline-block transition-transform active:scale-95">
                      Choose File
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-6">
                    <div className="bg-slate-100/80 rounded-[2.5rem] p-4 flex items-center justify-center overflow-auto min-h-[60vh] scrollbar-hide border border-slate-200/50">
                      <div ref={docWrapperRef} className="relative shadow-2xl bg-white leading-[0] transition-all origin-center">
                        {activeDoc?.type === 'RECEIPT' ? (
                          <div className="w-[800px] h-[1130px] p-16 relative bg-white border border-slate-200">
                             <h1 className="text-5xl font-black text-center mb-16 tracking-tight">RENT RECEIPT</h1>
                             <div className="space-y-12 text-xl font-medium leading-relaxed text-slate-700">
                               <p className="border-b-2 border-slate-100 pb-4">Date: <span className="font-bold text-black">{new Date().toLocaleDateString('en-IN')}</span></p>
                               <p className="border-b-2 border-slate-100 pb-4">Received with thanks from Mr./Ms. <span className="font-black text-black">{(JSON.parse(activeDoc.fileData || '{}')).tenantName}</span></p>
                               <p className="border-b-2 border-slate-100 pb-4">a sum of <span className="font-black text-black">₹{(JSON.parse(activeDoc.fileData || '{}')).rentAmount}</span> for the month of <span className="font-black text-black">{(JSON.parse(activeDoc.fileData || '{}')).month}</span></p>
                               <p className="border-b-2 border-slate-100 pb-4">towards rent of property at: <span className="font-black text-black">{(JSON.parse(activeDoc.fileData || '{}')).address}</span></p>
                               <div className="pt-24 mt-24 border-t-2 border-slate-50">
                                  <p className="text-sm font-black uppercase tracking-widest text-slate-400">Landlord Details</p>
                                  <p className="text-2xl font-black text-black mt-2">{(JSON.parse(activeDoc.fileData || '{}')).landlordName}</p>
                                  {(JSON.parse(activeDoc.fileData || '{}')).panNumber && <p className="text-sm font-bold text-indigo-600 mt-1 uppercase">PAN: {(JSON.parse(activeDoc.fileData || '{}')).panNumber}</p>}
                               </div>
                             </div>
                          </div>
                        ) : (uploadFile || activeDoc?.fileData)?.startsWith('data:application/pdf') ? (
                          <canvas ref={pdfCanvasRef} className="max-w-full h-auto" />
                        ) : (
                          <img src={uploadFile || activeDoc?.fileData} className="max-w-full max-h-[85vh] object-contain" alt="Preview" />
                        )}

                        {placedSignatures.map(ps => (
                          <div key={ps.id} style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} className="absolute z-20 cursor-move touch-none animate-pulse-once" onMouseDown={(e) => handleDrag(ps.id, e)} onTouchStart={(e) => handleDrag(ps.id, e)}>
                            <div className="relative group">
                              <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-500/50'} p-0.5`} />
                              {activeDoc?.status !== 'SIGNED' && (
                                <>
                                  <button onClick={(e) => { e.stopPropagation(); setPlacedSignatures(p => p.filter(x => x.id !== ps.id)); }} className="absolute -top-4 -right-4 bg-red-500 text-white w-8 h-8 rounded-full text-xs flex items-center justify-center shadow-lg font-bold border-2 border-white z-30">✕</button>
                                  <div onMouseDown={(e) => handleResize(ps.id, e)} onTouchStart={(e) => handleResize(ps.id, e)} className="resize-handle absolute -bottom-4 -right-4 w-9 h-9 bg-indigo-600 border-4 border-white rounded-full cursor-nwse-resize shadow-xl flex items-center justify-center z-30">
                                    <div className="w-2.5 h-2.5 border-r-2 border-b-2 border-white rotate-45 mb-1 mr-1"></div>
                                  </div>
                                </>
                              )}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>

                    <div className="bg-white rounded-[2.5rem] p-6 shadow-xl border border-slate-100 sticky bottom-2">
                       {activeDoc?.status === 'SIGNED' ? (
                         <div className="flex gap-3">
                           <button onClick={handleDownload} className="flex-[2] bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download</button>
                           <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all text-[10px] uppercase tracking-widest">Share</button>
                         </div>
                       ) : (
                         <div className="space-y-6">
                            <div className="flex justify-between items-center px-1">
                              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Select Signature</p>
                            </div>
                            <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-28 h-16 bg-white border-2 border-slate-100 rounded-2xl flex items-center justify-center p-2 shadow-sm hover:border-indigo-300 transition-all active:scale-90 overflow-hidden">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply object-contain" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-16 h-16 bg-slate-50 text-slate-400 rounded-2xl border-2 border-dashed border-slate-200 text-2xl font-bold flex items-center justify-center active:bg-indigo-50 transition-colors">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 disabled:opacity-30 transition-all active:scale-95">Complete Signing</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}
      {showReceiptCreator && <RentReceiptCreator onGenerate={handleReceiptGenerate} onCancel={() => setShowReceiptCreator(false)} />}

      <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t flex justify-around py-4 md:hidden z-40">
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className={`flex flex-col items-center gap-1 transition-colors ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-slate-400'}`}>
          <span className="text-2xl">🏠</span>
          <span className="text-[9px] font-black uppercase tracking-tighter">Home</span>
        </button>
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.SIGN_DOC); }} className={`flex flex-col items-center gap-1 transition-colors ${currentView === AppView.SIGN_DOC ? 'text-indigo-600' : 'text-slate-400'}`}>
          <span className="text-2xl">✍️</span>
          <span className="text-[9px] font-black uppercase tracking-tighter">Sign</span>
        </button>
        <button onClick={() => setShowReceiptCreator(true)} className="flex flex-col items-center gap-1 text-slate-400">
          <span className="text-2xl">🧾</span>
          <span className="text-[9px] font-black uppercase tracking-tighter">Receipt</span>
        </button>
      </nav>

      <style>{`
        @keyframes pulse-once {
          0% { transform: scale(0.9); opacity: 0; }
          50% { transform: scale(1.05); opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
        .animate-pulse-once {
          animation: pulse-once 0.4s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';
import RentReceiptCreator from './components/RentReceiptCreator';

declare const jspdf: any;
declare const pdfjsLib: any;

if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const STORAGE_KEYS = {
  DOCUMENTS: 'signease_docs_v3',
  SIGNATURES: 'signease_sigs_v3'
};

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [showReceiptCreator, setShowReceiptCreator] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const docWrapperRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const savedDocs = localStorage.getItem(STORAGE_KEYS.DOCUMENTS);
    const savedSigs = localStorage.getItem(STORAGE_KEYS.SIGNATURES);
    if (savedDocs) setDocuments(JSON.parse(savedDocs));
    if (savedSigs) setSignatures(JSON.parse(savedSigs));
  }, []);

  const saveToStorage = useCallback((docs: DocumentRecord[]) => {
    try {
      localStorage.setItem(STORAGE_KEYS.DOCUMENTS, JSON.stringify(docs));
    } catch (e) {
      console.error("Storage error", e);
    }
  }, []);

  // Fix: Added the missing handleDeleteDoc function to remove documents from state and storage
  const handleDeleteDoc = useCallback((id: string) => {
    setDocuments(prev => {
      const updated = prev.filter(doc => doc.id !== id);
      saveToStorage(updated);
      return updated;
    });
  }, [saveToStorage]);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
    setShowReceiptCreator(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleReceiptGenerate = (data: any) => {
    setIsLoading(true);
    setShowReceiptCreator(false);
    // Simulate complex receipt generation
    setTimeout(() => {
      const receiptId = `REC-${Date.now()}`;
      setActiveDoc({
        id: receiptId,
        name: `Rent_${data.month.replace(' ', '_')}.pdf`,
        type: 'RECEIPT',
        status: 'PENDING',
        date: new Date().toLocaleDateString('en-IN'),
        fileData: JSON.stringify(data)
      });
      setCurrentView(AppView.SIGN_DOC);
      setIsLoading(false);
    }, 800);
  };

  useEffect(() => {
    const renderPDF = async (dataUrl: string) => {
      if (!pdfCanvasRef.current) return;
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        const page = await pdf.getPage(1); 
        const viewport = page.getViewport({ scale: 2 });
        const canvas = pdfCanvasRef.current;
        const context = canvas.getContext('2d');
        if (!context) return;
        canvas.height = viewport.height;
        canvas.width = viewport.width;
        await page.render({ canvasContext: context, viewport }).promise;
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data && data.startsWith('data:application/pdf')) {
      renderPDF(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    const updated = [newSign, ...signatures];
    setSignatures(updated);
    localStorage.setItem(STORAGE_KEYS.SIGNATURES, JSON.stringify(updated));
    setShowSignaturePad(false);
  };

  const handleSignFinish = () => {
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) return;
    const isPdf = fileToUse.startsWith('data:application/pdf');
    const isReceipt = activeDoc?.type === 'RECEIPT';

    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || (isPdf ? 'Signed_Doc.pdf' : 'Signed_Image.png'),
      type: isReceipt ? 'RECEIPT' : (isPdf ? 'PDF' : 'IMAGE'),
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: fileToUse,
      placedSignatures: [...placedSignatures]
    };

    setDocuments(prev => {
      const updatedDocs = activeDoc && !uploadFile ? prev.map(d => d.id === activeDoc.id ? newDoc : d) : [newDoc, ...prev];
      saveToStorage(updatedDocs);
      return updatedDocs;
    });
    setShowSuccessScreen(true);
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 40, y: 50, w: 25 
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    const rect = docWrapperRef.current?.getBoundingClientRect();
    if (!rect) return;
    if (e.target.closest('.resize-handle')) return;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;
      const x = Math.max(-10, Math.min(100, ((cx - rect.left) / rect.width) * 100));
      const y = Math.max(-10, Math.min(100, ((cy - rect.top) / rect.height) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y } : p));
    };
    const end = () => { window.removeEventListener('mousemove', move); window.removeEventListener('touchmove', move); };
    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, e: any) => {
    e.stopPropagation();
    const rect = docWrapperRef.current?.getBoundingClientRect();
    if (!rect) return;
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;
    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(10, Math.min(90, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };
    const end = () => { window.removeEventListener('mousemove', move); window.removeEventListener('touchmove', move); };
    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleDownload = async () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = 1240; canvas.height = 1754;
    ctx.fillStyle = '#fff'; ctx.fillRect(0,0,1240,1754);

    const fileToUse = uploadFile || activeDoc?.fileData;
    if (activeDoc?.type === 'RECEIPT') {
       const r = JSON.parse(fileToUse || '{}');
       ctx.fillStyle = '#000'; ctx.font = 'bold 60px Inter'; ctx.fillText("RENT RECEIPT", 400, 150);
       ctx.font = '30px Inter';
       ctx.fillText(`Date: ${new Date().toLocaleDateString('en-IN')}`, 100, 250);
       ctx.fillText(`Received with thanks from Mr./Ms. ${r.tenantName}`, 100, 320);
       ctx.fillText(`a sum of ₹${r.rentAmount} for the month of ${r.month}`, 100, 370);
       ctx.fillText(`towards rent of property at: ${r.address}`, 100, 420);
       ctx.fillText(`Landlord: ${r.landlordName}`, 100, 520);
       if (r.panNumber) ctx.fillText(`Landlord PAN: ${r.panNumber}`, 100, 570);
       ctx.strokeStyle = '#eee'; ctx.strokeRect(100, 650, 1040, 400);
    } else if (fileToUse?.startsWith('data:image')) {
      const img = new Image(); img.src = fileToUse;
      await new Promise(r => img.onload = r);
      canvas.height = canvas.width * (img.height/img.width);
      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    }

    for (const s of placedSignatures) {
      const si = new Image(); si.src = s.dataUrl;
      await new Promise(r => si.onload = r);
      const sw = (canvas.width * (s.w || 25)) / 100;
      ctx.drawImage(si, (canvas.width * s.x)/100, (canvas.height * s.y)/100, sw, sw * (si.height/si.width));
    }
    const pdf = new jspdf.jsPDF({ format: [canvas.width, canvas.height], unit: 'px' });
    pdf.addImage(canvas.toDataURL('image/jpeg', 0.85), 'JPEG', 0, 0, canvas.width, canvas.height);
    pdf.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
  };

  const handleShare = (platform: 'whatsapp' | 'email') => {
    const text = encodeURIComponent(`Hi, I have signed the document: ${activeDoc?.name}. Please find it on SignEase.`);
    if (platform === 'whatsapp') window.open(`https://wa.me/?text=${text}`, '_blank');
    else window.location.href = `mailto:?subject=Signed Document&body=${text}`;
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-100 transition-transform active:scale-95">S</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignEase</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest">Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowSignaturePad(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/90 z-[70] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-14 h-14 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-800 tracking-tight">Processing...</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Success!</h2>
            <p className="text-gray-500 font-medium mb-10">Document signed and secured.</p>
            <div className="space-y-3">
              <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                 <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">WhatsApp</button>
                 <button onClick={() => handleShare('email')} className="flex-1 bg-slate-800 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">Email</button>
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Home</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <>
                <Dashboard documents={documents} onAction={(v) => { resetSigningState(); v === AppView.RENT_RECEIPT ? setShowReceiptCreator(true) : setCurrentView(AppView.SIGN_DOC); }} onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} onDeleteDoc={handleDeleteDoc} />
                <div className="mt-8 bg-indigo-50 p-6 rounded-[2rem] border border-indigo-100 flex items-center justify-between">
                  <div>
                    <h4 className="font-black text-indigo-900">Need a Rent Receipt?</h4>
                    <p className="text-xs font-medium text-indigo-600">HRA compliant & ready for signature.</p>
                  </div>
                  <button onClick={() => setShowReceiptCreator(true)} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-black text-xs active:scale-95 transition-all">Create Now</button>
                </div>
              </>
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'View Document' : 'Place Signature'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                   <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload File</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">Select a document to sign</p>
                    <label className="bg-indigo-600 text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-indigo-700 shadow-2xl shadow-indigo-100 inline-block transition-transform active:scale-95">
                      Choose File
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-6">
                    <div className="bg-slate-100/80 rounded-[2.5rem] p-4 flex items-center justify-center overflow-auto min-h-[60vh] scrollbar-hide border border-slate-200/50">
                      <div ref={docWrapperRef} className="relative shadow-2xl bg-white leading-[0] transition-all origin-center">
                        {activeDoc?.type === 'RECEIPT' ? (
                          <div className="w-[800px] h-[1130px] p-16 relative bg-white border border-slate-200">
                             <h1 className="text-5xl font-black text-center mb-16 tracking-tight">RENT RECEIPT</h1>
                             <div className="space-y-12 text-xl font-medium leading-relaxed text-slate-700">
                               <p className="border-b-2 border-slate-100 pb-4">Date: <span className="font-bold text-black">{new Date().toLocaleDateString('en-IN')}</span></p>
                               <p className="border-b-2 border-slate-100 pb-4">Received with thanks from Mr./Ms. <span className="font-black text-black">{(JSON.parse(activeDoc.fileData || '{}')).tenantName}</span></p>
                               <p className="border-b-2 border-slate-100 pb-4">a sum of <span className="font-black text-black">₹{(JSON.parse(activeDoc.fileData || '{}')).rentAmount}</span> for the month of <span className="font-black text-black">{(JSON.parse(activeDoc.fileData || '{}')).month}</span></p>
                               <p className="border-b-2 border-slate-100 pb-4">towards rent of property at: <span className="font-black text-black">{(JSON.parse(activeDoc.fileData || '{}')).address}</span></p>
                               <div className="pt-24 mt-24 border-t-2 border-slate-50">
                                  <p className="text-sm font-black uppercase tracking-widest text-slate-400">Landlord Details</p>
                                  <p className="text-2xl font-black text-black mt-2">{(JSON.parse(activeDoc.fileData || '{}')).landlordName}</p>
                                  {(JSON.parse(activeDoc.fileData || '{}')).panNumber && <p className="text-sm font-bold text-indigo-600 mt-1 uppercase">PAN: {(JSON.parse(activeDoc.fileData || '{}')).panNumber}</p>}
                               </div>
                             </div>
                          </div>
                        ) : (uploadFile || activeDoc?.fileData)?.startsWith('data:application/pdf') ? (
                          <canvas ref={pdfCanvasRef} className="max-w-full h-auto" />
                        ) : (
                          <img src={uploadFile || activeDoc?.fileData} className="max-w-full max-h-[85vh] object-contain" alt="Preview" />
                        )}

                        {placedSignatures.map(ps => (
                          <div key={ps.id} style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} className="absolute z-20 cursor-move touch-none animate-pulse-once" onMouseDown={(e) => handleDrag(ps.id, e)} onTouchStart={(e) => handleDrag(ps.id, e)}>
                            <div className="relative group">
                              <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-500/50'} p-0.5`} />
                              {activeDoc?.status !== 'SIGNED' && (
                                <>
                                  <button onClick={(e) => { e.stopPropagation(); setPlacedSignatures(p => p.filter(x => x.id !== ps.id)); }} className="absolute -top-4 -right-4 bg-red-500 text-white w-8 h-8 rounded-full text-xs flex items-center justify-center shadow-lg font-bold border-2 border-white z-30">✕</button>
                                  <div onMouseDown={(e) => handleResize(ps.id, e)} onTouchStart={(e) => handleResize(ps.id, e)} className="resize-handle absolute -bottom-4 -right-4 w-9 h-9 bg-indigo-600 border-4 border-white rounded-full cursor-nwse-resize shadow-xl flex items-center justify-center z-30">
                                    <div className="w-2.5 h-2.5 border-r-2 border-b-2 border-white rotate-45 mb-1 mr-1"></div>
                                  </div>
                                </>
                              )}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>

                    <div className="bg-white rounded-[2.5rem] p-6 shadow-xl border border-slate-100 sticky bottom-2">
                       {activeDoc?.status === 'SIGNED' ? (
                         <div className="flex gap-3">
                           <button onClick={handleDownload} className="flex-[2] bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download</button>
                           <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all text-[10px] uppercase tracking-widest">Share</button>
                         </div>
                       ) : (
                         <div className="space-y-6">
                            <div className="flex justify-between items-center px-1">
                              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Select Signature</p>
                            </div>
                            <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-28 h-16 bg-white border-2 border-slate-100 rounded-2xl flex items-center justify-center p-2 shadow-sm hover:border-indigo-300 transition-all active:scale-90 overflow-hidden">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply object-contain" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-16 h-16 bg-slate-50 text-slate-400 rounded-2xl border-2 border-dashed border-slate-200 text-2xl font-bold flex items-center justify-center active:bg-indigo-50 transition-colors">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 disabled:opacity-30 transition-all active:scale-95">Complete Signing</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}
      {showReceiptCreator && <RentReceiptCreator onGenerate={handleReceiptGenerate} onCancel={() => setShowReceiptCreator(false)} />}

      <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t flex justify-around py-4 md:hidden z-40">
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className={`flex flex-col items-center gap-1 transition-colors ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-slate-400'}`}>
          <span className="text-2xl">🏠</span>
          <span className="text-[9px] font-black uppercase tracking-tighter">Home</span>
        </button>
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.SIGN_DOC); }} className={`flex flex-col items-center gap-1 transition-colors ${currentView === AppView.SIGN_DOC ? 'text-indigo-600' : 'text-slate-400'}`}>
          <span className="text-2xl">✍️</span>
          <span className="text-[9px] font-black uppercase tracking-tighter">Sign</span>
        </button>
        <button onClick={() => setShowReceiptCreator(true)} className="flex flex-col items-center gap-1 text-slate-400">
          <span className="text-2xl">🧾</span>
          <span className="text-[9px] font-black uppercase tracking-tighter">Receipt</span>
        </button>
      </nav>

      <style>{`
        @keyframes pulse-once {
          0% { transform: scale(0.9); opacity: 0; }
          50% { transform: scale(1.05); opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
        .animate-pulse-once {
          animation: pulse-once 0.4s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

import { DocumentRecord, UserSignature } from './types';

const DB_NAME = 'SignEaseDB';
const DB_VERSION = 1;
const STORES = {
  DOCUMENTS: 'documents',
  SIGNATURES: 'signatures'
};

export const initDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORES.DOCUMENTS)) {
        db.createObjectStore(STORES.DOCUMENTS, { keyPath: 'id' });
      }
      if (!db.objectStoreNames.contains(STORES.SIGNATURES)) {
        db.createObjectStore(STORES.SIGNATURES, { keyPath: 'id' });
      }
    };

    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

export const getAllDocs = async (): Promise<DocumentRecord[]> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORES.DOCUMENTS, 'readonly');
    const store = transaction.objectStore(STORES.DOCUMENTS);
    const request = store.getAll();
    request.onsuccess = () => resolve(request.result.sort((a, b) => b.id.localeCompare(a.id)));
    request.onerror = () => reject(request.error);
  });
};

export const saveDoc = async (doc: DocumentRecord): Promise<void> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORES.DOCUMENTS, 'readwrite');
    const store = transaction.objectStore(STORES.DOCUMENTS);
    const request = store.put(doc);
    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

export const deleteDoc = async (id: string): Promise<void> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORES.DOCUMENTS, 'readwrite');
    const store = transaction.objectStore(STORES.DOCUMENTS);
    const request = store.delete(id);
    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

export const getAllSigs = async (): Promise<UserSignature[]> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORES.SIGNATURES, 'readonly');
    const store = transaction.objectStore(STORES.SIGNATURES);
    const request = store.getAll();
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
};

export const saveSig = async (sig: UserSignature): Promise<void> => {
  const db = await initDB();
  return new Promise((resolve, reject) => {
    const transaction = db.transaction(STORES.SIGNATURES, 'readwrite');
    const store = transaction.objectStore(STORES.SIGNATURES);
    const request = store.put(sig);
    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
};

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';
import RentReceiptCreator from './components/RentReceiptCreator';
import * as db from './db';

declare const jspdf: any;
declare const pdfjsLib: any;

if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [showReceiptCreator, setShowReceiptCreator] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const docWrapperRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);

  // Load initial data from IndexedDB
  useEffect(() => {
    const loadInitialData = async () => {
      try {
        const [docs, sigs] = await Promise.all([db.getAllDocs(), db.getAllSigs()]);
        setDocuments(docs);
        setSignatures(sigs);
      } catch (err) {
        console.error("Failed to load data from IndexedDB:", err);
      }
    };
    loadInitialData();
  }, []);

  const handleDeleteDoc = useCallback(async (id: string) => {
    try {
      await db.deleteDoc(id);
      setDocuments(prev => prev.filter(doc => doc.id !== id));
    } catch (err) {
      console.error("Failed to delete document:", err);
      alert("Error deleting document. Please try again.");
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
    setShowReceiptCreator(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleReceiptGenerate = (data: any) => {
    setIsLoading(true);
    setShowReceiptCreator(false);
    setTimeout(() => {
      const receiptId = `REC-${Date.now()}`;
      setActiveDoc({
        id: receiptId,
        name: `Rent_${data.month.replace(' ', '_')}.pdf`,
        type: 'RECEIPT',
        status: 'PENDING',
        date: new Date().toLocaleDateString('en-IN'),
        fileData: JSON.stringify(data)
      });
      setCurrentView(AppView.SIGN_DOC);
      setIsLoading(false);
    }, 800);
  };

  useEffect(() => {
    const renderPDF = async (dataUrl: string) => {
      if (!pdfCanvasRef.current) return;
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        const page = await pdf.getPage(1); 
        const viewport = page.getViewport({ scale: 2 });
        const canvas = pdfCanvasRef.current;
        const context = canvas.getContext('2d');
        if (!context) return;
        canvas.height = viewport.height;
        canvas.width = viewport.width;
        await page.render({ canvasContext: context, viewport }).promise;
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data && data.startsWith('data:application/pdf')) {
      renderPDF(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = async (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    try {
      await db.saveSig(newSign);
      setSignatures(prev => [newSign, ...prev]);
      setShowSignaturePad(false);
    } catch (err) {
      console.error("Failed to save signature:", err);
      alert("Storage error while saving signature.");
    }
  };

  const handleSignFinish = async () => {
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) return;
    setIsLoading(true);

    const isPdf = fileToUse.startsWith('data:application/pdf');
    const isReceipt = activeDoc?.type === 'RECEIPT';

    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || (isPdf ? 'Signed_Doc.pdf' : 'Signed_Image.png'),
      type: isReceipt ? 'RECEIPT' : (isPdf ? 'PDF' : 'IMAGE'),
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: fileToUse,
      placedSignatures: [...placedSignatures]
    };

    try {
      await db.saveDoc(newDoc);
      const updatedDocs = await db.getAllDocs();
      setDocuments(updatedDocs);
      setIsLoading(false);
      setShowSuccessScreen(true);
    } catch (err) {
      setIsLoading(false);
      console.error("Failed to save signed document:", err);
      alert("Error: Your document is too large or device storage is full. Try a smaller file.");
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 40, y: 50, w: 25 
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    const rect = docWrapperRef.current?.getBoundingClientRect();
    if (!rect) return;
    if (e.target.closest('.resize-handle')) return;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;
      const x = Math.max(-10, Math.min(100, ((cx - rect.left) / rect.width) * 100));
      const y = Math.max(-10, Math.min(100, ((cy - rect.top) / rect.height) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y } : p));
    };
    const end = () => { window.removeEventListener('mousemove', move); window.removeEventListener('touchmove', move); };
    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, e: any) => {
    e.stopPropagation();
    const rect = docWrapperRef.current?.getBoundingClientRect();
    if (!rect) return;
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;
    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(10, Math.min(90, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };
    const end = () => { window.removeEventListener('mousemove', move); window.removeEventListener('touchmove', move); };
    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleDownload = async () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = 1240; canvas.height = 1754;
    ctx.fillStyle = '#fff'; ctx.fillRect(0,0,1240,1754);

    const fileToUse = uploadFile || activeDoc?.fileData;
    if (activeDoc?.type === 'RECEIPT') {
       const r = JSON.parse(fileToUse || '{}');
       ctx.fillStyle = '#000'; ctx.font = 'bold 60px Inter'; ctx.fillText("RENT RECEIPT", 400, 150);
       ctx.font = '30px Inter';
       ctx.fillText(`Date: ${new Date().toLocaleDateString('en-IN')}`, 100, 250);
       ctx.fillText(`Received with thanks from Mr./Ms. ${r.tenantName}`, 100, 320);
       ctx.fillText(`a sum of ₹${r.rentAmount} for the month of ${r.month}`, 100, 370);
       ctx.fillText(`towards rent of property at: ${r.address}`, 100, 420);
       ctx.fillText(`Landlord: ${r.landlordName}`, 100, 520);
       if (r.panNumber) ctx.fillText(`Landlord PAN: ${r.panNumber}`, 100, 570);
       ctx.strokeStyle = '#eee'; ctx.strokeRect(100, 650, 1040, 400);
    } else if (fileToUse?.startsWith('data:image')) {
      const img = new Image(); img.src = fileToUse;
      await new Promise(r => img.onload = r);
      canvas.height = canvas.width * (img.height/img.width);
      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    }

    for (const s of placedSignatures) {
      const si = new Image(); si.src = s.dataUrl;
      await new Promise(r => si.onload = r);
      const sw = (canvas.width * (s.w || 25)) / 100;
      ctx.drawImage(si, (canvas.width * s.x)/100, (canvas.height * s.y)/100, sw, sw * (si.height/si.width));
    }
    const pdf = new jspdf.jsPDF({ format: [canvas.width, canvas.height], unit: 'px' });
    pdf.addImage(canvas.toDataURL('image/jpeg', 0.85), 'JPEG', 0, 0, canvas.width, canvas.height);
    pdf.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
  };

  const handleShare = (platform: 'whatsapp' | 'email') => {
    const text = encodeURIComponent(`Hi, I have signed the document: ${activeDoc?.name}. Please find it on SignEase.`);
    if (platform === 'whatsapp') window.open(`https://wa.me/?text=${text}`, '_blank');
    else window.location.href = `mailto:?subject=Signed Document&body=${text}`;
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-100 transition-transform active:scale-95">S</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignEase</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest">Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowSignaturePad(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/90 z-[70] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-14 h-14 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-800 tracking-tight">Processing & Saving...</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Success!</h2>
            <p className="text-gray-500 font-medium mb-10">Document signed and secured.</p>
            <div className="space-y-3">
              <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                 <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">WhatsApp</button>
                 <button onClick={() => handleShare('email')} className="flex-1 bg-slate-800 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">Email</button>
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Home</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <>
                <Dashboard documents={documents} onAction={(v) => { resetSigningState(); v === AppView.RENT_RECEIPT ? setShowReceiptCreator(true) : setCurrentView(AppView.SIGN_DOC); }} onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} onDeleteDoc={handleDeleteDoc} />
                <div className="mt-8 bg-indigo-50 p-6 rounded-[2rem] border border-indigo-100 flex items-center justify-between">
                  <div>
                    <h4 className="font-black text-indigo-900">Need a Rent Receipt?</h4>
                    <p className="text-xs font-medium text-indigo-600">HRA compliant & ready for signature.</p>
                  </div>
                  <button onClick={() => setShowReceiptCreator(true)} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-black text-xs active:scale-95 transition-all">Create Now</button>
                </div>
              </>
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'View Document' : 'Place Signature'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                   <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload File</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">Select a document to sign</p>
                    <label className="bg-indigo-600 text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-indigo-700 shadow-2xl shadow-indigo-100 inline-block transition-transform active:scale-95">
                      Choose File
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-6">
                    <div className="bg-slate-100/80 rounded-[2.5rem] p-4 flex items-center justify-center overflow-auto min-h-[60vh] scrollbar-hide border border-slate-200/50">
                      <div ref={docWrapperRef} className="relative shadow-2xl bg-white leading-[0] transition-all origin-center">
                        {activeDoc?.type === 'RECEIPT' ? (
                          <div className="w-[800px] h-[1130px] p-16 relative bg-white border border-slate-200">
                             <h1 className="text-5xl font-black text-center mb-16 tracking-tight">RENT RECEIPT</h1>
                             <div className="space-y-12 text-xl font-medium leading-relaxed text-slate-700">
                               <p className="border-b-2 border-slate-100 pb-4">Date: <span className="font-bold text-black">{new Date().toLocaleDateString('en-IN')}</span></p>
                               <p className="border-b-2 border-slate-100 pb-4">Received with thanks from Mr./Ms. <span className="font-black text-black">{(JSON.parse(activeDoc.fileData || '{}')).tenantName}</span></p>
                               <p className="border-b-2 border-slate-100 pb-4">a sum of <span className="font-black text-black">₹{(JSON.parse(activeDoc.fileData || '{}')).rentAmount}</span> for the month of <span className="font-black text-black">{(JSON.parse(activeDoc.fileData || '{}')).month}</span></p>
                               <p className="border-b-2 border-slate-100 pb-4">towards rent of property at: <span className="font-black text-black">{(JSON.parse(activeDoc.fileData || '{}')).address}</span></p>
                               <div className="pt-24 mt-24 border-t-2 border-slate-50">
                                  <p className="text-sm font-black uppercase tracking-widest text-slate-400">Landlord Details</p>
                                  <p className="text-2xl font-black text-black mt-2">{(JSON.parse(activeDoc.fileData || '{}')).landlordName}</p>
                                  {(JSON.parse(activeDoc.fileData || '{}')).panNumber && <p className="text-sm font-bold text-indigo-600 mt-1 uppercase">PAN: {(JSON.parse(activeDoc.fileData || '{}')).panNumber}</p>}
                               </div>
                             </div>
                          </div>
                        ) : (uploadFile || activeDoc?.fileData)?.startsWith('data:application/pdf') ? (
                          <canvas ref={pdfCanvasRef} className="max-w-full h-auto" />
                        ) : (
                          <img src={uploadFile || activeDoc?.fileData} className="max-w-full max-h-[85vh] object-contain" alt="Preview" />
                        )}

                        {placedSignatures.map(ps => (
                          <div key={ps.id} style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} className="absolute z-20 cursor-move touch-none animate-pulse-once" onMouseDown={(e) => handleDrag(ps.id, e)} onTouchStart={(e) => handleDrag(ps.id, e)}>
                            <div className="relative group">
                              <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-500/50'} p-0.5`} />
                              {activeDoc?.status !== 'SIGNED' && (
                                <>
                                  <button onClick={(e) => { e.stopPropagation(); setPlacedSignatures(p => p.filter(x => x.id !== ps.id)); }} className="absolute -top-4 -right-4 bg-red-500 text-white w-8 h-8 rounded-full text-xs flex items-center justify-center shadow-lg font-bold border-2 border-white z-30">✕</button>
                                  <div onMouseDown={(e) => handleResize(ps.id, e)} onTouchStart={(e) => handleResize(ps.id, e)} className="resize-handle absolute -bottom-4 -right-4 w-9 h-9 bg-indigo-600 border-4 border-white rounded-full cursor-nwse-resize shadow-xl flex items-center justify-center z-30">
                                    <div className="w-2.5 h-2.5 border-r-2 border-b-2 border-white rotate-45 mb-1 mr-1"></div>
                                  </div>
                                </>
                              )}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>

                    <div className="bg-white rounded-[2.5rem] p-6 shadow-xl border border-slate-100 sticky bottom-2">
                       {activeDoc?.status === 'SIGNED' ? (
                         <div className="flex gap-3">
                           <button onClick={handleDownload} className="flex-[2] bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download</button>
                           <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all text-[10px] uppercase tracking-widest">Share</button>
                         </div>
                       ) : (
                         <div className="space-y-6">
                            <div className="flex justify-between items-center px-1">
                              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Select Signature</p>
                            </div>
                            <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-28 h-16 bg-white border-2 border-slate-100 rounded-2xl flex items-center justify-center p-2 shadow-sm hover:border-indigo-300 transition-all active:scale-90 overflow-hidden">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply object-contain" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-16 h-16 bg-slate-50 text-slate-400 rounded-2xl border-2 border-dashed border-slate-200 text-2xl font-bold flex items-center justify-center active:bg-indigo-50 transition-colors">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 disabled:opacity-30 transition-all active:scale-95">Complete Signing</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}
      {showReceiptCreator && <RentReceiptCreator onGenerate={handleReceiptGenerate} onCancel={() => setShowReceiptCreator(false)} />}

      <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t flex justify-around py-4 md:hidden z-40">
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className={`flex flex-col items-center gap-1 transition-colors ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-slate-400'}`}>
          <span className="text-2xl">🏠</span>
          <span className="text-[9px] font-black uppercase tracking-tighter">Home</span>
        </button>
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.SIGN_DOC); }} className={`flex flex-col items-center gap-1 transition-colors ${currentView === AppView.SIGN_DOC ? 'text-indigo-600' : 'text-slate-400'}`}>
          <span className="text-2xl">✍️</span>
          <span className="text-[9px] font-black uppercase tracking-tighter">Sign</span>
        </button>
        <button onClick={() => setShowReceiptCreator(true)} className="flex flex-col items-center gap-1 text-slate-400">
          <span className="text-2xl">🧾</span>
          <span className="text-[9px] font-black uppercase tracking-tighter">Receipt</span>
        </button>
      </nav>

      <style>{`
        @keyframes pulse-once {
          0% { transform: scale(0.9); opacity: 0; }
          50% { transform: scale(1.05); opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
        .animate-pulse-once {
          animation: pulse-once 0.4s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

export enum AppView {
  DASHBOARD = 'DASHBOARD',
  SIGN_DOC = 'SIGN_DOC',
  VIEW_DOC = 'VIEW_DOC'
}

export interface PlacedSignature {
  id: string;
  dataUrl: string;
  x: number; // percentage 0-100
  y: number; // percentage 0-100
  w?: number; // width percentage 5-100
}

export interface UserSignature {
  id: string;
  dataUrl: string;
  label: string;
  createdAt: string;
}

export interface DocumentRecord {
  id: string;
  name: string;
  type: 'PDF' | 'IMAGE';
  status: 'SIGNED' | 'PENDING';
  date: string;
  fileData?: string; // base64 data
  placedSignatures?: PlacedSignature[];
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';
import * as db from './db';

declare const jspdf: any;
declare const pdfjsLib: any;

if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const docWrapperRef = useRef<HTMLDivElement>(null);
  const pdfCanvasRef = useRef<HTMLCanvasElement>(null);

  // Load initial data from IndexedDB
  useEffect(() => {
    const loadInitialData = async () => {
      try {
        const [docs, sigs] = await Promise.all([db.getAllDocs(), db.getAllSigs()]);
        setDocuments(docs);
        setSignatures(sigs);
      } catch (err) {
        console.error("Failed to load data from IndexedDB:", err);
      }
    };
    loadInitialData();
  }, []);

  const handleDeleteDoc = useCallback(async (id: string) => {
    try {
      await db.deleteDoc(id);
      setDocuments(prev => prev.filter(doc => doc.id !== id));
    } catch (err) {
      console.error("Failed to delete document:", err);
      alert("Error deleting document. Please try again.");
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  useEffect(() => {
    const renderPDF = async (dataUrl: string) => {
      if (!pdfCanvasRef.current) return;
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        const page = await pdf.getPage(1); 
        const viewport = page.getViewport({ scale: 2 });
        const canvas = pdfCanvasRef.current;
        const context = canvas.getContext('2d');
        if (!context) return;
        canvas.height = viewport.height;
        canvas.width = viewport.width;
        await page.render({ canvasContext: context, viewport }).promise;
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data && data.startsWith('data:application/pdf')) {
      renderPDF(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = async (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    try {
      await db.saveSig(newSign);
      setSignatures(prev => [newSign, ...prev]);
      setShowSignaturePad(false);
    } catch (err) {
      console.error("Failed to save signature:", err);
      alert("Storage error while saving signature.");
    }
  };

  const handleSignFinish = async () => {
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) return;
    setIsLoading(true);

    const isPdf = fileToUse.startsWith('data:application/pdf');

    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || (isPdf ? 'Signed_Doc.pdf' : 'Signed_Image.png'),
      type: isPdf ? 'PDF' : 'IMAGE',
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: fileToUse,
      placedSignatures: [...placedSignatures]
    };

    try {
      await db.saveDoc(newDoc);
      const updatedDocs = await db.getAllDocs();
      setDocuments(updatedDocs);
      setIsLoading(false);
      setShowSuccessScreen(true);
    } catch (err) {
      setIsLoading(false);
      console.error("Failed to save signed document:", err);
      alert("Error: Your document is too large or device storage is full. Try a smaller file.");
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 40, y: 50, w: 25 
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    const rect = docWrapperRef.current?.getBoundingClientRect();
    if (!rect) return;
    if (e.target.closest('.resize-handle')) return;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;
      const x = Math.max(-10, Math.min(100, ((cx - rect.left) / rect.width) * 100));
      const y = Math.max(-10, Math.min(100, ((cy - rect.top) / rect.height) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y } : p));
    };
    const end = () => { window.removeEventListener('mousemove', move); window.removeEventListener('touchmove', move); };
    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, e: any) => {
    e.stopPropagation();
    const rect = docWrapperRef.current?.getBoundingClientRect();
    if (!rect) return;
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;
    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(10, Math.min(90, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };
    const end = () => { window.removeEventListener('mousemove', move); window.removeEventListener('touchmove', move); };
    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleDownload = async () => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = 1240; canvas.height = 1754;
    ctx.fillStyle = '#fff'; ctx.fillRect(0,0,1240,1754);

    const fileToUse = uploadFile || activeDoc?.fileData;
    if (fileToUse?.startsWith('data:image')) {
      const img = new Image(); img.src = fileToUse;
      await new Promise(r => img.onload = r);
      canvas.height = canvas.width * (img.height/img.width);
      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
    } else if (fileToUse?.startsWith('data:application/pdf')) {
       // PDF rendering fallback for downloaded canvas
       ctx.fillStyle = '#000'; ctx.font = '20px Inter';
       ctx.fillText("Signed PDF Export", 100, 100);
    }

    for (const s of placedSignatures) {
      const si = new Image(); si.src = s.dataUrl;
      await new Promise(r => si.onload = r);
      const sw = (canvas.width * (s.w || 25)) / 100;
      ctx.drawImage(si, (canvas.width * s.x)/100, (canvas.height * s.y)/100, sw, sw * (si.height/si.width));
    }
    const pdf = new jspdf.jsPDF({ format: [canvas.width, canvas.height], unit: 'px' });
    pdf.addImage(canvas.toDataURL('image/jpeg', 0.85), 'JPEG', 0, 0, canvas.width, canvas.height);
    pdf.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
  };

  const handleShare = (platform: 'whatsapp' | 'email') => {
    const text = encodeURIComponent(`Hi, I have signed the document: ${activeDoc?.name}. Please find it on SignEase.`);
    if (platform === 'whatsapp') window.open(`https://wa.me/?text=${text}`, '_blank');
    else window.location.href = `mailto:?subject=Signed Document&body=${text}`;
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-100 transition-transform active:scale-95">S</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignEase</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest">Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowSignaturePad(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/90 z-[70] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-14 h-14 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-800 tracking-tight">Processing & Saving...</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Success!</h2>
            <p className="text-gray-500 font-medium mb-10">Document signed and secured.</p>
            <div className="space-y-3">
              <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                 <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">WhatsApp</button>
                 <button onClick={() => handleShare('email')} className="flex-1 bg-slate-800 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">Email</button>
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Home</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard documents={documents} onAction={() => { resetSigningState(); setCurrentView(AppView.SIGN_DOC); }} onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} onDeleteDoc={handleDeleteDoc} />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'View Document' : 'Place Signature'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                   <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload File</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">Select a document to sign</p>
                    <label className="bg-indigo-600 text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-indigo-700 shadow-2xl shadow-indigo-100 inline-block transition-transform active:scale-95">
                      Choose File
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-6">
                    <div className="bg-slate-100/80 rounded-[2.5rem] p-4 flex items-center justify-center overflow-auto min-h-[60vh] scrollbar-hide border border-slate-200/50">
                      <div ref={docWrapperRef} className="relative shadow-2xl bg-white leading-[0] transition-all origin-center">
                        {(uploadFile || activeDoc?.fileData)?.startsWith('data:application/pdf') ? (
                          <canvas ref={pdfCanvasRef} className="max-w-full h-auto" />
                        ) : (
                          <img src={uploadFile || activeDoc?.fileData} className="max-w-full max-h-[85vh] object-contain" alt="Preview" />
                        )}

                        {placedSignatures.map(ps => (
                          <div key={ps.id} style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} className="absolute z-20 cursor-move touch-none animate-pulse-once" onMouseDown={(e) => handleDrag(ps.id, e)} onTouchStart={(e) => handleDrag(ps.id, e)}>
                            <div className="relative group">
                              <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-500/50'} p-0.5`} />
                              {activeDoc?.status !== 'SIGNED' && (
                                <>
                                  <button onClick={(e) => { e.stopPropagation(); setPlacedSignatures(p => p.filter(x => x.id !== ps.id)); }} className="absolute -top-4 -right-4 bg-red-500 text-white w-8 h-8 rounded-full text-xs flex items-center justify-center shadow-lg font-bold border-2 border-white z-30">✕</button>
                                  <div onMouseDown={(e) => handleResize(ps.id, e)} onTouchStart={(e) => handleResize(ps.id, e)} className="resize-handle absolute -bottom-4 -right-4 w-9 h-9 bg-indigo-600 border-4 border-white rounded-full cursor-nwse-resize shadow-xl flex items-center justify-center z-30">
                                    <div className="w-2.5 h-2.5 border-r-2 border-b-2 border-white rotate-45 mb-1 mr-1"></div>
                                  </div>
                                </>
                              )}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>

                    <div className="bg-white rounded-[2.5rem] p-6 shadow-xl border border-slate-100 sticky bottom-2">
                       {activeDoc?.status === 'SIGNED' ? (
                         <div className="flex gap-3">
                           <button onClick={handleDownload} className="flex-[2] bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download</button>
                           <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all text-[10px] uppercase tracking-widest">Share</button>
                         </div>
                       ) : (
                         <div className="space-y-6">
                            <div className="flex justify-between items-center px-1">
                              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Select Signature</p>
                            </div>
                            <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-28 h-16 bg-white border-2 border-slate-100 rounded-2xl flex items-center justify-center p-2 shadow-sm hover:border-indigo-300 transition-all active:scale-90 overflow-hidden">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply object-contain" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-16 h-16 bg-slate-50 text-slate-400 rounded-2xl border-2 border-dashed border-slate-200 text-2xl font-bold flex items-center justify-center active:bg-indigo-50 transition-colors">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 disabled:opacity-30 transition-all active:scale-95">Complete Signing</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}

      <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t flex justify-around py-4 md:hidden z-40">
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className={`flex flex-col items-center gap-1 transition-colors ${currentView === AppView.DASHBOARD ? 'text-indigo-600' : 'text-slate-400'}`}>
          <span className="text-2xl">🏠</span>
          <span className="text-[9px] font-black uppercase tracking-tighter">Home</span>
        </button>
        <button onClick={() => { resetSigningState(); setCurrentView(AppView.SIGN_DOC); }} className={`flex flex-col items-center gap-1 transition-colors ${currentView === AppView.SIGN_DOC ? 'text-indigo-600' : 'text-slate-400'}`}>
          <span className="text-2xl">✍️</span>
          <span className="text-[9px] font-black uppercase tracking-tighter">Sign</span>
        </button>
      </nav>

      <style>{`
        @keyframes pulse-once {
          0% { transform: scale(0.9); opacity: 0; }
          50% { transform: scale(1.05); opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
        .animate-pulse-once {
          animation: pulse-once 0.4s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

export enum AppView {
  DASHBOARD = 'DASHBOARD',
  SIGN_DOC = 'SIGN_DOC',
  VIEW_DOC = 'VIEW_DOC'
}

export interface PlacedSignature {
  id: string;
  dataUrl: string;
  x: number; // percentage 0-100
  y: number; // percentage 0-100
  w?: number; // width percentage 5-100
  pageNumber: number; // The 1-based page index
}

export interface UserSignature {
  id: string;
  dataUrl: string;
  label: string;
  createdAt: string;
}

export interface DocumentRecord {
  id: string;
  name: string;
  type: 'PDF' | 'IMAGE';
  status: 'SIGNED' | 'PENDING';
  date: string;
  fileData?: string; // base64 data
  placedSignatures?: PlacedSignature[];
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';
import * as db from './db';

declare const jspdf: any;
declare const pdfjsLib: any;

if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [numPages, setNumPages] = useState(1);

  const docWrapperRef = useRef<HTMLDivElement>(null);
  const pageRefs = useRef<(HTMLCanvasElement | null)[]>([]);

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        const [docs, sigs] = await Promise.all([db.getAllDocs(), db.getAllSigs()]);
        setDocuments(docs);
        setSignatures(sigs);
      } catch (err) {
        console.error("Failed to load data from IndexedDB:", err);
      }
    };
    loadInitialData();
  }, []);

  const handleDeleteDoc = useCallback(async (id: string) => {
    try {
      await db.deleteDoc(id);
      setDocuments(prev => prev.filter(doc => doc.id !== id));
    } catch (err) {
      console.error("Failed to delete document:", err);
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
    setNumPages(1);
    pageRefs.current = [];
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  useEffect(() => {
    const renderAllPages = async (dataUrl: string) => {
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        setNumPages(pdf.numPages);

        // Brief delay to ensure DOM elements for all pages are created by React
        setTimeout(async () => {
          for (let i = 1; i <= pdf.numPages; i++) {
            const canvas = pageRefs.current[i];
            if (!canvas) continue;
            const page = await pdf.getPage(i);
            const viewport = page.getViewport({ scale: 2 });
            const context = canvas.getContext('2d');
            if (!context) continue;
            canvas.height = viewport.height;
            canvas.width = viewport.width;
            await page.render({ canvasContext: context, viewport }).promise;
          }
        }, 100);
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data && data.startsWith('data:application/pdf')) {
      renderAllPages(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = async (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    try {
      await db.saveSig(newSign);
      setSignatures(prev => [newSign, ...prev]);
      setShowSignaturePad(false);
    } catch (err) {
      console.error("Failed to save signature:", err);
    }
  };

  const handleSignFinish = async () => {
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) return;
    setIsLoading(true);

    const isPdf = fileToUse.startsWith('data:application/pdf');
    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || (isPdf ? 'Signed_Doc.pdf' : 'Signed_Image.png'),
      type: isPdf ? 'PDF' : 'IMAGE',
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: fileToUse,
      placedSignatures: [...placedSignatures]
    };

    try {
      await db.saveDoc(newDoc);
      const updatedDocs = await db.getAllDocs();
      setDocuments(updatedDocs);
      setIsLoading(false);
      setShowSuccessScreen(true);
    } catch (err) {
      setIsLoading(false);
      console.error("Failed to save signed document:", err);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 30, y: 30, w: 25,
      pageNumber: 1 // Default to first page, user can drag to others
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, pageNum: number, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    const canvas = pageRefs.current[pageNum];
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    if (e.target.closest('.resize-handle')) return;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;
      const x = Math.max(-5, Math.min(95, ((cx - rect.left) / rect.width) * 100));
      const y = Math.max(-5, Math.min(95, ((cy - rect.top) / rect.height) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y, pageNumber: pageNum } : p));
    };
    const end = () => { window.removeEventListener('mousemove', move); window.removeEventListener('touchmove', move); };
    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, pageNum: number, e: any) => {
    e.stopPropagation();
    const canvas = pageRefs.current[pageNum];
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;
    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(10, Math.min(90, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };
    const end = () => { window.removeEventListener('mousemove', move); window.removeEventListener('touchmove', move); };
    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleDownload = async () => {
    setIsLoading(true);
    const pdfOutput = new jspdf.jsPDF('p', 'px', 'a4');
    const firstPage = pageRefs.current[1];

    // For Images
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (fileToUse?.startsWith('data:image')) {
      const img = new Image();
      img.src = fileToUse;
      await new Promise(r => img.onload = r);
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d')!;
      canvas.width = img.width; canvas.height = img.height;
      ctx.drawImage(img, 0, 0);

      for (const s of placedSignatures) {
        const si = new Image(); si.src = s.dataUrl;
        await new Promise(r => si.onload = r);
        const sw = (canvas.width * (s.w || 25)) / 100;
        ctx.drawImage(si, (canvas.width * s.x)/100, (canvas.height * s.y)/100, sw, sw * (si.height/si.width));
      }
      const finalPdf = new jspdf.jsPDF({ format: [canvas.width, canvas.height], unit: 'px' });
      finalPdf.addImage(canvas.toDataURL('image/jpeg', 0.9), 'JPEG', 0, 0, canvas.width, canvas.height);
      finalPdf.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
      setIsLoading(false);
      return;
    }

    // For PDFs (Multi-page)
    for (let i = 1; i <= numPages; i++) {
      const canvas = pageRefs.current[i];
      if (!canvas) continue;

      if (i > 1) pdfOutput.addPage([canvas.width, canvas.height], 'p');
      else pdfOutput.deletePage(1), pdfOutput.addPage([canvas.width, canvas.height], 'p');

      // Draw original page content
      pdfOutput.addImage(canvas.toDataURL('image/jpeg', 0.8), 'JPEG', 0, 0, canvas.width, canvas.height);

      // Overlay signatures for this specific page
      const sigsOnPage = placedSignatures.filter(s => s.pageNumber === i);
      for (const s of sigsOnPage) {
        const sw = (canvas.width * (s.w || 25)) / 100;
        const sh = sw; // simplified aspect ratio for export
        pdfOutput.addImage(s.dataUrl, 'PNG', (canvas.width * s.x)/100, (canvas.height * s.y)/100, sw, sh);
      }
    }

    pdfOutput.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
    setIsLoading(false);
  };

  const handleShare = (platform: 'whatsapp' | 'email') => {
    const text = encodeURIComponent(`Hi, I have signed the document: ${activeDoc?.name}.`);
    if (platform === 'whatsapp') window.open(`https://wa.me/?text=${text}`, '_blank');
    else window.location.href = `mailto:?subject=Signed Document&body=${text}`;
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-100 transition-transform active:scale-95">S</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignEase</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest text-center">Digital Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowSignaturePad(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/90 z-[70] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-14 h-14 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-800 tracking-tight">Processing multi-page document...</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Success!</h2>
            <p className="text-gray-500 font-medium mb-10">All pages signed successfully.</p>
            <div className="space-y-3">
              <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                 <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">WhatsApp</button>
                 <button onClick={() => handleShare('email')} className="flex-1 bg-slate-800 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">Email</button>
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Home</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard documents={documents} onAction={() => { resetSigningState(); setCurrentView(AppView.SIGN_DOC); }} onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} onDeleteDoc={handleDeleteDoc} />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500 pb-32">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'View Document' : 'Place Signature'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                   <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload File</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">PDFs and Images supported</p>
                    <label className="bg-indigo-600 text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-indigo-700 shadow-2xl shadow-indigo-100 inline-block transition-transform active:scale-95">
                      Choose File
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-10">
                    <div className="flex flex-col items-center gap-8 px-2 overflow-y-auto scrollbar-hide">
                      {Array.from({ length: numPages }).map((_, idx) => {
                        const pageNum = idx + 1;
                        return (
                          <div key={pageNum} className="relative bg-white shadow-2xl leading-[0] border border-slate-200 rounded-sm">
                            <canvas 
                              ref={el => pageRefs.current[pageNum] = el} 
                              className="max-w-full h-auto"
                            />
                            {/* Signature Overlay Layer for this specific page */}
                            <div className="absolute inset-0 z-20 pointer-events-none">
                              {placedSignatures.filter(s => s.pageNumber === pageNum).map(ps => (
                                <div 
                                  key={ps.id} 
                                  style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} 
                                  className="absolute z-30 cursor-move touch-none pointer-events-auto animate-pulse-once" 
                                  onMouseDown={(e) => handleDrag(ps.id, pageNum, e)} 
                                  onTouchStart={(e) => handleDrag(ps.id, pageNum, e)}
                                >
                                  <div className="relative group">
                                    <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-500/50'} p-0.5`} />
                                    {activeDoc?.status !== 'SIGNED' && (
                                      <>
                                        <button onClick={(e) => { e.stopPropagation(); setPlacedSignatures(p => p.filter(x => x.id !== ps.id)); }} className="absolute -top-4 -right-4 bg-red-500 text-white w-8 h-8 rounded-full text-xs flex items-center justify-center shadow-lg font-bold border-2 border-white z-40">✕</button>
                                        <div onMouseDown={(e) => handleResize(ps.id, pageNum, e)} onTouchStart={(e) => handleResize(ps.id, pageNum, e)} className="resize-handle absolute -bottom-4 -right-4 w-9 h-9 bg-indigo-600 border-4 border-white rounded-full cursor-nwse-resize shadow-xl flex items-center justify-center z-40">
                                          <div className="w-2.5 h-2.5 border-r-2 border-b-2 border-white rotate-45 mb-1 mr-1"></div>
                                        </div>
                                      </>
                                    )}
                                  </div>
                                </div>
                              ))}
                            </div>
                            <div className="absolute top-2 right-2 bg-black/40 text-white text-[10px] font-black px-2 py-1 rounded backdrop-blur-sm pointer-events-none">
                              Page {pageNum} / {numPages}
                            </div>
                          </div>
                        );
                      })}
                    </div>

                    <div className="fixed bottom-0 left-0 right-0 p-6 z-40 bg-white/80 backdrop-blur-md border-t border-slate-100 flex flex-col gap-4">
                       {activeDoc?.status === 'SIGNED' ? (
                         <div className="flex gap-3 max-w-lg mx-auto w-full">
                           <button onClick={handleDownload} className="flex-[2] bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
                           <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all text-[10px] uppercase tracking-widest">Share</button>
                         </div>
                       ) : (
                         <div className="max-w-lg mx-auto w-full space-y-4">
                            <div className="flex gap-4 overflow-x-auto pb-1 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-24 h-14 bg-white border-2 border-slate-100 rounded-xl flex items-center justify-center p-2 shadow-sm hover:border-indigo-300 transition-all active:scale-90 overflow-hidden">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply object-contain" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-14 h-14 bg-slate-50 text-slate-400 rounded-xl border-2 border-dashed border-slate-200 text-xl font-bold flex items-center justify-center active:bg-indigo-50 transition-colors">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 disabled:opacity-30 transition-all active:scale-95">Complete & Secure Document</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}

      <style>{`
        @keyframes pulse-once {
          0% { transform: scale(0.9); opacity: 0; }
          50% { transform: scale(1.05); opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
        .animate-pulse-once {
          animation: pulse-once 0.3s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

