import React, { useState } from 'react';

declare const jspdf: any;

interface ImageToPdfConverterProps {
  onComplete: (dataUrl: string) => void;
  onCancel: () => void;
}

const ImageToPdfConverter: React.FC<ImageToPdfConverterProps> = ({ onComplete, onCancel }) => {
  const [images, setImages] = useState<{ id: string; data: string }[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    Array.from(files).forEach(file => {
      const reader = new FileReader();
      reader.onload = (re) => {
        setImages(prev => [...prev, { id: Math.random().toString(), data: re.target?.result as string }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const removeImage = (id: string) => {
    setImages(prev => prev.filter(img => img.id !== id));
  };

  const moveImage = (id: string, direction: 'up' | 'down') => {
    const idx = images.findIndex(img => img.id === id);
    if (idx === -1) return;
    const newImages = [...images];
    const targetIdx = direction === 'up' ? idx - 1 : idx + 1;
    if (targetIdx < 0 || targetIdx >= newImages.length) return;
    [newImages[idx], newImages[targetIdx]] = [newImages[targetIdx], newImages[idx]];
    setImages(newImages);
  };

  const generatePdf = async () => {
    if (images.length === 0) return;
    setIsProcessing(true);

    try {
      const pdf = new jspdf.jsPDF();
      for (let i = 0; i < images.length; i++) {
        const img = new Image();
        img.src = images[i].data;
        await new Promise(resolve => img.onload = resolve);

        if (i > 0) pdf.addPage();
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();
        const ratio = Math.min(pdfWidth / img.width, pdfHeight / img.height);
        const w = img.width * ratio;
        const h = img.height * ratio;
        const x = (pdfWidth - w) / 2;
        const y = (pdfHeight - h) / 2;

        pdf.addImage(images[i].data, 'JPEG', x, y, w, h);
      }

      onComplete(pdf.output('datauristring'));
    } catch (err) {
      console.error(err);
      alert("Failed to create PDF");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-300 pb-32">
      <div className="flex justify-between items-center px-2">
        <div>
          <h2 className="text-2xl font-black text-gray-900 tracking-tight">Images to PDF</h2>
          <p className="text-xs font-bold text-amber-500 uppercase tracking-widest mt-1">Bharat Scan</p>
        </div>
        <button onClick={onCancel} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900">✕</button>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 p-8 shadow-sm">
        {images.length === 0 ? (
          <div className="text-center py-12">
            <div className="w-20 h-20 bg-amber-50 text-amber-500 rounded-full flex items-center justify-center text-3xl mx-auto mb-6">📸</div>
            <p className="text-slate-500 font-black mb-10">Select one or more images</p>
            <label className="bg-amber-500 text-white px-10 py-5 rounded-2xl font-black cursor-pointer shadow-xl shadow-amber-100 active:scale-95 transition-all inline-block">
              Choose Images
              <input type="file" multiple accept="image/*" className="hidden" onChange={handleFileSelect} />
            </label>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
              {images.map((img, idx) => (
                <div key={img.id} className="relative group rounded-2xl overflow-hidden border border-slate-100 shadow-sm aspect-[3/4]">
                  <img src={img.data} className="w-full h-full object-cover" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center gap-2">
                    <div className="flex gap-2">
                      <button onClick={() => moveImage(img.id, 'up')} className="w-8 h-8 bg-white rounded-full text-xs font-black">↑</button>
                      <button onClick={() => moveImage(img.id, 'down')} className="w-8 h-8 bg-white rounded-full text-xs font-black">↓</button>
                    </div>
                    <button onClick={() => removeImage(img.id)} className="bg-red-500 text-white px-3 py-1.5 rounded-xl text-[8px] font-black uppercase tracking-widest">Remove</button>
                  </div>
                  <div className="absolute top-2 left-2 bg-black/50 text-white text-[10px] px-2 py-1 rounded font-black backdrop-blur-md">{idx + 1}</div>
                </div>
              ))}
              <label className="border-4 border-dashed border-slate-50 rounded-2xl flex flex-col items-center justify-center gap-2 cursor-pointer hover:bg-slate-50 transition-all aspect-[3/4]">
                <span className="text-2xl text-slate-300">+</span>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Add More</span>
                <input type="file" multiple accept="image/*" className="hidden" onChange={handleFileSelect} />
              </label>
            </div>

            <div className="pt-6 border-t border-slate-50">
               <button 
                onClick={generatePdf} 
                disabled={isProcessing}
                className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 disabled:opacity-50 active:scale-95 transition-all"
               >
                {isProcessing ? 'Generating...' : `Create PDF from ${images.length} images`}
               </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ImageToPdfConverter;

import React, { useState } from 'react';

declare const jspdf: any;
declare const pdfjsLib: any;

interface PdfMergerProps {
  onComplete: (dataUrl: string) => void;
  onCancel: () => void;
}

const PdfMerger: React.FC<PdfMergerProps> = ({ onComplete, onCancel }) => {
  const [pdfs, setPdfs] = useState<{ id: string; name: string; data: string; pageCount: number }[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    for (const file of Array.from(files)) {
      const reader = new FileReader();
      reader.onload = async (re) => {
        const data = re.target?.result as string;
        try {
          const loadingTask = pdfjsLib.getDocument(data);
          const pdfDoc = await loadingTask.promise;
          setPdfs(prev => [...prev, { 
            id: Math.random().toString(), 
            name: file.name, 
            data, 
            pageCount: pdfDoc.numPages 
          }]);
        } catch (err) {
          console.error("Not a valid PDF", err);
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const removePdf = (id: string) => {
    setPdfs(prev => prev.filter(p => p.id !== id));
  };

  const movePdf = (id: string, direction: 'up' | 'down') => {
    const idx = pdfs.findIndex(p => p.id === id);
    if (idx === -1) return;
    const newPdfs = [...pdfs];
    const targetIdx = direction === 'up' ? idx - 1 : idx + 1;
    if (targetIdx < 0 || targetIdx >= newPdfs.length) return;
    [newPdfs[idx], newPdfs[targetIdx]] = [newPdfs[targetIdx], newPdfs[idx]];
    setPdfs(newPdfs);
  };

  const mergePdfs = async () => {
    if (pdfs.length < 2) {
      alert("Select at least 2 PDFs to merge");
      return;
    }
    setIsProcessing(true);

    try {
      const finalPdf = new jspdf.jsPDF();
      let totalPagesAdded = 0;

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d')!;

      for (const pdfData of pdfs) {
        const loadingTask = pdfjsLib.getDocument(pdfData.data);
        const pdf = await loadingTask.promise;

        for (let i = 1; i <= pdf.numPages; i++) {
          const page = await pdf.getPage(i);
          const viewport = page.getViewport({ scale: 2 });
          canvas.width = viewport.width;
          canvas.height = viewport.height;

          await page.render({ canvasContext: ctx, viewport }).promise;

          if (totalPagesAdded > 0) {
            finalPdf.addPage();
          }

          const pdfWidth = finalPdf.internal.pageSize.getWidth();
          const pdfHeight = finalPdf.internal.pageSize.getHeight();
          const ratio = Math.min(pdfWidth / canvas.width, pdfHeight / canvas.height);
          const w = canvas.width * ratio;
          const h = canvas.height * ratio;
          const x = (pdfWidth - w) / 2;
          const y = (pdfHeight - h) / 2;

          finalPdf.addImage(canvas.toDataURL('image/jpeg', 0.8), 'JPEG', x, y, w, h);
          totalPagesAdded++;
        }
      }

      onComplete(finalPdf.output('datauristring'));
    } catch (err) {
      console.error(err);
      alert("Failed to merge PDFs");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-300 pb-32">
      <div className="flex justify-between items-center px-2">
        <div>
          <h2 className="text-2xl font-black text-gray-900 tracking-tight">Merge PDFs</h2>
          <p className="text-xs font-bold text-indigo-500 uppercase tracking-widest mt-1">Digital Bharat Binder</p>
        </div>
        <button onClick={onCancel} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900">✕</button>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 p-8 shadow-sm">
        {pdfs.length === 0 ? (
          <div className="text-center py-12">
            <div className="w-20 h-20 bg-indigo-50 text-indigo-500 rounded-full flex items-center justify-center text-3xl mx-auto mb-6">📑</div>
            <p className="text-slate-500 font-black mb-10">Select PDF files to combine</p>
            <label className="bg-indigo-600 text-white px-10 py-5 rounded-2xl font-black cursor-pointer shadow-xl shadow-indigo-100 active:scale-95 transition-all inline-block">
              Choose PDF Files
              <input type="file" multiple accept=".pdf" className="hidden" onChange={handleFileSelect} />
            </label>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="space-y-3">
              {pdfs.map((pdf, idx) => (
                <div key={pdf.id} className="bg-slate-50 p-4 rounded-2xl border border-slate-100 flex items-center justify-between group">
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-lg shadow-sm font-black border border-slate-100">{idx + 1}</div>
                    <div className="overflow-hidden">
                      <p className="text-xs font-black text-slate-800 truncate max-w-[150px]">{pdf.name}</p>
                      <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{pdf.pageCount} Pages</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <button onClick={() => movePdf(pdf.id, 'up')} className="w-8 h-8 bg-white rounded-lg text-[10px] font-black border border-slate-100 shadow-sm active:scale-90 transition-all">↑</button>
                    <button onClick={() => movePdf(pdf.id, 'down')} className="w-8 h-8 bg-white rounded-lg text-[10px] font-black border border-slate-100 shadow-sm active:scale-90 transition-all">↓</button>
                    <button onClick={() => removePdf(pdf.id)} className="w-8 h-8 bg-red-50 text-red-500 rounded-lg text-[10px] font-black border border-red-100 active:scale-90 transition-all">✕</button>
                  </div>
                </div>
              ))}
              <label className="border-2 border-dashed border-slate-200 rounded-2xl p-4 flex items-center justify-center gap-2 cursor-pointer hover:bg-slate-50 transition-all mt-4">
                <span className="text-indigo-600 font-black text-sm">+ Add More Files</span>
                <input type="file" multiple accept=".pdf" className="hidden" onChange={handleFileSelect} />
              </label>
            </div>

            <div className="pt-6 border-t border-slate-50">
               <button 
                onClick={mergePdfs} 
                disabled={isProcessing || pdfs.length < 2}
                className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 disabled:opacity-30 active:scale-95 transition-all"
               >
                {isProcessing ? 'Processing...' : `Merge ${pdfs.length} PDFs`}
               </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default PdfMerger;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';
import ImageToPdfConverter from './components/ImageToPdfConverter';
import PdfMerger from './components/PdfMerger';
import * as db from './db';

declare const jspdf: any;
declare const pdfjsLib: any;

if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [numPages, setNumPages] = useState(1);

  const pageRefs = useRef<(HTMLCanvasElement | null)[]>([]);

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        const [docs, sigs] = await Promise.all([db.getAllDocs(), db.getAllSigs()]);
        setDocuments(docs);
        setSignatures(sigs);
      } catch (err) {
        console.error("Failed to load data from IndexedDB:", err);
      }
    };
    loadInitialData();
  }, []);

  const handleDeleteDoc = useCallback(async (id: string) => {
    try {
      await db.deleteDoc(id);
      setDocuments(prev => prev.filter(doc => doc.id !== id));
    } catch (err) {
      console.error("Failed to delete document:", err);
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
    setNumPages(1);
    pageRefs.current = [];
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleToolComplete = (dataUrl: string) => {
    setUploadFile(dataUrl);
    setCurrentView(AppView.SIGN_DOC);
  };

  useEffect(() => {
    const renderAllPages = async (dataUrl: string) => {
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        setNumPages(pdf.numPages);

        setTimeout(async () => {
          for (let i = 1; i <= pdf.numPages; i++) {
            const canvas = pageRefs.current[i];
            if (!canvas) continue;
            const page = await pdf.getPage(i);
            const viewport = page.getViewport({ scale: 2 });
            const context = canvas.getContext('2d');
            if (!context) continue;
            canvas.height = viewport.height;
            canvas.width = viewport.width;
            await page.render({ canvasContext: context, viewport }).promise;
          }
        }, 150);
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data && data.startsWith('data:application/pdf')) {
      renderAllPages(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = async (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    try {
      await db.saveSig(newSign);
      setSignatures(prev => [newSign, ...prev]);
      setShowSignaturePad(false);
    } catch (err) {
      console.error("Failed to save signature:", err);
    }
  };

  const handleSignFinish = async () => {
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) return;
    setIsLoading(true);

    const isPdf = fileToUse.startsWith('data:application/pdf');
    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || (isPdf ? 'Signed_Doc.pdf' : 'Signed_Image.png'),
      type: isPdf ? 'PDF' : 'IMAGE',
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: fileToUse,
      placedSignatures: [...placedSignatures]
    };

    try {
      await db.saveDoc(newDoc);
      const updatedDocs = await db.getAllDocs();
      setDocuments(updatedDocs);
      setIsLoading(false);
      setShowSuccessScreen(true);
    } catch (err) {
      setIsLoading(false);
      console.error("Failed to save signed document:", err);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 35, y: 40, w: 25,
      pageNumber: 1
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, initialPageNum: number, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    if (e.target.closest('.resize-handle')) return;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;

      let targetPageNum = initialPageNum;
      let targetRect = pageRefs.current[initialPageNum]?.getBoundingClientRect();

      for (let i = 1; i <= numPages; i++) {
        const canvas = pageRefs.current[i];
        if (!canvas) continue;
        const rect = canvas.getBoundingClientRect();
        if (cy >= rect.top && cy <= rect.bottom) {
          targetPageNum = i;
          targetRect = rect;
          break;
        }
      }

      if (targetRect) {
        const x = Math.max(-5, Math.min(95, ((cx - targetRect.left) / targetRect.width) * 100));
        const y = Math.max(-5, Math.min(95, ((cy - targetRect.top) / targetRect.height) * 100));
        setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y, pageNumber: targetPageNum } : p));
      }
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, pageNum: number, e: any) => {
    e.stopPropagation();
    const canvas = pageRefs.current[pageNum];
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(10, Math.min(90, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleDownload = async () => {
    setIsLoading(true);
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) {
      setIsLoading(false);
      return;
    }

    try {
      const pdfOutput = new jspdf.jsPDF({
        orientation: 'p',
        unit: 'pt',
        format: 'a4'
      });

      if (fileToUse.startsWith('data:image')) {
        const img = new Image();
        img.src = fileToUse;
        await new Promise(r => img.onload = r);
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d')!;
        canvas.width = img.width; canvas.height = img.height;
        ctx.drawImage(img, 0, 0);

        for (const s of placedSignatures) {
          const si = new Image(); si.src = s.dataUrl;
          await new Promise(r => si.onload = r);
          const sw = (canvas.width * (s.w || 25)) / 100;
          const sh = sw * (si.height / si.width);
          ctx.drawImage(si, (canvas.width * s.x)/100, (canvas.height * s.y)/100, sw, sh);
        }

        const imgPdf = new jspdf.jsPDF({ 
          orientation: canvas.width > canvas.height ? 'l' : 'p',
          format: [canvas.width, canvas.height], 
          unit: 'pt' 
        });
        imgPdf.addImage(canvas.toDataURL('image/jpeg', 0.95), 'JPEG', 0, 0, canvas.width, canvas.height);
        imgPdf.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
        setIsLoading(false);
        return;
      }

      const loadingTask = pdfjsLib.getDocument(fileToUse);
      const pdf = await loadingTask.promise;

      const offscreenCanvas = document.createElement('canvas');
      const ctx = offscreenCanvas.getContext('2d')!;

      for (let i = 1; i <= pdf.numPages; i++) {
        const page = await pdf.getPage(i);
        const baseViewport = page.getViewport({ scale: 1 });
        const renderViewport = page.getViewport({ scale: 2 });

        offscreenCanvas.width = renderViewport.width;
        offscreenCanvas.height = renderViewport.height;
        await page.render({ canvasContext: ctx, viewport: renderViewport }).promise;

        if (i > 1) {
          pdfOutput.addPage([baseViewport.width, baseViewport.height], baseViewport.width > baseViewport.height ? 'l' : 'p');
        } else {
          pdfOutput.deletePage(1);
          pdfOutput.addPage([baseViewport.width, baseViewport.height], baseViewport.width > baseViewport.height ? 'l' : 'p');
        }

        pdfOutput.addImage(offscreenCanvas.toDataURL('image/jpeg', 0.9), 'JPEG', 0, 0, baseViewport.width, baseViewport.height);

        const sigsOnPage = placedSignatures.filter(s => s.pageNumber === i);
        for (const s of sigsOnPage) {
          const si = new Image();
          si.src = s.dataUrl;
          await new Promise(r => si.onload = r);

          const sw = (baseViewport.width * (s.w || 25)) / 100;
          const sh = sw * (si.height / si.width);

          pdfOutput.addImage(s.dataUrl, 'PNG', (baseViewport.width * s.x)/100, (baseViewport.height * s.y)/100, sw, sh);
        }
      }

      pdfOutput.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
    } catch (err) {
      console.error("Critical download error:", err);
      alert("Error generating high-quality PDF. Please try a smaller file.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleShare = (platform: 'whatsapp' | 'email') => {
    const text = encodeURIComponent(`Hi, I have signed the document: ${activeDoc?.name}.`);
    if (platform === 'whatsapp') window.open(`https://wa.me/?text=${text}`, '_blank');
    else window.location.href = `mailto:?subject=Signed Document&body=${text}`;
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-100 transition-transform active:scale-95">S</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignEase</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest text-center">Digital Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowSignaturePad(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/95 z-[70] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-16 h-16 border-[6px] border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-900 tracking-tight text-lg">Processing...</p>
            <p className="text-sm text-slate-500 font-medium">Please wait, ensuring maximum quality.</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Securely Signed</h2>
            <p className="text-gray-500 font-medium mb-10">Your document is ready for download.</p>
            <div className="space-y-3">
              <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                 <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">WhatsApp</button>
                 <button onClick={() => handleShare('email')} className="flex-1 bg-slate-800 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">Email</button>
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Dashboard</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard documents={documents} onAction={(view) => setCurrentView(view)} onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} onDeleteDoc={handleDeleteDoc} />
            )}

            {currentView === AppView.IMAGE_TO_PDF && (
              <ImageToPdfConverter onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.MERGE_PDF && (
              <PdfMerger onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500 pb-32">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'Document View' : 'Signing Area'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                   <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload Document</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">Select PDF or Image to sign</p>
                    <label className="bg-indigo-600 text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-indigo-700 shadow-2xl shadow-indigo-100 inline-block transition-transform active:scale-95">
                      Browse Files
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-10">
                    <div className="flex flex-col items-center gap-8 px-2 overflow-y-auto scrollbar-hide">
                      {Array.from({ length: numPages }).map((_, idx) => {
                        const pageNum = idx + 1;
                        return (
                          <div key={pageNum} className="relative bg-white shadow-2xl leading-[0] border border-slate-200 rounded-sm">
                            <canvas 
                              ref={el => pageRefs.current[pageNum] = el} 
                              className="max-w-full h-auto"
                            />
                            <div className="absolute inset-0 z-20 pointer-events-none">
                              {placedSignatures.filter(s => s.pageNumber === pageNum).map(ps => (
                                <div 
                                  key={ps.id} 
                                  style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} 
                                  className="absolute z-30 cursor-move touch-none pointer-events-auto animate-pulse-once" 
                                  onMouseDown={(e) => handleDrag(ps.id, pageNum, e)} 
                                  onTouchStart={(e) => handleDrag(ps.id, pageNum, e)}
                                >
                                  <div className="relative group">
                                    <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-500/50'} p-0.5`} />
                                    {activeDoc?.status !== 'SIGNED' && (
                                      <>
                                        <button onClick={(e) => { e.stopPropagation(); setPlacedSignatures(p => p.filter(x => x.id !== ps.id)); }} className="absolute -top-4 -right-4 bg-red-500 text-white w-8 h-8 rounded-full text-xs flex items-center justify-center shadow-lg font-bold border-2 border-white z-40">✕</button>
                                        <div onMouseDown={(e) => handleResize(ps.id, pageNum, e)} onTouchStart={(e) => handleResize(ps.id, pageNum, e)} className="resize-handle absolute -bottom-4 -right-4 w-9 h-9 bg-indigo-600 border-4 border-white rounded-full cursor-nwse-resize shadow-xl flex items-center justify-center z-40">
                                          <div className="w-2.5 h-2.5 border-r-2 border-b-2 border-white rotate-45 mb-1 mr-1"></div>
                                        </div>
                                      </>
                                    )}
                                  </div>
                                </div>
                              ))}
                            </div>
                            <div className="absolute top-2 right-2 bg-black/40 text-white text-[10px] font-black px-2 py-1 rounded backdrop-blur-sm pointer-events-none">
                              Page {pageNum} / {numPages}
                            </div>
                          </div>
                        );
                      })}
                    </div>

                    <div className="fixed bottom-0 left-0 right-0 p-6 z-40 bg-white/80 backdrop-blur-md border-t border-slate-100 flex flex-col gap-4">
                       {activeDoc?.status === 'SIGNED' ? (
                         <div className="flex gap-3 max-w-lg mx-auto w-full">
                           <button onClick={handleDownload} className="flex-[2] bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
                           <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all text-[10px] uppercase tracking-widest">Share</button>
                         </div>
                       ) : (
                         <div className="max-w-lg mx-auto w-full space-y-4">
                            <div className="flex gap-4 overflow-x-auto pb-1 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-24 h-14 bg-white border-2 border-slate-100 rounded-xl flex items-center justify-center p-2 shadow-sm hover:border-indigo-300 transition-all active:scale-90 overflow-hidden">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply object-contain" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-14 h-14 bg-slate-50 text-slate-400 rounded-xl border-2 border-dashed border-slate-200 text-xl font-bold flex items-center justify-center active:bg-indigo-50 transition-colors">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 disabled:opacity-30 transition-all active:scale-95">Complete & Secure</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}

      <style>{`
        @keyframes pulse-once {
          0% { transform: scale(0.9); opacity: 0; }
          50% { transform: scale(1.05); opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
        .animate-pulse-once {
          animation: pulse-once 0.3s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState } from 'react';

declare const jspdf: any;

interface ImageToPdfConverterProps {
  onComplete: (dataUrl: string) => void;
  onCancel: () => void;
}

const ImageToPdfConverter: React.FC<ImageToPdfConverterProps> = ({ onComplete, onCancel }) => {
  const [images, setImages] = useState<{ id: string; data: string }[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    // Fixed: Cast the result of Array.from(files) to File[] to ensure 'file' is properly typed as a Blob/File
    (Array.from(files) as File[]).forEach(file => {
      const reader = new FileReader();
      reader.onload = (re) => {
        setImages(prev => [...prev, { id: Math.random().toString(), data: re.target?.result as string }]);
      };
      reader.readAsDataURL(file);
    });
  };

  const removeImage = (id: string) => {
    setImages(prev => prev.filter(img => img.id !== id));
  };

  const moveImage = (id: string, direction: 'up' | 'down') => {
    const idx = images.findIndex(img => img.id === id);
    if (idx === -1) return;
    const newImages = [...images];
    const targetIdx = direction === 'up' ? idx - 1 : idx + 1;
    if (targetIdx < 0 || targetIdx >= newImages.length) return;
    [newImages[idx], newImages[targetIdx]] = [newImages[targetIdx], newImages[idx]];
    setImages(newImages);
  };

  const generatePdf = async () => {
    if (images.length === 0) return;
    setIsProcessing(true);

    try {
      const pdf = new jspdf.jsPDF();
      for (let i = 0; i < images.length; i++) {
        const img = new Image();
        img.src = images[i].data;
        await new Promise(resolve => img.onload = resolve);

        if (i > 0) pdf.addPage();
        const pdfWidth = pdf.internal.pageSize.getWidth();
        const pdfHeight = pdf.internal.pageSize.getHeight();
        const ratio = Math.min(pdfWidth / img.width, pdfHeight / img.height);
        const w = img.width * ratio;
        const h = img.height * ratio;
        const x = (pdfWidth - w) / 2;
        const y = (pdfHeight - h) / 2;

        pdf.addImage(images[i].data, 'JPEG', x, y, w, h);
      }

      onComplete(pdf.output('datauristring'));
    } catch (err) {
      console.error(err);
      alert("Failed to create PDF");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-300 pb-32">
      <div className="flex justify-between items-center px-2">
        <div>
          <h2 className="text-2xl font-black text-gray-900 tracking-tight">Images to PDF</h2>
          <p className="text-xs font-bold text-amber-500 uppercase tracking-widest mt-1">Bharat Scan</p>
        </div>
        <button onClick={onCancel} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900">✕</button>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 p-8 shadow-sm">
        {images.length === 0 ? (
          <div className="text-center py-12">
            <div className="w-20 h-20 bg-amber-50 text-amber-500 rounded-full flex items-center justify-center text-3xl mx-auto mb-6">📸</div>
            <p className="text-slate-500 font-black mb-10">Select one or more images</p>
            <label className="bg-amber-500 text-white px-10 py-5 rounded-2xl font-black cursor-pointer shadow-xl shadow-amber-100 active:scale-95 transition-all inline-block">
              Choose Images
              <input type="file" multiple accept="image/*" className="hidden" onChange={handleFileSelect} />
            </label>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
              {images.map((img, idx) => (
                <div key={img.id} className="relative group rounded-2xl overflow-hidden border border-slate-100 shadow-sm aspect-[3/4]">
                  <img src={img.data} className="w-full h-full object-cover" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center gap-2">
                    <div className="flex gap-2">
                      <button onClick={() => moveImage(img.id, 'up')} className="w-8 h-8 bg-white rounded-full text-xs font-black">↑</button>
                      <button onClick={() => moveImage(img.id, 'down')} className="w-8 h-8 bg-white rounded-full text-xs font-black">↓</button>
                    </div>
                    <button onClick={() => removeImage(img.id)} className="bg-red-500 text-white px-3 py-1.5 rounded-xl text-[8px] font-black uppercase tracking-widest">Remove</button>
                  </div>
                  <div className="absolute top-2 left-2 bg-black/50 text-white text-[10px] px-2 py-1 rounded font-black backdrop-blur-md">{idx + 1}</div>
                </div>
              ))}
              <label className="border-4 border-dashed border-slate-50 rounded-2xl flex flex-col items-center justify-center gap-2 cursor-pointer hover:bg-slate-50 transition-all aspect-[3/4]">
                <span className="text-2xl text-slate-300">+</span>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Add More</span>
                <input type="file" multiple accept="image/*" className="hidden" onChange={handleFileSelect} />
              </label>
            </div>

            <div className="pt-6 border-t border-slate-50">
               <button 
                onClick={generatePdf} 
                disabled={isProcessing}
                className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 disabled:opacity-50 active:scale-95 transition-all"
               >
                {isProcessing ? 'Generating...' : `Create PDF from ${images.length} images`}
               </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default ImageToPdfConverter;

import React, { useState } from 'react';

declare const jspdf: any;
declare const pdfjsLib: any;

interface PdfMergerProps {
  onComplete: (dataUrl: string) => void;
  onCancel: () => void;
}

const PdfMerger: React.FC<PdfMergerProps> = ({ onComplete, onCancel }) => {
  const [pdfs, setPdfs] = useState<{ id: string; name: string; data: string; pageCount: number }[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    // Fixed: Cast the result of Array.from(files) to File[] to ensure 'file' is properly typed
    for (const file of Array.from(files) as File[]) {
      const reader = new FileReader();
      reader.onload = async (re) => {
        const data = re.target?.result as string;
        try {
          const loadingTask = pdfjsLib.getDocument(data);
          const pdfDoc = await loadingTask.promise;
          setPdfs(prev => [...prev, { 
            id: Math.random().toString(), 
            name: file.name, 
            data, 
            pageCount: pdfDoc.numPages 
          }]);
        } catch (err) {
          console.error("Not a valid PDF", err);
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const removePdf = (id: string) => {
    setPdfs(prev => prev.filter(p => p.id !== id));
  };

  const movePdf = (id: string, direction: 'up' | 'down') => {
    const idx = pdfs.findIndex(p => p.id === id);
    if (idx === -1) return;
    const newPdfs = [...pdfs];
    const targetIdx = direction === 'up' ? idx - 1 : idx + 1;
    if (targetIdx < 0 || targetIdx >= newPdfs.length) return;
    [newPdfs[idx], newPdfs[targetIdx]] = [newPdfs[targetIdx], newPdfs[idx]];
    setPdfs(newPdfs);
  };

  const mergePdfs = async () => {
    if (pdfs.length < 2) {
      alert("Select at least 2 PDFs to merge");
      return;
    }
    setIsProcessing(true);

    try {
      const finalPdf = new jspdf.jsPDF();
      let totalPagesAdded = 0;

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d')!;

      for (const pdfData of pdfs) {
        const loadingTask = pdfjsLib.getDocument(pdfData.data);
        const pdf = await loadingTask.promise;

        for (let i = 1; i <= pdf.numPages; i++) {
          const page = await pdf.getPage(i);
          const viewport = page.getViewport({ scale: 2 });
          canvas.width = viewport.width;
          canvas.height = viewport.height;

          await page.render({ canvasContext: ctx, viewport }).promise;

          if (totalPagesAdded > 0) {
            finalPdf.addPage();
          }

          const pdfWidth = finalPdf.internal.pageSize.getWidth();
          const pdfHeight = finalPdf.internal.pageSize.getHeight();
          const ratio = Math.min(pdfWidth / canvas.width, pdfHeight / canvas.height);
          const w = canvas.width * ratio;
          const h = canvas.height * ratio;
          const x = (pdfWidth - w) / 2;
          const y = (pdfHeight - h) / 2;

          finalPdf.addImage(canvas.toDataURL('image/jpeg', 0.8), 'JPEG', x, y, w, h);
          totalPagesAdded++;
        }
      }

      onComplete(finalPdf.output('datauristring'));
    } catch (err) {
      console.error(err);
      alert("Failed to merge PDFs");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-300 pb-32">
      <div className="flex justify-between items-center px-2">
        <div>
          <h2 className="text-2xl font-black text-gray-900 tracking-tight">Merge PDFs</h2>
          <p className="text-xs font-bold text-indigo-500 uppercase tracking-widest mt-1">Digital Bharat Binder</p>
        </div>
        <button onClick={onCancel} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900">✕</button>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 p-8 shadow-sm">
        {pdfs.length === 0 ? (
          <div className="text-center py-12">
            <div className="w-20 h-20 bg-indigo-50 text-indigo-500 rounded-full flex items-center justify-center text-3xl mx-auto mb-6">📑</div>
            <p className="text-slate-500 font-black mb-10">Select PDF files to combine</p>
            <label className="bg-indigo-600 text-white px-10 py-5 rounded-2xl font-black cursor-pointer shadow-xl shadow-indigo-100 active:scale-95 transition-all inline-block">
              Choose PDF Files
              <input type="file" multiple accept=".pdf" className="hidden" onChange={handleFileSelect} />
            </label>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="space-y-3">
              {pdfs.map((pdf, idx) => (
                <div key={pdf.id} className="bg-slate-50 p-4 rounded-2xl border border-slate-100 flex items-center justify-between group">
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-lg shadow-sm font-black border border-slate-100">{idx + 1}</div>
                    <div className="overflow-hidden">
                      <p className="text-xs font-black text-slate-800 truncate max-w-[150px]">{pdf.name}</p>
                      <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{pdf.pageCount} Pages</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <button onClick={() => movePdf(pdf.id, 'up')} className="w-8 h-8 bg-white rounded-lg text-[10px] font-black border border-slate-100 shadow-sm active:scale-90 transition-all">↑</button>
                    <button onClick={() => movePdf(pdf.id, 'down')} className="w-8 h-8 bg-white rounded-lg text-[10px] font-black border border-slate-100 shadow-sm active:scale-90 transition-all">↓</button>
                    <button onClick={() => removePdf(pdf.id)} className="w-8 h-8 bg-red-50 text-red-500 rounded-lg text-[10px] font-black border border-red-100 active:scale-90 transition-all">✕</button>
                  </div>
                </div>
              ))}
              <label className="border-2 border-dashed border-slate-200 rounded-2xl p-4 flex items-center justify-center gap-2 cursor-pointer hover:bg-slate-50 transition-all mt-4">
                <span className="text-indigo-600 font-black text-sm">+ Add More Files</span>
                <input type="file" multiple accept=".pdf" className="hidden" onChange={handleFileSelect} />
              </label>
            </div>

            <div className="pt-6 border-t border-slate-50">
               <button 
                onClick={mergePdfs} 
                disabled={isProcessing || pdfs.length < 2}
                className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 disabled:opacity-30 active:scale-95 transition-all"
               >
                {isProcessing ? 'Processing...' : `Merge ${pdfs.length} PDFs`}
               </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default PdfMerger;

export enum AppView {
  DASHBOARD = 'DASHBOARD',
  SIGN_DOC = 'SIGN_DOC',
  VIEW_DOC = 'VIEW_DOC',
  IMAGE_TO_PDF = 'IMAGE_TO_PDF',
  MERGE_PDF = 'MERGE_PDF',
  TOOL_SUCCESS = 'TOOL_SUCCESS'
}

export interface PlacedSignature {
  id: string;
  dataUrl: string;
  x: number; // percentage 0-100
  y: number; // percentage 0-100
  w?: number; // width percentage 5-100
  pageNumber: number; // The 1-based page index
}

export interface UserSignature {
  id: string;
  dataUrl: string;
  label: string;
  createdAt: string;
}

export interface DocumentRecord {
  id: string;
  name: string;
  type: 'PDF' | 'IMAGE';
  status: 'SIGNED' | 'PENDING';
  date: string;
  fileData?: string; // base64 data
  placedSignatures?: PlacedSignature[];
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';
import ImageToPdfConverter from './components/ImageToPdfConverter';
import PdfMerger from './components/PdfMerger';
import * as db from './db';

declare const jspdf: any;
declare const pdfjsLib: any;

if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [numPages, setNumPages] = useState(1);
  const [toolResultData, setToolResultData] = useState<{ dataUrl: string, name: string } | null>(null);

  const pageRefs = useRef<(HTMLCanvasElement | null)[]>([]);

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        const [docs, sigs] = await Promise.all([db.getAllDocs(), db.getAllSigs()]);
        setDocuments(docs);
        setSignatures(sigs);
      } catch (err) {
        console.error("Failed to load data from IndexedDB:", err);
      }
    };
    loadInitialData();
  }, []);

  const handleDeleteDoc = useCallback(async (id: string) => {
    try {
      await db.deleteDoc(id);
      setDocuments(prev => prev.filter(doc => doc.id !== id));
    } catch (err) {
      console.error("Failed to delete document:", err);
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
    setNumPages(1);
    setToolResultData(null);
    pageRefs.current = [];
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleToolComplete = (dataUrl: string) => {
    const toolName = currentView === AppView.IMAGE_TO_PDF ? 'Converted_Images.pdf' : 'Merged_Document.pdf';
    setToolResultData({ dataUrl, name: toolName });
    setCurrentView(AppView.TOOL_SUCCESS);
  };

  const proceedToSignFromTool = () => {
    if (toolResultData) {
      setUploadFile(toolResultData.dataUrl);
      setCurrentView(AppView.SIGN_DOC);
    }
  };

  useEffect(() => {
    const renderAllPages = async (dataUrl: string) => {
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        setNumPages(pdf.numPages);

        setTimeout(async () => {
          for (let i = 1; i <= pdf.numPages; i++) {
            const canvas = pageRefs.current[i];
            if (!canvas) continue;
            const page = await pdf.getPage(i);
            const viewport = page.getViewport({ scale: 2 });
            const context = canvas.getContext('2d');
            if (!context) continue;
            canvas.height = viewport.height;
            canvas.width = viewport.width;
            await page.render({ canvasContext: context, viewport }).promise;
          }
        }, 150);
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data && data.startsWith('data:application/pdf')) {
      renderAllPages(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = async (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    try {
      await db.saveSig(newSign);
      setSignatures(prev => [newSign, ...prev]);
      setShowSignaturePad(false);
    } catch (err) {
      console.error("Failed to save signature:", err);
    }
  };

  const handleSignFinish = async () => {
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) return;
    setIsLoading(true);

    const isPdf = fileToUse.startsWith('data:application/pdf');
    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || (isPdf ? 'Signed_Doc.pdf' : 'Signed_Image.png'),
      type: isPdf ? 'PDF' : 'IMAGE',
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: fileToUse,
      placedSignatures: [...placedSignatures]
    };

    try {
      await db.saveDoc(newDoc);
      const updatedDocs = await db.getAllDocs();
      setDocuments(updatedDocs);
      setIsLoading(false);
      setShowSuccessScreen(true);
    } catch (err) {
      setIsLoading(false);
      console.error("Failed to save signed document:", err);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 35, y: 40, w: 25,
      pageNumber: 1
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, initialPageNum: number, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    if (e.target.closest('.resize-handle')) return;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;

      let targetPageNum = initialPageNum;
      let targetRect = pageRefs.current[initialPageNum]?.getBoundingClientRect();

      for (let i = 1; i <= numPages; i++) {
        const canvas = pageRefs.current[i];
        if (!canvas) continue;
        const rect = canvas.getBoundingClientRect();
        if (cy >= rect.top && cy <= rect.bottom) {
          targetPageNum = i;
          targetRect = rect;
          break;
        }
      }

      if (targetRect) {
        const x = Math.max(-5, Math.min(95, ((cx - targetRect.left) / targetRect.width) * 100));
        const y = Math.max(-5, Math.min(95, ((cy - targetRect.top) / targetRect.height) * 100));
        setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y, pageNumber: targetPageNum } : p));
      }
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, pageNum: number, e: any) => {
    e.stopPropagation();
    const canvas = pageRefs.current[pageNum];
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(10, Math.min(90, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const downloadDataUrl = (dataUrl: string, fileName: string) => {
    const link = document.createElement('a');
    link.href = dataUrl;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleDownload = async () => {
    setIsLoading(true);
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) {
      setIsLoading(false);
      return;
    }

    try {
      const pdfOutput = new jspdf.jsPDF({
        orientation: 'p',
        unit: 'pt',
        format: 'a4'
      });

      if (fileToUse.startsWith('data:image')) {
        const img = new Image();
        img.src = fileToUse;
        await new Promise(r => img.onload = r);
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d')!;
        canvas.width = img.width; canvas.height = img.height;
        ctx.drawImage(img, 0, 0);

        for (const s of placedSignatures) {
          const si = new Image(); si.src = s.dataUrl;
          await new Promise(r => si.onload = r);
          const sw = (canvas.width * (s.w || 25)) / 100;
          const sh = sw * (si.height / si.width);
          ctx.drawImage(si, (canvas.width * s.x)/100, (canvas.height * s.y)/100, sw, sh);
        }

        const imgPdf = new jspdf.jsPDF({ 
          orientation: canvas.width > canvas.height ? 'l' : 'p',
          format: [canvas.width, canvas.height], 
          unit: 'pt' 
        });
        imgPdf.addImage(canvas.toDataURL('image/jpeg', 0.95), 'JPEG', 0, 0, canvas.width, canvas.height);
        imgPdf.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
        setIsLoading(false);
        return;
      }

      const loadingTask = pdfjsLib.getDocument(fileToUse);
      const pdf = await loadingTask.promise;

      const offscreenCanvas = document.createElement('canvas');
      const ctx = offscreenCanvas.getContext('2d')!;

      for (let i = 1; i <= pdf.numPages; i++) {
        const page = await pdf.getPage(i);
        const baseViewport = page.getViewport({ scale: 1 });
        const renderViewport = page.getViewport({ scale: 2 });

        offscreenCanvas.width = renderViewport.width;
        offscreenCanvas.height = renderViewport.height;
        await page.render({ canvasContext: ctx, viewport: renderViewport }).promise;

        if (i > 1) {
          pdfOutput.addPage([baseViewport.width, baseViewport.height], baseViewport.width > baseViewport.height ? 'l' : 'p');
        } else {
          pdfOutput.deletePage(1);
          pdfOutput.addPage([baseViewport.width, baseViewport.height], baseViewport.width > baseViewport.height ? 'l' : 'p');
        }

        pdfOutput.addImage(offscreenCanvas.toDataURL('image/jpeg', 0.9), 'JPEG', 0, 0, baseViewport.width, baseViewport.height);

        const sigsOnPage = placedSignatures.filter(s => s.pageNumber === i);
        for (const s of sigsOnPage) {
          const si = new Image();
          si.src = s.dataUrl;
          await new Promise(r => si.onload = r);

          const sw = (baseViewport.width * (s.w || 25)) / 100;
          const sh = sw * (si.height / si.width);

          pdfOutput.addImage(s.dataUrl, 'PNG', (baseViewport.width * s.x)/100, (baseViewport.height * s.y)/100, sw, sh);
        }
      }

      pdfOutput.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
    } catch (err) {
      console.error("Critical download error:", err);
      alert("Error generating high-quality PDF. Please try a smaller file.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleShare = (platform: 'whatsapp' | 'email') => {
    const text = encodeURIComponent(`Hi, I have signed the document: ${activeDoc?.name}.`);
    if (platform === 'whatsapp') window.open(`https://wa.me/?text=${text}`, '_blank');
    else window.location.href = `mailto:?subject=Signed Document&body=${text}`;
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-100 transition-transform active:scale-95">S</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignEase</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest text-center">Digital Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowSignaturePad(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/95 z-[70] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-16 h-16 border-[6px] border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-900 tracking-tight text-lg">Processing...</p>
            <p className="text-sm text-slate-500 font-medium">Please wait, ensuring maximum quality.</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Securely Signed</h2>
            <p className="text-gray-500 font-medium mb-10">Your document is ready for download.</p>
            <div className="space-y-3">
              <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                 <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">WhatsApp</button>
                 <button onClick={() => handleShare('email')} className="flex-1 bg-slate-800 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">Email</button>
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Dashboard</button>
            </div>
          </div>
        ) : currentView === AppView.TOOL_SUCCESS ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Ready!</h2>
            <p className="text-gray-500 font-medium mb-10">Document processed successfully.</p>
            <div className="space-y-3">
              <button onClick={() => toolResultData && downloadDataUrl(toolResultData.dataUrl, toolResultData.name)} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <button onClick={proceedToSignFromTool} className="w-full bg-slate-800 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg">Add Digital Signature</button>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Home</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard documents={documents} onAction={(view) => setCurrentView(view)} onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} onDeleteDoc={handleDeleteDoc} />
            )}

            {currentView === AppView.IMAGE_TO_PDF && (
              <ImageToPdfConverter onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.MERGE_PDF && (
              <PdfMerger onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500 pb-32">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'Document View' : 'Signing Area'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                   <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload Document</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">Select PDF or Image to sign</p>
                    <label className="bg-indigo-600 text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-indigo-700 shadow-2xl shadow-indigo-100 inline-block transition-transform active:scale-95">
                      Browse Files
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-10">
                    <div className="flex flex-col items-center gap-8 px-2 overflow-y-auto scrollbar-hide">
                      {Array.from({ length: numPages }).map((_, idx) => {
                        const pageNum = idx + 1;
                        return (
                          <div key={pageNum} className="relative bg-white shadow-2xl leading-[0] border border-slate-200 rounded-sm">
                            <canvas 
                              ref={el => pageRefs.current[pageNum] = el} 
                              className="max-w-full h-auto"
                            />
                            <div className="absolute inset-0 z-20 pointer-events-none">
                              {placedSignatures.filter(s => s.pageNumber === pageNum).map(ps => (
                                <div 
                                  key={ps.id} 
                                  style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} 
                                  className="absolute z-30 cursor-move touch-none pointer-events-auto animate-pulse-once" 
                                  onMouseDown={(e) => handleDrag(ps.id, pageNum, e)} 
                                  onTouchStart={(e) => handleDrag(ps.id, pageNum, e)}
                                >
                                  <div className="relative group">
                                    <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-500/50'} p-0.5`} />
                                    {activeDoc?.status !== 'SIGNED' && (
                                      <>
                                        <button onClick={(e) => { e.stopPropagation(); setPlacedSignatures(p => p.filter(x => x.id !== ps.id)); }} className="absolute -top-4 -right-4 bg-red-500 text-white w-8 h-8 rounded-full text-xs flex items-center justify-center shadow-lg font-bold border-2 border-white z-40">✕</button>
                                        <div onMouseDown={(e) => handleResize(ps.id, pageNum, e)} onTouchStart={(e) => handleResize(ps.id, pageNum, e)} className="resize-handle absolute -bottom-4 -right-4 w-9 h-9 bg-indigo-600 border-4 border-white rounded-full cursor-nwse-resize shadow-xl flex items-center justify-center z-40">
                                          <div className="w-2.5 h-2.5 border-r-2 border-b-2 border-white rotate-45 mb-1 mr-1"></div>
                                        </div>
                                      </>
                                    )}
                                  </div>
                                </div>
                              ))}
                            </div>
                            <div className="absolute top-2 right-2 bg-black/40 text-white text-[10px] font-black px-2 py-1 rounded backdrop-blur-sm pointer-events-none">
                              Page {pageNum} / {numPages}
                            </div>
                          </div>
                        );
                      })}
                    </div>

                    <div className="fixed bottom-0 left-0 right-0 p-6 z-40 bg-white/80 backdrop-blur-md border-t border-slate-100 flex flex-col gap-4">
                       {activeDoc?.status === 'SIGNED' ? (
                         <div className="flex gap-3 max-w-lg mx-auto w-full">
                           <button onClick={handleDownload} className="flex-[2] bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
                           <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all text-[10px] uppercase tracking-widest">Share</button>
                         </div>
                       ) : (
                         <div className="max-w-lg mx-auto w-full space-y-4">
                            <div className="flex gap-4 overflow-x-auto pb-1 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-24 h-14 bg-white border-2 border-slate-100 rounded-xl flex items-center justify-center p-2 shadow-sm hover:border-indigo-300 transition-all active:scale-90 overflow-hidden">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply object-contain" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-14 h-14 bg-slate-50 text-slate-400 rounded-xl border-2 border-dashed border-slate-200 text-xl font-bold flex items-center justify-center active:bg-indigo-50 transition-colors">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 disabled:opacity-30 transition-all active:scale-95">Complete & Secure</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}

      <style>{`
        @keyframes pulse-once {
          0% { transform: scale(0.9); opacity: 0; }
          50% { transform: scale(1.05); opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
        .animate-pulse-once {
          animation: pulse-once 0.3s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';
import ImageToPdfConverter from './components/ImageToPdfConverter';
import PdfMerger from './components/PdfMerger';
import * as db from './db';

declare const jspdf: any;
declare const pdfjsLib: any;

if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [numPages, setNumPages] = useState(1);
  const [toolResultData, setToolResultData] = useState<{ dataUrl: string, name: string } | null>(null);

  const pageRefs = useRef<(HTMLCanvasElement | null)[]>([]);

  const refreshDocuments = async () => {
    try {
      const docs = await db.getAllDocs();
      setDocuments(docs);
    } catch (err) {
      console.error("Failed to refresh documents:", err);
    }
  };

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        const [docs, sigs] = await Promise.all([db.getAllDocs(), db.getAllSigs()]);
        setDocuments(docs);
        setSignatures(sigs);
      } catch (err) {
        console.error("Failed to load data from IndexedDB:", err);
      }
    };
    loadInitialData();
  }, []);

  const handleDeleteDoc = useCallback(async (id: string) => {
    try {
      await db.deleteDoc(id);
      setDocuments(prev => prev.filter(doc => doc.id !== id));
    } catch (err) {
      console.error("Failed to delete document:", err);
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
    setNumPages(1);
    setToolResultData(null);
    pageRefs.current = [];
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleToolComplete = async (dataUrl: string) => {
    setIsLoading(true);
    const toolName = currentView === AppView.IMAGE_TO_PDF ? 'Converted_Images.pdf' : 'Merged_Document.pdf';

    const newDoc: DocumentRecord = {
      id: Date.now().toString(),
      name: toolName,
      type: 'PDF',
      status: 'PENDING',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: dataUrl,
      placedSignatures: []
    };

    try {
      await db.saveDoc(newDoc);
      await refreshDocuments();
      setToolResultData({ dataUrl, name: toolName });
      setCurrentView(AppView.TOOL_SUCCESS);
    } catch (err) {
      console.error("Failed to save tool result:", err);
      alert("Document processed but could not be saved to library.");
      // Fallback: still show success screen so they can download
      setToolResultData({ dataUrl, name: toolName });
      setCurrentView(AppView.TOOL_SUCCESS);
    } finally {
      setIsLoading(false);
    }
  };

  const proceedToSignFromTool = () => {
    if (toolResultData) {
      setUploadFile(toolResultData.dataUrl);
      setCurrentView(AppView.SIGN_DOC);
    }
  };

  useEffect(() => {
    const renderAllPages = async (dataUrl: string) => {
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        setNumPages(pdf.numPages);

        setTimeout(async () => {
          for (let i = 1; i <= pdf.numPages; i++) {
            const canvas = pageRefs.current[i];
            if (!canvas) continue;
            const page = await pdf.getPage(i);
            const viewport = page.getViewport({ scale: 2 });
            const context = canvas.getContext('2d');
            if (!context) continue;
            canvas.height = viewport.height;
            canvas.width = viewport.width;
            await page.render({ canvasContext: context, viewport }).promise;
          }
        }, 150);
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data && data.startsWith('data:application/pdf')) {
      renderAllPages(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = async (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    try {
      await db.saveSig(newSign);
      setSignatures(prev => [newSign, ...prev]);
      setShowSignaturePad(false);
    } catch (err) {
      console.error("Failed to save signature:", err);
    }
  };

  const handleSignFinish = async () => {
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) return;
    setIsLoading(true);

    const isPdf = fileToUse.startsWith('data:application/pdf');
    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || (isPdf ? 'Signed_Doc.pdf' : 'Signed_Image.png'),
      type: isPdf ? 'PDF' : 'IMAGE',
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: fileToUse,
      placedSignatures: [...placedSignatures]
    };

    try {
      await db.saveDoc(newDoc);
      await refreshDocuments();
      setIsLoading(false);
      setShowSuccessScreen(true);
    } catch (err) {
      setIsLoading(false);
      console.error("Failed to save signed document:", err);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 35, y: 40, w: 25,
      pageNumber: 1
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, initialPageNum: number, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    if (e.target.closest('.resize-handle')) return;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;

      let targetPageNum = initialPageNum;
      let targetRect = pageRefs.current[initialPageNum]?.getBoundingClientRect();

      for (let i = 1; i <= numPages; i++) {
        const canvas = pageRefs.current[i];
        if (!canvas) continue;
        const rect = canvas.getBoundingClientRect();
        if (cy >= rect.top && cy <= rect.bottom) {
          targetPageNum = i;
          targetRect = rect;
          break;
        }
      }

      if (targetRect) {
        const x = Math.max(-5, Math.min(95, ((cx - targetRect.left) / targetRect.width) * 100));
        const y = Math.max(-5, Math.min(95, ((cy - targetRect.top) / targetRect.height) * 100));
        setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y, pageNumber: targetPageNum } : p));
      }
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, pageNum: number, e: any) => {
    e.stopPropagation();
    const canvas = pageRefs.current[pageNum];
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(10, Math.min(90, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const downloadDataUrl = (dataUrl: string, fileName: string) => {
    const link = document.createElement('a');
    link.href = dataUrl;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleDownload = async () => {
    setIsLoading(true);
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) {
      setIsLoading(false);
      return;
    }

    try {
      const pdfOutput = new jspdf.jsPDF({
        orientation: 'p',
        unit: 'pt',
        format: 'a4'
      });

      if (fileToUse.startsWith('data:image')) {
        const img = new Image();
        img.src = fileToUse;
        await new Promise(r => img.onload = r);
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d')!;
        canvas.width = img.width; canvas.height = img.height;
        ctx.drawImage(img, 0, 0);

        for (const s of placedSignatures) {
          const si = new Image(); si.src = s.dataUrl;
          await new Promise(r => si.onload = r);
          const sw = (canvas.width * (s.w || 25)) / 100;
          const sh = sw * (si.height / si.width);
          ctx.drawImage(si, (canvas.width * s.x)/100, (canvas.height * s.y)/100, sw, sh);
        }

        const imgPdf = new jspdf.jsPDF({ 
          orientation: canvas.width > canvas.height ? 'l' : 'p',
          format: [canvas.width, canvas.height], 
          unit: 'pt' 
        });
        imgPdf.addImage(canvas.toDataURL('image/jpeg', 0.95), 'JPEG', 0, 0, canvas.width, canvas.height);
        imgPdf.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
        setIsLoading(false);
        return;
      }

      const loadingTask = pdfjsLib.getDocument(fileToUse);
      const pdf = await loadingTask.promise;

      const offscreenCanvas = document.createElement('canvas');
      const ctx = offscreenCanvas.getContext('2d')!;

      for (let i = 1; i <= pdf.numPages; i++) {
        const page = await pdf.getPage(i);
        const baseViewport = page.getViewport({ scale: 1 });
        const renderViewport = page.getViewport({ scale: 2 });

        offscreenCanvas.width = renderViewport.width;
        offscreenCanvas.height = renderViewport.height;
        await page.render({ canvasContext: ctx, viewport: renderViewport }).promise;

        if (i > 1) {
          pdfOutput.addPage([baseViewport.width, baseViewport.height], baseViewport.width > baseViewport.height ? 'l' : 'p');
        } else {
          pdfOutput.deletePage(1);
          pdfOutput.addPage([baseViewport.width, baseViewport.height], baseViewport.width > baseViewport.height ? 'l' : 'p');
        }

        pdfOutput.addImage(offscreenCanvas.toDataURL('image/jpeg', 0.9), 'JPEG', 0, 0, baseViewport.width, baseViewport.height);

        const sigsOnPage = placedSignatures.filter(s => s.pageNumber === i);
        for (const s of sigsOnPage) {
          const si = new Image();
          si.src = s.dataUrl;
          await new Promise(r => si.onload = r);

          const sw = (baseViewport.width * (s.w || 25)) / 100;
          const sh = sw * (si.height / si.width);

          pdfOutput.addImage(s.dataUrl, 'PNG', (baseViewport.width * s.x)/100, (baseViewport.height * s.y)/100, sw, sh);
        }
      }

      pdfOutput.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
    } catch (err) {
      console.error("Critical download error:", err);
      alert("Error generating high-quality PDF. Please try a smaller file.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleShare = (platform: 'whatsapp' | 'email') => {
    const text = encodeURIComponent(`Hi, I have signed the document: ${activeDoc?.name}.`);
    if (platform === 'whatsapp') window.open(`https://wa.me/?text=${text}`, '_blank');
    else window.location.href = `mailto:?subject=Signed Document&body=${text}`;
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-100 transition-transform active:scale-95">S</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignEase</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest text-center">Digital Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowSignaturePad(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/95 z-[70] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-16 h-16 border-[6px] border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-900 tracking-tight text-lg">Processing...</p>
            <p className="text-sm text-slate-500 font-medium">Please wait, ensuring maximum quality.</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Securely Signed</h2>
            <p className="text-gray-500 font-medium mb-10">Your document is ready for download.</p>
            <div className="space-y-3">
              <button onClick={handleDownload} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                 <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">WhatsApp</button>
                 <button onClick={() => handleShare('email')} className="flex-1 bg-slate-800 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">Email</button>
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Dashboard</button>
            </div>
          </div>
        ) : currentView === AppView.TOOL_SUCCESS ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Ready!</h2>
            <p className="text-gray-500 font-medium mb-10">Document processed and saved to your library.</p>
            <div className="space-y-3">
              <button onClick={() => toolResultData && downloadDataUrl(toolResultData.dataUrl, toolResultData.name)} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <button onClick={proceedToSignFromTool} className="w-full bg-slate-800 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg">Add Digital Signature</button>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Go to Dashboard</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard documents={documents} onAction={(view) => setCurrentView(view)} onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} onDeleteDoc={handleDeleteDoc} />
            )}

            {currentView === AppView.IMAGE_TO_PDF && (
              <ImageToPdfConverter onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.MERGE_PDF && (
              <PdfMerger onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500 pb-32">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'Document View' : 'Signing Area'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                   <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload Document</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">Select PDF or Image to sign</p>
                    <label className="bg-indigo-600 text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-indigo-700 shadow-2xl shadow-indigo-100 inline-block transition-transform active:scale-95">
                      Browse Files
                      <input type="file" className="hidden" accept=".pdf,image/*" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-10">
                    <div className="flex flex-col items-center gap-8 px-2 overflow-y-auto scrollbar-hide">
                      {Array.from({ length: numPages }).map((_, idx) => {
                        const pageNum = idx + 1;
                        return (
                          <div key={pageNum} className="relative bg-white shadow-2xl leading-[0] border border-slate-200 rounded-sm">
                            <canvas 
                              ref={el => pageRefs.current[pageNum] = el} 
                              className="max-w-full h-auto"
                            />
                            <div className="absolute inset-0 z-20 pointer-events-none">
                              {placedSignatures.filter(s => s.pageNumber === pageNum).map(ps => (
                                <div 
                                  key={ps.id} 
                                  style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} 
                                  className="absolute z-30 cursor-move touch-none pointer-events-auto animate-pulse-once" 
                                  onMouseDown={(e) => handleDrag(ps.id, pageNum, e)} 
                                  onTouchStart={(e) => handleDrag(ps.id, pageNum, e)}
                                >
                                  <div className="relative group">
                                    <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-500/50'} p-0.5`} />
                                    {activeDoc?.status !== 'SIGNED' && (
                                      <>
                                        <button onClick={(e) => { e.stopPropagation(); setPlacedSignatures(p => p.filter(x => x.id !== ps.id)); }} className="absolute -top-4 -right-4 bg-red-500 text-white w-8 h-8 rounded-full text-xs flex items-center justify-center shadow-lg font-bold border-2 border-white z-40">✕</button>
                                        <div onMouseDown={(e) => handleResize(ps.id, pageNum, e)} onTouchStart={(e) => handleResize(ps.id, pageNum, e)} className="resize-handle absolute -bottom-4 -right-4 w-9 h-9 bg-indigo-600 border-4 border-white rounded-full cursor-nwse-resize shadow-xl flex items-center justify-center z-40">
                                          <div className="w-2.5 h-2.5 border-r-2 border-b-2 border-white rotate-45 mb-1 mr-1"></div>
                                        </div>
                                      </>
                                    )}
                                  </div>
                                </div>
                              ))}
                            </div>
                            <div className="absolute top-2 right-2 bg-black/40 text-white text-[10px] font-black px-2 py-1 rounded backdrop-blur-sm pointer-events-none">
                              Page {pageNum} / {numPages}
                            </div>
                          </div>
                        );
                      })}
                    </div>

                    <div className="fixed bottom-0 left-0 right-0 p-6 z-40 bg-white/80 backdrop-blur-md border-t border-slate-100 flex flex-col gap-4">
                       {activeDoc?.status === 'SIGNED' ? (
                         <div className="flex gap-3 max-w-lg mx-auto w-full">
                           <button onClick={handleDownload} className="flex-[2] bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
                           <button onClick={() => handleShare('whatsapp')} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all text-[10px] uppercase tracking-widest">Share</button>
                         </div>
                       ) : (
                         <div className="max-w-lg mx-auto w-full space-y-4">
                            <div className="flex gap-4 overflow-x-auto pb-1 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-24 h-14 bg-white border-2 border-slate-100 rounded-xl flex items-center justify-center p-2 shadow-sm hover:border-indigo-300 transition-all active:scale-90 overflow-hidden">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply object-contain" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-14 h-14 bg-slate-50 text-slate-400 rounded-xl border-2 border-dashed border-slate-200 text-xl font-bold flex items-center justify-center active:bg-indigo-50 transition-colors">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 disabled:opacity-30 transition-all active:scale-95">Complete & Secure</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}

      <style>{`
        @keyframes pulse-once {
          0% { transform: scale(0.9); opacity: 0; }
          50% { transform: scale(1.05); opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
        .animate-pulse-once {
          animation: pulse-once 0.3s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

export enum AppView {
  DASHBOARD = 'DASHBOARD',
  SIGN_DOC = 'SIGN_DOC',
  VIEW_DOC = 'VIEW_DOC',
  IMAGE_TO_PDF = 'IMAGE_TO_PDF',
  MERGE_PDF = 'MERGE_PDF',
  TOOL_SUCCESS = 'TOOL_SUCCESS',
  COMPRESS_PDF = 'COMPRESS_PDF'
}

export interface PlacedSignature {
  id: string;
  dataUrl: string;
  x: number; // percentage 0-100
  y: number; // percentage 0-100
  w?: number; // width percentage 5-100
  pageNumber: number; // The 1-based page index
}

export interface UserSignature {
  id: string;
  dataUrl: string;
  label: string;
  createdAt: string;
}

export interface DocumentRecord {
  id: string;
  name: string;
  type: 'PDF' | 'IMAGE';
  status: 'SIGNED' | 'PENDING';
  date: string;
  fileData?: string; // base64 data
  placedSignatures?: PlacedSignature[];
}

import React, { useState, useMemo } from 'react';
import { DocumentRecord, AppView } from '../types';

interface DashboardProps {
  documents: DocumentRecord[];
  onAction: (view: AppView) => void;
  onViewDoc: (doc: DocumentRecord) => void;
  onDeleteDoc: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ documents, onAction, onViewDoc, onDeleteDoc }) => {
  const [filter, setFilter] = useState<'ALL' | 'SIGNED'>('ALL');
  const [docToDelete, setDocToDelete] = useState<string | null>(null);

  const filteredDocs = useMemo(() => {
    if (filter === 'ALL') return documents;
    return documents.filter(d => d.status === filter);
  }, [documents, filter]);

  const confirmDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setDocToDelete(id);
  };

  const handleFinalDelete = () => {
    if (docToDelete) {
      onDeleteDoc(docToDelete);
      setDocToDelete(null);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {docToDelete && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 p-6 backdrop-blur-md animate-in fade-in duration-200">
          <div className="w-full max-sm bg-white rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="w-20 h-20 bg-red-50 text-red-500 rounded-full flex items-center justify-center text-4xl mx-auto mb-6 shadow-inner">🗑️</div>
            <h3 className="text-2xl font-black text-gray-900 text-center mb-2 tracking-tight">Delete this?</h3>
            <p className="text-slate-500 text-center text-sm font-medium leading-relaxed mb-10 px-2">
              This will permanently remove the document from your local storage.
            </p>
            <div className="flex flex-col gap-3">
              <button onClick={handleFinalDelete} className="w-full py-5 bg-red-500 text-white font-black rounded-2xl hover:bg-red-600 transition-all active:scale-95 shadow-xl shadow-red-100">Delete Forever</button>
              <button onClick={() => setDocToDelete(null)} className="w-full py-5 bg-slate-50 text-slate-600 font-bold rounded-2xl hover:bg-slate-100 transition-all">Cancel</button>
            </div>
          </div>
        </div>
      )}

      <div className="bg-indigo-600 p-10 rounded-[3rem] text-white shadow-2xl shadow-indigo-100 relative overflow-hidden group">
        <div className="relative z-10">
          <p className="text-indigo-200 text-[10px] font-black uppercase tracking-[0.2em] mb-2 opacity-80">Workspace Dashboard</p>
          <h2 className="text-4xl font-black mb-8 leading-tight tracking-tight">E-Sign Anything,<br/>Anywhere.</h2>
          <div className="flex gap-4">
             <div className="bg-white/10 backdrop-blur-xl px-6 py-3 rounded-2xl border border-white/20 shadow-inner">
                <span className="block text-3xl font-black">{documents.length}</span>
                <span className="text-[9px] uppercase font-black opacity-60 tracking-widest">Total Files</span>
             </div>
             <button onClick={() => onAction(AppView.SIGN_DOC)} className="bg-white text-indigo-600 px-8 py-4 rounded-2xl font-black hover:shadow-2xl transition-all active:scale-95 flex items-center gap-2 group-hover:bg-indigo-50">
                <span className="text-xl">+</span> Sign New
             </button>
          </div>
        </div>
        <div className="absolute -right-20 -top-20 w-80 h-80 bg-white/10 rounded-full blur-[100px] pointer-events-none"></div>
        <div className="absolute -left-10 -bottom-10 w-40 h-40 bg-indigo-400/20 rounded-full blur-[60px] pointer-events-none"></div>
      </div>

      <div className="space-y-4">
        <h3 className="text-lg font-black text-slate-800 tracking-tight px-2">Quick Tools</h3>
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4 px-1">
          <button 
            onClick={() => onAction(AppView.IMAGE_TO_PDF)}
            className="flex flex-col items-center justify-center gap-3 p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm active:scale-95 transition-all group"
          >
            <div className="w-12 h-12 bg-amber-50 text-amber-500 rounded-2xl flex items-center justify-center text-xl shadow-sm border border-amber-100 group-hover:bg-amber-100">📸</div>
            <span className="text-[10px] font-black uppercase tracking-widest text-slate-600">Images to PDF</span>
          </button>
          <button 
            onClick={() => onAction(AppView.MERGE_PDF)}
            className="flex flex-col items-center justify-center gap-3 p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm active:scale-95 transition-all group"
          >
            <div className="w-12 h-12 bg-indigo-50 text-indigo-500 rounded-2xl flex items-center justify-center text-xl shadow-sm border border-indigo-100 group-hover:bg-indigo-100">📑</div>
            <span className="text-[10px] font-black uppercase tracking-widest text-slate-600">Merge PDFs</span>
          </button>
          <button 
            onClick={() => onAction(AppView.COMPRESS_PDF)}
            className="flex flex-col items-center justify-center gap-3 p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm active:scale-95 transition-all group"
          >
            <div className="w-12 h-12 bg-emerald-50 text-emerald-500 rounded-2xl flex items-center justify-center text-xl shadow-sm border border-emerald-100 group-hover:bg-emerald-100">🗜️</div>
            <span className="text-[10px] font-black uppercase tracking-widest text-slate-600">Reduce Size</span>
          </button>
        </div>
      </div>

      <div className="flex items-center justify-between px-2">
         <h3 className="text-lg font-black text-slate-800 tracking-tight">Recent Activity</h3>
         <div className="flex bg-slate-100 p-1.5 rounded-2xl shadow-inner border border-slate-200/50">
            {(['ALL', 'SIGNED'] as const).map(f => (
