            </div>
            <div className="flex items-center gap-3">
              <span className={`text-[8px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest shadow-sm ${doc.status === 'SIGNED' ? 'bg-emerald-500 text-white' : 'bg-amber-100 text-amber-700'}`}>
