             <p className="text-slate-400 text-sm font-black tracking-tight mb-8">No documents in your storage.</p>
             <button onClick={() => onAction(AppView.SIGN_DOC)} className="px-10 py-4 bg-indigo-50 text-indigo-600 text-xs font-black uppercase tracking-widest rounded-2xl hover:bg-indigo-100 transition-colors shadow-sm shadow-indigo-50">Create New Doc</button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';

declare const jspdf: any;
declare const pdfjsLib: any;

interface PdfCompressorProps {
  initialFile?: string | null;
  onComplete: (dataUrl: string) => void;
  onCancel: () => void;
}

const PdfCompressor: React.FC<PdfCompressorProps> = ({ initialFile, onComplete, onCancel }) => {
  const [fileData, setFileData] = useState<string | null>(initialFile || null);
  const [fileName, setFileName] = useState<string>("document.pdf");
  const [isProcessing, setIsProcessing] = useState(false);
  const [reductionLevel, setReductionLevel] = useState<25 | 50 | 75>(50);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setFileName(file.name);
      const reader = new FileReader();
      reader.onload = (re) => {
        setFileData(re.target?.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const compressPdf = async () => {
    if (!fileData) return;
    setIsProcessing(true);

    try {
      // Quality mapping: 25% reduction -> 0.8 quality, 50% -> 0.5, 75% -> 0.2
      const qualityMap = { 25: 0.8, 50: 0.5, 75: 0.25 };
      const quality = qualityMap[reductionLevel];

      const loadingTask = pdfjsLib.getDocument(fileData);
      const pdf = await loadingTask.promise;
      const finalPdf = new jspdf.jsPDF();

      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d')!;

      for (let i = 1; i <= pdf.numPages; i++) {
        const page = await pdf.getPage(i);
        // We use a moderate scale (1.5x) to maintain decent resolution before JPEG compression
        const viewport = page.getViewport({ scale: 1.5 });
        canvas.width = viewport.width;
        canvas.height = viewport.height;

        await page.render({ canvasContext: ctx, viewport }).promise;

        if (i > 1) finalPdf.addPage();

        const pdfWidth = finalPdf.internal.pageSize.getWidth();
        const pdfHeight = finalPdf.internal.pageSize.getHeight();
        const ratio = Math.min(pdfWidth / canvas.width, pdfHeight / canvas.height);
        const w = canvas.width * ratio;
        const h = canvas.height * ratio;
        const x = (pdfWidth - w) / 2;
        const y = (pdfHeight - h) / 2;

        // The key compression happens here with the second argument of toDataURL
        finalPdf.addImage(canvas.toDataURL('image/jpeg', quality), 'JPEG', x, y, w, h);
      }

      onComplete(finalPdf.output('datauristring'));
    } catch (err) {
      console.error(err);
      alert("Failed to compress PDF");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-300 pb-32">
      <div className="flex justify-between items-center px-2">
        <div>
          <h2 className="text-2xl font-black text-gray-900 tracking-tight">PDF Compressor</h2>
          <p className="text-xs font-bold text-emerald-500 uppercase tracking-widest mt-1">Bharat Lite</p>
        </div>
        <button onClick={onCancel} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900">✕</button>
      </div>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 p-8 shadow-sm">
        {!fileData ? (
          <div className="text-center py-12">
            <div className="w-20 h-20 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-3xl mx-auto mb-6">🗜️</div>
            <p className="text-slate-500 font-black mb-10">Select a PDF to reduce its size</p>
            <label className="bg-emerald-600 text-white px-10 py-5 rounded-2xl font-black cursor-pointer shadow-xl shadow-emerald-100 active:scale-95 transition-all inline-block">
              Choose PDF
              <input type="file" accept=".pdf" className="hidden" onChange={handleFileSelect} />
            </label>
          </div>
        ) : (
          <div className="space-y-8">
            <div className="bg-slate-50 p-6 rounded-3xl border border-slate-100 flex items-center gap-4">
              <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-2xl shadow-sm border border-slate-100">📄</div>
              <div className="overflow-hidden">
                <p className="text-sm font-black text-slate-800 truncate">{fileName}</p>
                <button onClick={() => setFileData(null)} className="text-[10px] font-bold text-red-500 uppercase tracking-widest">Change File</button>
              </div>
            </div>

            <div className="space-y-4">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Reduction Level</label>
              <div className="grid grid-cols-3 gap-3">
                {[25, 50, 75].map((level) => (
                  <button
                    key={level}
                    onClick={() => setReductionLevel(level as any)}
                    className={`p-4 rounded-2xl border transition-all flex flex-col items-center gap-1 ${
                      reductionLevel === level 
                      ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg shadow-indigo-100' 
                      : 'bg-white border-slate-100 text-slate-600'
                    }`}
                  >
                    <span className="text-lg font-black">{level}%</span>
                    <span className="text-[8px] font-black uppercase tracking-widest opacity-80">
                      {level === 25 ? 'Light' : level === 50 ? 'Balanced' : 'Strong'}
                    </span>
                  </button>
                ))}
              </div>
              <p className="text-[10px] text-slate-400 font-medium italic text-center px-4 pt-2">
                Higher percentage means smaller file size but lower image quality.
              </p>
            </div>

            <div className="pt-6 border-t border-slate-50">
               <button 
                onClick={compressPdf} 
                disabled={isProcessing}
                className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 disabled:opacity-50 active:scale-95 transition-all"
               >
                {isProcessing ? 'Optimizing...' : `Apply ${reductionLevel}% Optimization`}
               </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default PdfCompressor;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';
import ImageToPdfConverter from './components/ImageToPdfConverter';
import PdfMerger from './components/PdfMerger';
import PdfCompressor from './components/PdfCompressor';
import * as db from './db';

declare const jspdf: any;
declare const pdfjsLib: any;

if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [numPages, setNumPages] = useState(1);
  const [toolResultData, setToolResultData] = useState<{ dataUrl: string, name: string } | null>(null);

  const pageRefs = useRef<(HTMLCanvasElement | null)[]>([]);

  const refreshDocuments = async () => {
    try {
      const docs = await db.getAllDocs();
      setDocuments(docs);
    } catch (err) {
      console.error("Failed to refresh documents:", err);
    }
  };

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        const [docs, sigs] = await Promise.all([db.getAllDocs(), db.getAllSigs()]);
        setDocuments(docs);
        setSignatures(sigs);
      } catch (err) {
        console.error("Failed to load data from IndexedDB:", err);
      }
    };
    loadInitialData();
  }, []);

  const handleDeleteDoc = useCallback(async (id: string) => {
    try {
      await db.deleteDoc(id);
      setDocuments(prev => prev.filter(doc => doc.id !== id));
    } catch (err) {
      console.error("Failed to delete document:", err);
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
    setNumPages(1);
    setToolResultData(null);
    pageRefs.current = [];
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleToolComplete = async (dataUrl: string) => {
    setIsLoading(true);
    let toolName = 'Processed_Document.pdf';
    if (currentView === AppView.IMAGE_TO_PDF) toolName = 'Converted_Images.pdf';
    else if (currentView === AppView.MERGE_PDF) toolName = 'Merged_Document.pdf';
    else if (currentView === AppView.COMPRESS_PDF) toolName = 'Optimized_Document.pdf';

    const newDoc: DocumentRecord = {
      id: Date.now().toString(),
      name: toolName,
      type: 'PDF',
      status: 'PENDING',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: dataUrl,
      placedSignatures: []
    };

    try {
      await db.saveDoc(newDoc);
      await refreshDocuments();
      setToolResultData({ dataUrl, name: toolName });
      setCurrentView(AppView.TOOL_SUCCESS);
    } catch (err) {
      console.error("Failed to save tool result:", err);
      alert("Document processed but could not be saved to library.");
      setToolResultData({ dataUrl, name: toolName });
      setCurrentView(AppView.TOOL_SUCCESS);
    } finally {
      setIsLoading(false);
    }
  };

  const proceedToSignFromTool = () => {
    if (toolResultData) {
      setUploadFile(toolResultData.dataUrl);
      setCurrentView(AppView.SIGN_DOC);
    }
  };

  const startCompressingFromTool = () => {
    if (toolResultData) {
      setUploadFile(toolResultData.dataUrl);
      setCurrentView(AppView.COMPRESS_PDF);
    }
  };

  useEffect(() => {
    const renderAllPages = async (dataUrl: string) => {
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        setNumPages(pdf.numPages);

        setTimeout(async () => {
          for (let i = 1; i <= pdf.numPages; i++) {
            const canvas = pageRefs.current[i];
            if (!canvas) continue;
            const page = await pdf.getPage(i);
            const viewport = page.getViewport({ scale: 2 });
            const context = canvas.getContext('2d');
            if (!context) continue;
            canvas.height = viewport.height;
            canvas.width = viewport.width;
            await page.render({ canvasContext: context, viewport }).promise;
          }
        }, 150);
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data && data.startsWith('data:application/pdf')) {
      renderAllPages(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = async (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    try {
      await db.saveSig(newSign);
      setSignatures(prev => [newSign, ...prev]);
      setShowSignaturePad(false);
    } catch (err) {
      console.error("Failed to save signature:", err);
    }
  };

  const handleSignFinish = async () => {
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) return;
    setIsLoading(true);

    const isPdf = fileToUse.startsWith('data:application/pdf');
    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || (isPdf ? 'Signed_Doc.pdf' : 'Signed_Image.png'),
      type: isPdf ? 'PDF' : 'IMAGE',
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: fileToUse,
      placedSignatures: [...placedSignatures]
    };

    try {
      await db.saveDoc(newDoc);
      await refreshDocuments();
      setIsLoading(false);
      setShowSuccessScreen(true);
    } catch (err) {
      setIsLoading(false);
      console.error("Failed to save signed document:", err);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 35, y: 40, w: 25,
      pageNumber: 1
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, initialPageNum: number, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    if (e.target.closest('.resize-handle')) return;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;

      let targetPageNum = initialPageNum;
      let targetRect = pageRefs.current[initialPageNum]?.getBoundingClientRect();

      for (let i = 1; i <= numPages; i++) {
        const canvas = pageRefs.current[i];
        if (!canvas) continue;
        const rect = canvas.getBoundingClientRect();
        if (cy >= rect.top && cy <= rect.bottom) {
          targetPageNum = i;
          targetRect = rect;
          break;
        }
      }

      if (targetRect) {
        const x = Math.max(-5, Math.min(95, ((cx - targetRect.left) / targetRect.width) * 100));
        const y = Math.max(-5, Math.min(95, ((cy - targetRect.top) / targetRect.height) * 100));
        setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y, pageNumber: targetPageNum } : p));
      }
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, pageNum: number, e: any) => {
    e.stopPropagation();
    const canvas = pageRefs.current[pageNum];
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(10, Math.min(90, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const downloadDataUrl = (dataUrl: string, fileName: string) => {
    const link = document.createElement('a');
    link.href = dataUrl;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleDownload = async () => {
    setIsLoading(true);
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) {
      setIsLoading(false);
      return;
    }

    try {
      const pdfOutput = new jspdf.jsPDF({
        orientation: 'p',
        unit: 'pt',
        format: 'a4'
      });

      if (fileToUse.startsWith('data:image')) {
        const img = new Image();
        img.src = fileToUse;
        await new Promise(r => img.onload = r);
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d')!;
        canvas.width = img.width; canvas.height = img.height;
        ctx.drawImage(img, 0, 0);

        for (const s of placedSignatures) {
          const si = new Image(); si.src = s.dataUrl;
          await new Promise(r => si.onload = r);
          const sw = (canvas.width * (s.w || 25)) / 100;
          const sh = sw * (si.height / si.width);
          ctx.drawImage(si, (canvas.width * s.x)/100, (canvas.height * s.y)/100, sw, sh);
        }

        const imgPdf = new jspdf.jsPDF({ 
          orientation: canvas.width > canvas.height ? 'l' : 'p',
          format: [canvas.width, canvas.height], 
          unit: 'pt' 
        });
        imgPdf.addImage(canvas.toDataURL('image/jpeg', 0.95), 'JPEG', 0, 0, canvas.width, canvas.height);
        imgPdf.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
        setIsLoading(false);
        return;
      }

      const loadingTask = pdfjsLib.getDocument(fileToUse);
      const pdf = await loadingTask.promise;

      const offscreenCanvas = document.createElement('canvas');
      const ctx = offscreenCanvas.getContext('2d')!;

      for (let i = 1; i <= pdf.numPages; i++) {
        const page = await pdf.getPage(i);
        const baseViewport = page.getViewport({ scale: 1 });
        const renderViewport = page.getViewport({ scale: 2 });

        offscreenCanvas.width = renderViewport.width;
        offscreenCanvas.height = renderViewport.height;
        await page.render({ canvasContext: ctx, viewport: renderViewport }).promise;

        if (i > 1) {
          pdfOutput.addPage([baseViewport.width, baseViewport.height], baseViewport.width > baseViewport.height ? 'l' : 'p');
        } else {
          pdfOutput.deletePage(1);
          pdfOutput.addPage([baseViewport.width, baseViewport.height], baseViewport.width > baseViewport.height ? 'l' : 'p');
        }

        pdfOutput.addImage(offscreenCanvas.toDataURL('image/jpeg', 0.9), 'JPEG', 0, 0, baseViewport.width, baseViewport.height);

        const sigsOnPage = placedSignatures.filter(s => s.pageNumber === i);
        for (const s of sigsOnPage) {
          const si = new Image();
          si.src = s.dataUrl;
          await new Promise(r => si.onload = r);

          const sw = (baseViewport.width * (s.w || 25)) / 100;
          const sh = sw * (si.height / si.width);

          pdfOutput.addImage(s.dataUrl, 'PNG', (baseViewport.width * s.x)/100, (baseViewport.height * s.y)/100, sw, sh);
        }
      }

      pdfOutput.save(`${activeDoc?.name || 'Signed_Doc'}.pdf`);
    } catch (err) {
      console.error("Critical download error:", err);
      alert("Error generating high-quality PDF. Please try a smaller file.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleShare = (platform: 'whatsapp' | 'email') => {
    const text = encodeURIComponent(`Hi, I have signed the document: ${activeDoc?.name}.`);
    if (platform === 'whatsapp') window.open(`https://wa.me/?text=${text}`, '_blank');
    else window.location.href = `mailto:?subject=Signed Document&body=${text}`;
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-100 transition-transform active:scale-95">S</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignEase</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest text-center">Digital Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowSignaturePad(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/95 z-[70] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-16 h-16 border-[6px] border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-900 tracking-tight text-lg">Processing...</p>
            <p className="text-sm text-slate-500 font-medium">Please wait, ensuring maximum quality.</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
