            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Ready!</h2>
            <p className="text-gray-500 font-medium mb-10">Document processed and saved to your library.</p>
            <div className="space-y-3">
              <button onClick={() => toolResultData && downloadDataUrl(toolResultData.dataUrl, toolResultData.name)} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                <button onClick={proceedToSignFromTool} className="flex-1 bg-slate-800 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg text-xs">Add Signature</button>
                <button onClick={startCompressingFromTool} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg text-xs">Compress PDF</button>
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Go to Dashboard</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard documents={documents} onAction={(view) => setCurrentView(view)} onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} onDeleteDoc={handleDeleteDoc} />
            )}

            {currentView === AppView.IMAGE_TO_PDF && (
              <ImageToPdfConverter onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.MERGE_PDF && (
              <PdfMerger onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.COMPRESS_PDF && (
              <PdfCompressor initialFile={uploadFile} onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
