          >
            <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center text-lg shadow-sm border border-indigo-100 group-hover:bg-indigo-100">🏠</div>
            <span className="text-[9px] font-black uppercase tracking-widest text-slate-600">Rent</span>
