          <button 
            onClick={() => onAction(AppView.COMPRESS_PDF)}
            className="flex flex-col items-center justify-center gap-3 p-5 bg-white rounded-[2rem] border border-slate-100 shadow-sm active:scale-95 transition-all group"
          >
            <div className="w-10 h-10 bg-emerald-50 text-emerald-500 rounded-xl flex items-center justify-center text-lg shadow-sm border border-emerald-100 group-hover:bg-emerald-100">🗜️</div>
            <span className="text-[9px] font-black uppercase tracking-widest text-slate-600">Lite</span>
          </button>
        </div>
      </div>

      <div className="flex items-center justify-between px-2">
         <h3 className="text-lg font-black text-slate-800 tracking-tight">Recent Activity</h3>
         <div className="flex bg-slate-100 p-1.5 rounded-2xl shadow-inner border border-slate-200/50">
            {(['ALL', 'SIGNED'] as const).map(f => (
              <button key={f} onClick={() => setFilter(f)} className={`text-[9px] px-5 py-2 rounded-xl font-black transition-all ${filter === f ? 'bg-white text-indigo-600 shadow-md border border-slate-100' : 'text-slate-400 hover:text-slate-600'}`}>
                {f}
