      <div className="space-y-4 pb-20">
        {filteredDocs.length > 0 ? filteredDocs.map((doc, idx) => (
          <div key={doc.id} onClick={() => onViewDoc(doc)} className="bg-white p-5 rounded-[2rem] border border-slate-100 shadow-sm flex items-center justify-between active:bg-indigo-50/30 transition-all active:scale-[0.98] animate-in fade-in slide-in-from-bottom-4 duration-500" style={{ animationDelay: `${idx * 80}ms` }}>
            <div className="flex items-center gap-5">
              <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-sm ${doc.type === 'PDF' ? 'bg-red-50 text-red-500 border border-red-100' : 'bg-blue-50 text-blue-500 border border-blue-100'}`}>
