import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';
import ProfileMenu from './components/ProfileMenu';
import RentReceiptCreator from './components/RentReceiptCreator';
import ImageToPdfConverter from './components/ImageToPdfConverter';
import PdfMerger from './components/PdfMerger';
import PdfCompressor from './components/PdfCompressor';
import * as db from './db';

declare const jspdf: any;
declare const pdfjsLib: any;

if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [numPages, setNumPages] = useState(1);
  const [toolResultData, setToolResultData] = useState<{ dataUrl: string, name: string } | null>(null);

  const pageRefs = useRef<(HTMLCanvasElement | null)[]>([]);

  const refreshDocuments = async () => {
    try {
      const docs = await db.getAllDocs();
      setDocuments(docs);
    } catch (err) {
      console.error("Failed to refresh documents:", err);
    }
  };

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        const [docs, sigs] = await Promise.all([db.getAllDocs(), db.getAllSigs()]);
        setDocuments(docs);
        setSignatures(sigs);
      } catch (err) {
        console.error("Failed to load data from IndexedDB:", err);
      }
    };
    loadInitialData();
  }, []);

  const handleDeleteDoc = useCallback(async (id: string) => {
    try {
      await db.deleteDoc(id);
      setDocuments(prev => prev.filter(doc => doc.id !== id));
    } catch (err) {
      console.error("Failed to delete document:", err);
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
    setNumPages(1);
    setToolResultData(null);
    pageRefs.current = [];
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.type !== 'application/pdf') {
        alert("SignEase India currently only supports PDF documents for secure digital signatures.");
        return;
      }
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleReceiptGenerate = async (data: any) => {
    setIsLoading(true);
    const pdf = new jspdf.jsPDF();
    pdf.setFontSize(22);
    pdf.text("RENT RECEIPT", 105, 30, { align: "center" });
    pdf.setFontSize(12);
    pdf.text(`Date: ${new Date().toLocaleDateString('en-IN')}`, 20, 50);
    pdf.text(`Received from Mr./Ms. ${data.tenantName}`, 20, 70);
    pdf.text(`Sum of Rupees ${data.rentAmount} only`, 20, 80);
    pdf.text(`Towards Rent of Property: ${data.address}`, 20, 90);
    pdf.text(`For the month of: ${data.month}`, 20, 100);
    pdf.text("Landlord Signature:", 20, 140);
    pdf.text(`Landlord Name: ${data.landlordName}`, 20, 170);
    if (data.panNumber) pdf.text(`Landlord PAN: ${data.panNumber}`, 20, 180);

    const dataUrl = pdf.output('datauristring');
    handleToolComplete(dataUrl, `Rent_Receipt_${data.month.replace(/\s/g, '_')}.pdf`);
  };

  const handleToolComplete = async (dataUrl: string, customName?: string) => {
    setIsLoading(true);
    let toolName = customName || 'Processed_Document.pdf';
    if (!customName) {
        if (currentView === AppView.IMAGE_TO_PDF) toolName = 'Converted_Images.pdf';
        else if (currentView === AppView.MERGE_PDF) toolName = 'Merged_Document.pdf';
        else if (currentView === AppView.COMPRESS_PDF) toolName = 'Optimized_Document.pdf';
    }

    const newDoc: DocumentRecord = {
      id: Date.now().toString(),
      name: toolName,
      type: 'PDF',
      status: 'PENDING',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: dataUrl,
      placedSignatures: []
    };

    try {
      await db.saveDoc(newDoc);
      await refreshDocuments();
      setToolResultData({ dataUrl, name: toolName });
      setCurrentView(AppView.TOOL_SUCCESS);
    } catch (err) {
      console.error("Failed to save tool result:", err);
      setToolResultData({ dataUrl, name: toolName });
      setCurrentView(AppView.TOOL_SUCCESS);
    } finally {
      setIsLoading(false);
    }
  };

  const proceedToSignFromTool = () => {
    if (toolResultData) {
      setUploadFile(toolResultData.dataUrl);
      setCurrentView(AppView.SIGN_DOC);
    }
  };

  const startCompressingFromTool = () => {
    if (toolResultData) {
      setUploadFile(toolResultData.dataUrl);
      setCurrentView(AppView.COMPRESS_PDF);
    }
  };

  useEffect(() => {
    const renderAllPages = async (dataUrl: string) => {
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        setNumPages(pdf.numPages);

        setTimeout(async () => {
          for (let i = 1; i <= pdf.numPages; i++) {
            const canvas = pageRefs.current[i];
            if (!canvas) continue;
            const page = await pdf.getPage(i);
            const viewport = page.getViewport({ scale: 2 });
            const context = canvas.getContext('2d');
            if (!context) continue;
            canvas.height = viewport.height;
            canvas.width = viewport.width;
            await page.render({ canvasContext: context, viewport }).promise;
          }
        }, 150);
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data && data.startsWith('data:application/pdf')) {
      renderAllPages(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = async (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    try {
      await db.saveSig(newSign);
      setSignatures(prev => [newSign, ...prev]);
      setShowSignaturePad(false);
    } catch (err) {
      console.error("Failed to save signature:", err);
    }
  };

  const handleSignFinish = async () => {
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) return;
    setIsLoading(true);

    const isPdf = fileToUse.startsWith('data:application/pdf');
    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || 'Signed_Doc.pdf',
      type: 'PDF',
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: fileToUse,
      placedSignatures: [...placedSignatures]
    };

    try {
      await db.saveDoc(newDoc);
      await refreshDocuments();
      setActiveDoc(newDoc);
      setIsLoading(false);
      setShowSuccessScreen(true);
    } catch (err) {
      setIsLoading(false);
      console.error("Failed to save signed document:", err);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 35, y: 40, w: 25,
      pageNumber: 1
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, initialPageNum: number, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    if (e.target.closest('.resize-handle')) return;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;

      let targetPageNum = initialPageNum;
      let targetRect = pageRefs.current[initialPageNum]?.getBoundingClientRect();

      for (let i = 1; i <= numPages; i++) {
        const canvas = pageRefs.current[i];
        if (!canvas) continue;
        const rect = canvas.getBoundingClientRect();
        if (cy >= rect.top && cy <= rect.bottom) {
          targetPageNum = i;
          targetRect = rect;
          break;
        }
      }

      if (targetRect) {
        const x = Math.max(-5, Math.min(95, ((cx - targetRect.left) / targetRect.width) * 100));
        const y = Math.max(-5, Math.min(95, ((cy - targetRect.top) / targetRect.height) * 100));
        setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y, pageNumber: targetPageNum } : p));
      }
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, pageNum: number, e: any) => {
    e.stopPropagation();
    const canvas = pageRefs.current[pageNum];
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(10, Math.min(90, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const downloadDataUrl = (dataUrl: string, fileName: string) => {
    const link = document.createElement('a');
    link.href = dataUrl;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Helper to generate the final PDF Blob with signatures burnt in
  const generateProcessedBlob = async (doc: DocumentRecord): Promise<Blob | null> => {
    const fileToUse = doc.fileData;
    if (!fileToUse) return null;

    const docPlacedSigs = doc.placedSignatures || [];

    // PDF specific logic
    const pdfOutput = new jspdf.jsPDF({
      orientation: 'p',
      unit: 'pt',
      format: 'a4'
    });

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;

    const loadingTask = pdfjsLib.getDocument(fileToUse);
    const pdf = await loadingTask.promise;

    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const baseViewport = page.getViewport({ scale: 1 });
      const renderViewport = page.getViewport({ scale: 2 });

      canvas.width = renderViewport.width;
      canvas.height = renderViewport.height;
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      await page.render({ canvasContext: ctx, viewport: renderViewport }).promise;

      const orientation = baseViewport.width > baseViewport.height ? 'l' : 'p';
      if (i === 1) {
        pdfOutput.deletePage(1);
      }
      pdfOutput.addPage([baseViewport.width, baseViewport.height], orientation);

      pdfOutput.addImage(canvas.toDataURL('image/jpeg', 0.9), 'JPEG', 0, 0, baseViewport.width, baseViewport.height);

      const sigsOnPage = docPlacedSigs.filter(s => s.pageNumber === i);
      for (const s of sigsOnPage) {
        pdfOutput.addImage(s.dataUrl, 'PNG', (baseViewport.width * s.x)/100, (baseViewport.height * s.y)/100, (baseViewport.width * (s.w || 25)) / 100, ((baseViewport.width * (s.w || 25)) / 100) * 0.5);
      }
    }

    return pdfOutput.output('blob');
  };

  const processAndDownloadDoc = async (doc: DocumentRecord) => {
    setIsLoading(true);
    try {
      const blob = await generateProcessedBlob(doc);
      if (blob) {
        const url = URL.createObjectURL(blob);
        downloadDataUrl(url, `${doc.name}`);
        URL.revokeObjectURL(url);
      }
    } catch (err) {
      console.error("Critical download error:", err);
      alert("Error generating high-quality PDF. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleShare = async (isRequest: boolean = false) => {
    if (!activeDoc) return;
    setIsLoading(true);

    try {
      const blob = await generateProcessedBlob(activeDoc);
      if (!blob) throw new Error("Could not generate file");

      const fileName = activeDoc.name.endsWith('.pdf') ? activeDoc.name : `${activeDoc.name}.pdf`;
      const file = new File([blob], fileName, { type: 'application/pdf' });

      const shareData = {
        files: [file],
        title: activeDoc.name,
        text: isRequest 
          ? `Namaste! I have sent a document: ${activeDoc.name}. Please open it in your browser and sign it digitally. Thank you!`
          : `Hi, here is the signed document: ${activeDoc.name}.`
      };

      if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share(shareData);
      } else {
        // Fallback for browsers that don't support file sharing (Desktop)
        const text = encodeURIComponent(shareData.text);
        window.open(`https://wa.me/?text=${text}`, '_blank');
      }
    } catch (err) {
      console.error("Sharing failed:", err);
      alert("Sharing failed. You can still download the document and send it manually.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-100 transition-transform active:scale-95">S</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignEase</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest text-center">Digital Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowProfileMenu(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/95 z-[150] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-16 h-16 border-[6px] border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-900 tracking-tight text-lg">Processing...</p>
            <p className="text-sm text-slate-500 font-medium">Please wait, ensuring maximum quality.</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Securely Signed</h2>
            <p className="text-gray-500 font-medium mb-10">Your document is ready.</p>
            <div className="space-y-3">
              <button onClick={() => activeDoc && processAndDownloadDoc(activeDoc)} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                 <button onClick={() => handleShare()} className="flex-1 bg-emerald-500 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">Attach & Share</button>
                 <button onClick={() => handleShare(true)} className="flex-1 bg-amber-500 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">Request Sign</button>
              </div>
              <button onClick={() => { setUploadFile(activeDoc?.fileData || null); setCurrentView(AppView.COMPRESS_PDF); }} className="w-full bg-emerald-50 text-emerald-600 font-bold py-5 rounded-2xl hover:bg-emerald-100 transition-all">Compress this PDF</button>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Dashboard</button>
            </div>
          </div>
        ) : currentView === AppView.TOOL_SUCCESS ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Ready!</h2>
            <p className="text-gray-500 font-medium mb-10">Document processed and saved to your library.</p>
            <div className="space-y-3">
              <button onClick={() => toolResultData && downloadDataUrl(toolResultData.dataUrl, toolResultData.name)} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                <button onClick={proceedToSignFromTool} className="flex-1 bg-slate-800 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg text-xs">Add Signature</button>
                <button onClick={startCompressingFromTool} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg text-xs">Compress PDF</button>
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Go to Dashboard</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard 
                documents={documents} 
                onAction={(view) => setCurrentView(view)} 
                onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} 
                onDeleteDoc={handleDeleteDoc}
                onDownloadDoc={processAndDownloadDoc}
              />
            )}

            {currentView === AppView.CREATE_RECEIPT && (
              <RentReceiptCreator onGenerate={handleReceiptGenerate} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.IMAGE_TO_PDF && (
              <ImageToPdfConverter onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.MERGE_PDF && (
              <PdfMerger onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.COMPRESS_PDF && (
              <PdfCompressor initialFile={uploadFile} onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500 pb-32">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'Document View' : 'Signing Area'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                   <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload PDF</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">Select a PDF document to sign</p>
                    <label className="bg-indigo-600 text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-indigo-700 shadow-2xl shadow-indigo-100 inline-block transition-transform active:scale-95">
                      Browse PDFs
                      <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-10">
                    <div className="flex flex-col items-center gap-8 px-2 overflow-y-auto scrollbar-hide">
                      {Array.from({ length: numPages }).map((_, idx) => {
                        const pageNum = idx + 1;
                        return (
                          <div key={pageNum} className="relative bg-white shadow-2xl leading-[0] border border-slate-200 rounded-sm">
                            <canvas 
                              ref={el => { pageRefs.current[pageNum] = el; }} 
                              className="max-w-full h-auto"
                            />
                            <div className="absolute inset-0 z-20 pointer-events-none">
                              {placedSignatures.filter(s => s.pageNumber === pageNum).map(ps => (
                                <div 
                                  key={ps.id} 
                                  style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} 
                                  className="absolute z-30 cursor-move touch-none pointer-events-auto animate-pulse-once" 
                                  onMouseDown={(e) => handleDrag(ps.id, pageNum, e)} 
                                  onTouchStart={(e) => handleDrag(ps.id, pageNum, e)}
                                >
                                  <div className="relative group">
                                    <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-500/50'} p-0.5`} />
                                    {activeDoc?.status !== 'SIGNED' && (
                                      <>
                                        <button onClick={(e) => { e.stopPropagation(); setPlacedSignatures(p => p.filter(x => x.id !== ps.id)); }} className="absolute -top-4 -right-4 bg-red-500 text-white w-8 h-8 rounded-full text-xs flex items-center justify-center shadow-lg font-bold border-2 border-white z-40">✕</button>
                                        <div onMouseDown={(e) => handleResize(ps.id, pageNum, e)} onTouchStart={(e) => handleResize(ps.id, pageNum, e)} className="resize-handle absolute -bottom-4 -right-4 w-9 h-9 bg-indigo-600 border-4 border-white rounded-full cursor-nwse-resize shadow-xl flex items-center justify-center z-40">
                                          <div className="w-2.5 h-2.5 border-r-2 border-b-2 border-white rotate-45 mb-1 mr-1"></div>
                                        </div>
                                      </>
                                    )}
                                  </div>
                                </div>
                              ))}
                            </div>
                            <div className="absolute top-2 right-2 bg-black/40 text-white text-[10px] font-black px-2 py-1 rounded backdrop-blur-sm pointer-events-none">
                              Page {pageNum} / {numPages}
                            </div>
                          </div>
                        );
                      })}
                    </div>

                    <div className="fixed bottom-0 left-0 right-0 p-6 z-40 bg-white/80 backdrop-blur-md border-t border-slate-100 flex flex-col gap-4">
                       {activeDoc?.status === 'SIGNED' ? (
                         <div className="flex gap-3 max-w-lg mx-auto w-full">
                           <button onClick={() => activeDoc && processAndDownloadDoc(activeDoc)} className="flex-[2] bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
                           <button onClick={() => handleShare()} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all text-[10px] uppercase tracking-widest">Share</button>
                         </div>
                       ) : (
                         <div className="max-w-lg mx-auto w-full space-y-4">
                            <div className="flex gap-4 overflow-x-auto pb-1 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-24 h-14 bg-white border-2 border-slate-100 rounded-xl flex items-center justify-center p-2 shadow-sm hover:border-indigo-300 transition-all active:scale-90 overflow-hidden">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply object-contain" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-14 h-14 bg-slate-50 text-slate-400 rounded-xl border-2 border-dashed border-slate-200 text-xl font-bold flex items-center justify-center active:bg-indigo-50 transition-colors">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 disabled:opacity-30 transition-all active:scale-95">Complete & Secure</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showProfileMenu && <ProfileMenu onClose={() => setShowProfileMenu(false)} onManageSignatures={() => setShowSignaturePad(true)} />}
      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}

      <style>{`
        @keyframes pulse-once {
          0% { transform: scale(0.9); opacity: 0; }
          50% { transform: scale(1.05); opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
        .animate-pulse-once {
          animation: pulse-once 0.3s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

{
  "name": "SignX PDF - Digital Signatures & Rent Receipts",
  "description": "A mobile-first digital signature platform specifically designed for the Indian market. Easily sign PDFs, create HRA-compliant rent receipts, and share documents securely.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';
import ProfileMenu from './components/ProfileMenu';
import RentReceiptCreator from './components/RentReceiptCreator';
import ImageToPdfConverter from './components/ImageToPdfConverter';
import PdfMerger from './components/PdfMerger';
import PdfCompressor from './components/PdfCompressor';
import * as db from './db';

declare const jspdf: any;
declare const pdfjsLib: any;

if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [numPages, setNumPages] = useState(1);
  const [toolResultData, setToolResultData] = useState<{ dataUrl: string, name: string } | null>(null);

  const pageRefs = useRef<(HTMLCanvasElement | null)[]>([]);

  const refreshDocuments = async () => {
    try {
      const docs = await db.getAllDocs();
      setDocuments(docs);
    } catch (err) {
      console.error("Failed to refresh documents:", err);
    }
  };

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        const [docs, sigs] = await Promise.all([db.getAllDocs(), db.getAllSigs()]);
        setDocuments(docs);
        setSignatures(sigs);
      } catch (err) {
        console.error("Failed to load data from IndexedDB:", err);
      }
    };
    loadInitialData();
  }, []);

  const handleDeleteDoc = useCallback(async (id: string) => {
    try {
      await db.deleteDoc(id);
      setDocuments(prev => prev.filter(doc => doc.id !== id));
    } catch (err) {
      console.error("Failed to delete document:", err);
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
    setNumPages(1);
    setToolResultData(null);
    pageRefs.current = [];
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.type !== 'application/pdf') {
        alert("SignX PDF currently only supports PDF documents for secure digital signatures.");
        return;
      }
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleReceiptGenerate = async (data: any) => {
    setIsLoading(true);
    const pdf = new jspdf.jsPDF();
    pdf.setFontSize(22);
    pdf.text("RENT RECEIPT", 105, 30, { align: "center" });
    pdf.setFontSize(12);
    pdf.text(`Date: ${new Date().toLocaleDateString('en-IN')}`, 20, 50);
    pdf.text(`Received from Mr./Ms. ${data.tenantName}`, 20, 70);
    pdf.text(`Sum of Rupees ${data.rentAmount} only`, 20, 80);
    pdf.text(`Towards Rent of Property: ${data.address}`, 20, 90);
    pdf.text(`For the month of: ${data.month}`, 20, 100);
    pdf.text("Landlord Signature:", 20, 140);
    pdf.text(`Landlord Name: ${data.landlordName}`, 20, 170);
    if (data.panNumber) pdf.text(`Landlord PAN: ${data.panNumber}`, 20, 180);

    const dataUrl = pdf.output('datauristring');
    handleToolComplete(dataUrl, `Rent_Receipt_${data.month.replace(/\s/g, '_')}.pdf`);
  };

  const handleToolComplete = async (dataUrl: string, customName?: string) => {
    setIsLoading(true);
    let toolName = customName || 'Processed_Document.pdf';
    if (!customName) {
        if (currentView === AppView.IMAGE_TO_PDF) toolName = 'Converted_Images.pdf';
        else if (currentView === AppView.MERGE_PDF) toolName = 'Merged_Document.pdf';
        else if (currentView === AppView.COMPRESS_PDF) toolName = 'Optimized_Document.pdf';
    }

    const newDoc: DocumentRecord = {
      id: Date.now().toString(),
      name: toolName,
      type: 'PDF',
      status: 'PENDING',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: dataUrl,
      placedSignatures: []
    };

    try {
      await db.saveDoc(newDoc);
      await refreshDocuments();
      setToolResultData({ dataUrl, name: toolName });
      setCurrentView(AppView.TOOL_SUCCESS);
    } catch (err) {
      console.error("Failed to save tool result:", err);
      setToolResultData({ dataUrl, name: toolName });
      setCurrentView(AppView.TOOL_SUCCESS);
    } finally {
      setIsLoading(false);
    }
  };

  const proceedToSignFromTool = () => {
    if (toolResultData) {
      setUploadFile(toolResultData.dataUrl);
      setCurrentView(AppView.SIGN_DOC);
    }
  };

  const startCompressingFromTool = () => {
    if (toolResultData) {
      setUploadFile(toolResultData.dataUrl);
      setCurrentView(AppView.COMPRESS_PDF);
    }
  };

  useEffect(() => {
    const renderAllPages = async (dataUrl: string) => {
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        setNumPages(pdf.numPages);

        setTimeout(async () => {
          for (let i = 1; i <= pdf.numPages; i++) {
            const canvas = pageRefs.current[i];
            if (!canvas) continue;
            const page = await pdf.getPage(i);
            const viewport = page.getViewport({ scale: 2 });
            const context = canvas.getContext('2d');
            if (!context) continue;
            canvas.height = viewport.height;
            canvas.width = viewport.width;
            await page.render({ canvasContext: context, viewport }).promise;
          }
        }, 150);
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data && data.startsWith('data:application/pdf')) {
      renderAllPages(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = async (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    try {
      await db.saveSig(newSign);
      setSignatures(prev => [newSign, ...prev]);
      setShowSignaturePad(false);
    } catch (err) {
      console.error("Failed to save signature:", err);
    }
  };

  const handleSignFinish = async () => {
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) return;
    setIsLoading(true);

    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || 'Signed_Doc.pdf',
      type: 'PDF',
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: fileToUse,
      placedSignatures: [...placedSignatures]
    };

    try {
      await db.saveDoc(newDoc);
      await refreshDocuments();
      setActiveDoc(newDoc);
      setIsLoading(false);
      setShowSuccessScreen(true);
    } catch (err) {
      setIsLoading(false);
      console.error("Failed to save signed document:", err);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 35, y: 40, w: 25,
      pageNumber: 1
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, initialPageNum: number, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    if (e.target.closest('.resize-handle')) return;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;

      let targetPageNum = initialPageNum;
      let targetRect = pageRefs.current[initialPageNum]?.getBoundingClientRect();

      for (let i = 1; i <= numPages; i++) {
        const canvas = pageRefs.current[i];
        if (!canvas) continue;
        const rect = canvas.getBoundingClientRect();
        if (cy >= rect.top && cy <= rect.bottom) {
          targetPageNum = i;
          targetRect = rect;
          break;
        }
      }

      if (targetRect) {
        const x = Math.max(-5, Math.min(95, ((cx - targetRect.left) / targetRect.width) * 100));
        const y = Math.max(-5, Math.min(95, ((cy - targetRect.top) / targetRect.height) * 100));
        setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y, pageNumber: targetPageNum } : p));
      }
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, pageNum: number, e: any) => {
    e.stopPropagation();
    const canvas = pageRefs.current[pageNum];
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(10, Math.min(90, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const downloadDataUrl = (dataUrl: string, fileName: string) => {
    const link = document.createElement('a');
    link.href = dataUrl;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Helper to generate the final PDF Blob with signatures burnt in
  const generateProcessedBlob = async (doc: DocumentRecord): Promise<Blob | null> => {
    const fileToUse = doc.fileData;
    if (!fileToUse) return null;

    const docPlacedSigs = doc.placedSignatures || [];

    const pdfOutput = new jspdf.jsPDF({
      orientation: 'p',
      unit: 'pt',
      format: 'a4'
    });

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;

    const loadingTask = pdfjsLib.getDocument(fileToUse);
    const pdf = await loadingTask.promise;

    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const baseViewport = page.getViewport({ scale: 1 });
      const renderViewport = page.getViewport({ scale: 2 });

      canvas.width = renderViewport.width;
      canvas.height = renderViewport.height;
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      await page.render({ canvasContext: ctx, viewport: renderViewport }).promise;

      const orientation = baseViewport.width > baseViewport.height ? 'l' : 'p';
      if (i === 1) {
        pdfOutput.deletePage(1);
      }
      pdfOutput.addPage([baseViewport.width, baseViewport.height], orientation);

      pdfOutput.addImage(canvas.toDataURL('image/jpeg', 0.9), 'JPEG', 0, 0, baseViewport.width, baseViewport.height);

      const sigsOnPage = docPlacedSigs.filter(s => s.pageNumber === i);
      for (const s of sigsOnPage) {
        pdfOutput.addImage(s.dataUrl, 'PNG', (baseViewport.width * s.x)/100, (baseViewport.height * s.y)/100, (baseViewport.width * (s.w || 25)) / 100, ((baseViewport.width * (s.w || 25)) / 100) * 0.5);
      }
    }

    return pdfOutput.output('blob');
  };

  const processAndDownloadDoc = async (doc: DocumentRecord) => {
    setIsLoading(true);
    try {
      const blob = await generateProcessedBlob(doc);
      if (blob) {
        const url = URL.createObjectURL(blob);
        downloadDataUrl(url, `${doc.name}`);
        URL.revokeObjectURL(url);
      }
    } catch (err) {
      console.error("Critical download error:", err);
      alert("Error generating high-quality PDF. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleShare = async (isRequest: boolean = false) => {
    if (!activeDoc) return;
    setIsLoading(true);

    try {
      const blob = await generateProcessedBlob(activeDoc);
      if (!blob) throw new Error("Could not generate file");

      const fileName = activeDoc.name.endsWith('.pdf') ? activeDoc.name : `${activeDoc.name}.pdf`;
      const file = new File([blob], fileName, { type: 'application/pdf' });

      const shareData = {
        files: [file],
        title: activeDoc.name,
        text: isRequest 
          ? `Namaste! I have sent a document: ${activeDoc.name}. Please open it in your browser and sign it digitally. Thank you!`
          : `Hi, here is the signed document: ${activeDoc.name}.`
      };

      if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share(shareData);
      } else {
        const text = encodeURIComponent(shareData.text);
        window.open(`https://wa.me/?text=${text}`, '_blank');
      }
    } catch (err) {
      console.error("Sharing failed:", err);
      alert("Sharing failed. You can still download the document and send it manually.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-100 transition-transform active:scale-95">X</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignX PDF</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest text-center">Digital Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowProfileMenu(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/95 z-[150] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-16 h-16 border-[6px] border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-900 tracking-tight text-lg">Processing...</p>
            <p className="text-sm text-slate-500 font-medium">Please wait, ensuring maximum quality.</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Securely Signed</h2>
            <p className="text-gray-500 font-medium mb-10">Your document is ready.</p>
            <div className="space-y-3">
              <button onClick={() => activeDoc && processAndDownloadDoc(activeDoc)} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                 <button onClick={() => handleShare()} className="flex-1 bg-emerald-500 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">Attach & Share</button>
                 <button onClick={() => handleShare(true)} className="flex-1 bg-amber-500 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">Request Sign</button>
              </div>
              <button onClick={() => { setUploadFile(activeDoc?.fileData || null); setCurrentView(AppView.COMPRESS_PDF); }} className="w-full bg-emerald-50 text-emerald-600 font-bold py-5 rounded-2xl hover:bg-emerald-100 transition-all">Compress this PDF</button>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Dashboard</button>
            </div>
          </div>
        ) : currentView === AppView.TOOL_SUCCESS ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Ready!</h2>
            <p className="text-gray-500 font-medium mb-10">Document processed and saved to your library.</p>
            <div className="space-y-3">
              <button onClick={() => toolResultData && downloadDataUrl(toolResultData.dataUrl, toolResultData.name)} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                <button onClick={proceedToSignFromTool} className="flex-1 bg-slate-800 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg text-xs">Add Signature</button>
                <button onClick={startCompressingFromTool} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg text-xs">Compress PDF</button>
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Go to Dashboard</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard 
                documents={documents} 
                onAction={(view) => setCurrentView(view)} 
                onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} 
                onDeleteDoc={handleDeleteDoc}
                onDownloadDoc={processAndDownloadDoc}
              />
            )}

            {currentView === AppView.CREATE_RECEIPT && (
              <RentReceiptCreator onGenerate={handleReceiptGenerate} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.IMAGE_TO_PDF && (
              <ImageToPdfConverter onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.MERGE_PDF && (
              <PdfMerger onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.COMPRESS_PDF && (
              <PdfCompressor initialFile={uploadFile} onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500 pb-32">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'Document View' : 'Signing Area'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                   <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload PDF</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">Select a PDF document to sign</p>
                    <label className="bg-indigo-600 text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-indigo-700 shadow-2xl shadow-indigo-100 inline-block transition-transform active:scale-95">
                      Browse PDFs
                      <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-10">
                    <div className="flex flex-col items-center gap-8 px-2 overflow-y-auto scrollbar-hide">
                      {Array.from({ length: numPages }).map((_, idx) => {
                        const pageNum = idx + 1;
                        return (
                          <div key={pageNum} className="relative bg-white shadow-2xl leading-[0] border border-slate-200 rounded-sm">
                            <canvas 
                              ref={el => { pageRefs.current[pageNum] = el; }} 
                              className="max-w-full h-auto"
                            />
                            <div className="absolute inset-0 z-20 pointer-events-none">
                              {placedSignatures.filter(s => s.pageNumber === pageNum).map(ps => (
                                <div 
                                  key={ps.id} 
                                  style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} 
                                  className="absolute z-30 cursor-move touch-none pointer-events-auto animate-pulse-once" 
                                  onMouseDown={(e) => handleDrag(ps.id, pageNum, e)} 
                                  onTouchStart={(e) => handleDrag(ps.id, pageNum, e)}
                                >
                                  <div className="relative group">
                                    <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-500/50'} p-0.5`} />
                                    {activeDoc?.status !== 'SIGNED' && (
                                      <>
                                        <button onClick={(e) => { e.stopPropagation(); setPlacedSignatures(p => p.filter(x => x.id !== ps.id)); }} className="absolute -top-4 -right-4 bg-red-500 text-white w-8 h-8 rounded-full text-xs flex items-center justify-center shadow-lg font-bold border-2 border-white z-40">✕</button>
                                        <div onMouseDown={(e) => handleResize(ps.id, pageNum, e)} onTouchStart={(e) => handleResize(ps.id, pageNum, e)} className="resize-handle absolute -bottom-4 -right-4 w-9 h-9 bg-indigo-600 border-4 border-white rounded-full cursor-nwse-resize shadow-xl flex items-center justify-center z-40">
                                          <div className="w-2.5 h-2.5 border-r-2 border-b-2 border-white rotate-45 mb-1 mr-1"></div>
                                        </div>
                                      </>
                                    )}
                                  </div>
                                </div>
                              ))}
                            </div>
                            <div className="absolute top-2 right-2 bg-black/40 text-white text-[10px] font-black px-2 py-1 rounded backdrop-blur-sm pointer-events-none">
                              Page {pageNum} / {numPages}
                            </div>
                          </div>
                        );
                      })}
                    </div>

                    <div className="fixed bottom-0 left-0 right-0 p-6 z-40 bg-white/80 backdrop-blur-md border-t border-slate-100 flex flex-col gap-4">
                       {activeDoc?.status === 'SIGNED' ? (
                         <div className="flex gap-3 max-w-lg mx-auto w-full">
                           <button onClick={() => activeDoc && processAndDownloadDoc(activeDoc)} className="flex-[2] bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
                           <button onClick={() => handleShare()} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all text-[10px] uppercase tracking-widest">Share</button>
                         </div>
                       ) : (
                         <div className="max-w-lg mx-auto w-full space-y-4">
                            <div className="flex gap-4 overflow-x-auto pb-1 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-24 h-14 bg-white border-2 border-slate-100 rounded-xl flex items-center justify-center p-2 shadow-sm hover:border-indigo-300 transition-all active:scale-90 overflow-hidden">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply object-contain" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-14 h-14 bg-slate-50 text-slate-400 rounded-xl border-2 border-dashed border-slate-200 text-xl font-bold flex items-center justify-center active:bg-indigo-50 transition-colors">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 disabled:opacity-30 transition-all active:scale-95">Complete & Secure</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showProfileMenu && <ProfileMenu onClose={() => setShowProfileMenu(false)} onManageSignatures={() => setShowSignaturePad(true)} onCreateReceipt={() => { setShowProfileMenu(false); setCurrentView(AppView.CREATE_RECEIPT); }} />}
      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}

      <style>{`
        @keyframes pulse-once {
          0% { transform: scale(0.9); opacity: 0; }
          50% { transform: scale(1.05); opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
        .animate-pulse-once {
          animation: pulse-once 0.3s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';
import ProfileMenu from './components/ProfileMenu';
import RentReceiptCreator from './components/RentReceiptCreator';
import ImageToPdfConverter from './components/ImageToPdfConverter';
import PdfMerger from './components/PdfMerger';
import PdfCompressor from './components/PdfCompressor';
import * as db from './db';

declare const jspdf: any;
declare const pdfjsLib: any;

if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [numPages, setNumPages] = useState(1);
  const [toolResultData, setToolResultData] = useState<{ dataUrl: string, name: string } | null>(null);

  const pageRefs = useRef<(HTMLCanvasElement | null)[]>([]);

  const refreshDocuments = async () => {
    try {
      const docs = await db.getAllDocs();
      setDocuments(docs);
    } catch (err) {
      console.error("Failed to refresh documents:", err);
    }
  };

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        const [docs, sigs] = await Promise.all([db.getAllDocs(), db.getAllSigs()]);
        setDocuments(docs);
        setSignatures(sigs);
      } catch (err) {
        console.error("Failed to load data from IndexedDB:", err);
      }
    };
    loadInitialData();
  }, []);

  const handleDeleteDoc = useCallback(async (id: string) => {
    try {
      await db.deleteDoc(id);
      setDocuments(prev => prev.filter(doc => doc.id !== id));
    } catch (err) {
      console.error("Failed to delete document:", err);
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
    setNumPages(1);
    setToolResultData(null);
    pageRefs.current = [];
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.type !== 'application/pdf') {
        alert("SignX PDF currently only supports PDF documents for secure digital signatures.");
        return;
      }
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleReceiptGenerate = async (data: any) => {
    setIsLoading(true);
    const pdf = new jspdf.jsPDF();
    pdf.setFontSize(22);
    pdf.text("RENT RECEIPT", 105, 30, { align: "center" });
    pdf.setFontSize(12);
    pdf.text(`Date: ${new Date().toLocaleDateString('en-IN')}`, 20, 50);
    pdf.text(`Received from Mr./Ms. ${data.tenantName}`, 20, 70);
    pdf.text(`Sum of Rupees ${data.rentAmount} only`, 20, 80);
    pdf.text(`Towards Rent of Property: ${data.address}`, 20, 90);
    pdf.text(`For the month of: ${data.month}`, 20, 100);
    pdf.text("Landlord Signature:", 20, 140);
    pdf.text(`Landlord Name: ${data.landlordName}`, 20, 170);
    if (data.panNumber) pdf.text(`Landlord PAN: ${data.panNumber}`, 20, 180);

    const dataUrl = pdf.output('datauristring');
    handleToolComplete(dataUrl, `Rent_Receipt_${data.month.replace(/\s/g, '_')}.pdf`);
  };

  const handleToolComplete = async (dataUrl: string, customName?: string) => {
    setIsLoading(true);
    let toolName = customName || 'Processed_Document.pdf';
    if (!customName) {
        if (currentView === AppView.IMAGE_TO_PDF) toolName = 'Converted_Images.pdf';
        else if (currentView === AppView.MERGE_PDF) toolName = 'Merged_Document.pdf';
        else if (currentView === AppView.COMPRESS_PDF) toolName = 'Optimized_Document.pdf';
    }

    const newDoc: DocumentRecord = {
      id: Date.now().toString(),
      name: toolName,
      type: 'PDF',
      status: 'PENDING',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: dataUrl,
      placedSignatures: []
    };

    try {
      await db.saveDoc(newDoc);
      await refreshDocuments();
      setToolResultData({ dataUrl, name: toolName });
      setCurrentView(AppView.TOOL_SUCCESS);
    } catch (err) {
      console.error("Failed to save tool result:", err);
      setToolResultData({ dataUrl, name: toolName });
      setCurrentView(AppView.TOOL_SUCCESS);
    } finally {
      setIsLoading(false);
    }
  };

  const proceedToSignFromTool = () => {
    if (toolResultData) {
      setUploadFile(toolResultData.dataUrl);
      setCurrentView(AppView.SIGN_DOC);
    }
  };

  const startCompressingFromTool = () => {
    if (toolResultData) {
      setUploadFile(toolResultData.dataUrl);
      setCurrentView(AppView.COMPRESS_PDF);
    }
  };

  useEffect(() => {
    const renderAllPages = async (dataUrl: string) => {
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        setNumPages(pdf.numPages);

        setTimeout(async () => {
          for (let i = 1; i <= pdf.numPages; i++) {
            const canvas = pageRefs.current[i];
            if (!canvas) continue;
            const page = await pdf.getPage(i);
            const viewport = page.getViewport({ scale: 2 });
            const context = canvas.getContext('2d');
            if (!context) continue;
            canvas.height = viewport.height;
            canvas.width = viewport.width;
            await page.render({ canvasContext: context, viewport }).promise;
          }
        }, 150);
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data && data.startsWith('data:application/pdf')) {
      renderAllPages(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = async (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    try {
      await db.saveSig(newSign);
      setSignatures(prev => [newSign, ...prev]);
      setShowSignaturePad(false);
    } catch (err) {
      console.error("Failed to save signature:", err);
    }
  };

  const handleSignFinish = async () => {
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) return;
    setIsLoading(true);

    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || 'Signed_Doc.pdf',
      type: 'PDF',
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: fileToUse,
      placedSignatures: [...placedSignatures]
    };

    try {
      await db.saveDoc(newDoc);
      await refreshDocuments();
      setActiveDoc(newDoc);
      setIsLoading(false);
      setShowSuccessScreen(true);
    } catch (err) {
      setIsLoading(false);
      console.error("Failed to save signed document:", err);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 35, y: 40, w: 25,
      pageNumber: 1
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, initialPageNum: number, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    if (e.target.closest('.resize-handle')) return;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;

      let targetPageNum = initialPageNum;
      let targetRect = pageRefs.current[initialPageNum]?.getBoundingClientRect();

      for (let i = 1; i <= numPages; i++) {
        const canvas = pageRefs.current[i];
        if (!canvas) continue;
        const rect = canvas.getBoundingClientRect();
        if (cy >= rect.top && cy <= rect.bottom) {
          targetPageNum = i;
          targetRect = rect;
          break;
        }
      }

      if (targetRect) {
        const x = Math.max(-5, Math.min(95, ((cx - targetRect.left) / targetRect.width) * 100));
        const y = Math.max(-5, Math.min(95, ((cy - targetRect.top) / targetRect.height) * 100));
        setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y, pageNumber: targetPageNum } : p));
      }
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, pageNum: number, e: any) => {
    e.stopPropagation();
    const canvas = pageRefs.current[pageNum];
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(10, Math.min(90, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const downloadDataUrl = (dataUrl: string, fileName: string) => {
    const link = document.createElement('a');
    link.href = dataUrl;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Helper to generate the final PDF Blob with signatures burnt in
  const generateProcessedBlob = async (doc: DocumentRecord): Promise<Blob | null> => {
    const fileToUse = doc.fileData;
    if (!fileToUse) return null;

    const docPlacedSigs = doc.placedSignatures || [];

    const pdfOutput = new jspdf.jsPDF({
      orientation: 'p',
      unit: 'pt',
      format: 'a4'
    });

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;

    const loadingTask = pdfjsLib.getDocument(fileToUse);
    const pdf = await loadingTask.promise;

    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const baseViewport = page.getViewport({ scale: 1 });
      const renderViewport = page.getViewport({ scale: 2 });

      canvas.width = renderViewport.width;
      canvas.height = renderViewport.height;
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      await page.render({ canvasContext: ctx, viewport: renderViewport }).promise;

      const orientation = baseViewport.width > baseViewport.height ? 'l' : 'p';
      if (i === 1) {
        pdfOutput.deletePage(1);
      }
      pdfOutput.addPage([baseViewport.width, baseViewport.height], orientation);

      pdfOutput.addImage(canvas.toDataURL('image/jpeg', 0.9), 'JPEG', 0, 0, baseViewport.width, baseViewport.height);

      const sigsOnPage = docPlacedSigs.filter(s => s.pageNumber === i);
      for (const s of sigsOnPage) {
        pdfOutput.addImage(s.dataUrl, 'PNG', (baseViewport.width * s.x)/100, (baseViewport.height * s.y)/100, (baseViewport.width * (s.w || 25)) / 100, ((baseViewport.width * (s.w || 25)) / 100) * 0.5);
      }
    }

    return pdfOutput.output('blob');
  };

  const processAndDownloadDoc = async (doc: DocumentRecord) => {
    setIsLoading(true);
    try {
      const blob = await generateProcessedBlob(doc);
      if (blob) {
        const url = URL.createObjectURL(blob);
        downloadDataUrl(url, `${doc.name}`);
        URL.revokeObjectURL(url);
      }
    } catch (err) {
      console.error("Critical download error:", err);
      alert("Error generating high-quality PDF. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleShare = async (isRequest: boolean = false) => {
    if (!activeDoc) return;
    setIsLoading(true);

    try {
      const blob = await generateProcessedBlob(activeDoc);
      if (!blob) throw new Error("Could not generate file");

      const fileName = activeDoc.name.endsWith('.pdf') ? activeDoc.name : `${activeDoc.name}.pdf`;
      const file = new File([blob], fileName, { type: 'application/pdf' });

      const shareData = {
        files: [file],
        title: activeDoc.name,
        text: isRequest 
          ? `Namaste! I have sent a document: ${activeDoc.name}. Please open it in your browser and sign it digitally. Thank you!`
          : `Hi, here is the signed document: ${activeDoc.name}.`
      };

      if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share(shareData);
      } else {
        const text = encodeURIComponent(shareData.text);
        window.open(`https://wa.me/?text=${text}`, '_blank');
      }
    } catch (err) {
      console.error("Sharing failed:", err);
      alert("Sharing failed. You can still download the document and send it manually.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-100 transition-transform active:scale-95">X</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignX PDF</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest text-center">Digital Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowProfileMenu(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/95 z-[150] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-16 h-16 border-[6px] border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-900 tracking-tight text-lg">Processing...</p>
            <p className="text-sm text-slate-500 font-medium">Please wait, ensuring maximum quality.</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Securely Signed</h2>
            <p className="text-gray-500 font-medium mb-10">Your document is ready.</p>
            <div className="space-y-3">
              <button onClick={() => activeDoc && processAndDownloadDoc(activeDoc)} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                 <button onClick={() => handleShare()} className="flex-1 bg-emerald-500 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">Attach & Share</button>
                 <button onClick={() => handleShare(true)} className="flex-1 bg-amber-500 text-white font-black py-4 rounded-2xl active:scale-95 transition-all text-xs">Request Sign</button>
              </div>
              <button onClick={() => { setUploadFile(activeDoc?.fileData || null); setCurrentView(AppView.COMPRESS_PDF); }} className="w-full bg-emerald-50 text-emerald-600 font-bold py-5 rounded-2xl hover:bg-emerald-100 transition-all">Compress this PDF</button>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Dashboard</button>
            </div>
          </div>
        ) : currentView === AppView.TOOL_SUCCESS ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Ready!</h2>
            <p className="text-gray-500 font-medium mb-10">Document processed and saved to your library.</p>
            <div className="space-y-3">
              <button onClick={() => toolResultData && downloadDataUrl(toolResultData.dataUrl, toolResultData.name)} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                <button onClick={proceedToSignFromTool} className="flex-1 bg-slate-800 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg text-xs">Add Signature</button>
                <button onClick={startCompressingFromTool} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg text-xs">Compress PDF</button>
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Go to Dashboard</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard 
                documents={documents} 
                onAction={(view) => setCurrentView(view)} 
                onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} 
                onDeleteDoc={handleDeleteDoc}
                onDownloadDoc={processAndDownloadDoc}
              />
            )}

            {currentView === AppView.CREATE_RECEIPT && (
              <RentReceiptCreator onGenerate={handleReceiptGenerate} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.IMAGE_TO_PDF && (
              <ImageToPdfConverter onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.MERGE_PDF && (
              <PdfMerger onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.COMPRESS_PDF && (
              <PdfCompressor initialFile={uploadFile} onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500 pb-32">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'Document View' : 'Signing Area'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                   <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload PDF</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">Select a PDF document to sign</p>
                    <label className="bg-indigo-600 text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-indigo-700 shadow-2xl shadow-indigo-100 inline-block transition-transform active:scale-95">
                      Browse PDFs
                      <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-10">
                    <div className="flex flex-col items-center gap-8 px-2 overflow-y-auto scrollbar-hide">
                      {Array.from({ length: numPages }).map((_, idx) => {
                        const pageNum = idx + 1;
                        return (
                          <div key={pageNum} className="relative bg-white shadow-2xl leading-[0] border border-slate-200 rounded-sm">
                            <canvas 
                              ref={el => { pageRefs.current[pageNum] = el; }} 
                              className="max-w-full h-auto"
                            />
                            <div className="absolute inset-0 z-20 pointer-events-none">
                              {placedSignatures.filter(s => s.pageNumber === pageNum).map(ps => (
                                <div 
                                  key={ps.id} 
                                  style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} 
                                  className="absolute z-30 cursor-move touch-none pointer-events-auto animate-pulse-once" 
                                  onMouseDown={(e) => handleDrag(ps.id, pageNum, e)} 
                                  onTouchStart={(e) => handleDrag(ps.id, pageNum, e)}
                                >
                                  <div className="relative group">
                                    <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-500/50'} p-0.5`} />
                                    {activeDoc?.status !== 'SIGNED' && (
                                      <>
                                        <button onClick={(e) => { e.stopPropagation(); setPlacedSignatures(p => p.filter(x => x.id !== ps.id)); }} className="absolute -top-4 -right-4 bg-red-500 text-white w-8 h-8 rounded-full text-xs flex items-center justify-center shadow-lg font-bold border-2 border-white z-40">✕</button>
                                        <div onMouseDown={(e) => handleResize(ps.id, pageNum, e)} onTouchStart={(e) => handleResize(ps.id, pageNum, e)} className="resize-handle absolute -bottom-4 -right-4 w-9 h-9 bg-indigo-600 border-4 border-white rounded-full cursor-nwse-resize shadow-xl flex items-center justify-center z-40">
                                          <div className="w-2.5 h-2.5 border-r-2 border-b-2 border-white rotate-45 mb-1 mr-1"></div>
                                        </div>
                                      </>
                                    )}
                                  </div>
                                </div>
                              ))}
                            </div>
                            <div className="absolute top-2 right-2 bg-black/40 text-white text-[10px] font-black px-2 py-1 rounded backdrop-blur-sm pointer-events-none">
                              Page {pageNum} / {numPages}
                            </div>
                          </div>
                        );
                      })}
                    </div>

                    <div className="fixed bottom-0 left-0 right-0 p-6 z-40 bg-white/80 backdrop-blur-md border-t border-slate-100 flex flex-col gap-4">
                       {activeDoc?.status === 'SIGNED' ? (
                         <div className="flex gap-3 max-w-lg mx-auto w-full">
                           <button onClick={() => activeDoc && processAndDownloadDoc(activeDoc)} className="flex-[2] bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
                           <button onClick={() => handleShare()} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all text-[10px] uppercase tracking-widest">Share</button>
                         </div>
                       ) : (
                         <div className="max-w-lg mx-auto w-full space-y-4">
                            <div className="flex gap-4 overflow-x-auto pb-1 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-24 h-14 bg-white border-2 border-slate-100 rounded-xl flex items-center justify-center p-2 shadow-sm hover:border-indigo-300 transition-all active:scale-90 overflow-hidden">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply object-contain" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-14 h-14 bg-slate-50 text-slate-400 rounded-xl border-2 border-dashed border-slate-200 text-xl font-bold flex items-center justify-center active:bg-indigo-50 transition-colors">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 disabled:opacity-30 transition-all active:scale-95">Complete & Secure</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showProfileMenu && <ProfileMenu onClose={() => setShowProfileMenu(false)} onManageSignatures={() => setShowSignaturePad(true)} />}
      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}

      <style>{`
        @keyframes pulse-once {
          0% { transform: scale(0.9); opacity: 0; }
          50% { transform: scale(1.05); opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
        .animate-pulse-once {
          animation: pulse-once 0.3s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';
import ProfileMenu from './components/ProfileMenu';
import RentReceiptCreator from './components/RentReceiptCreator';
import ImageToPdfConverter from './components/ImageToPdfConverter';
import PdfMerger from './components/PdfMerger';
import PdfCompressor from './components/PdfCompressor';
import * as db from './db';

declare const jspdf: any;
declare const pdfjsLib: any;

if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [numPages, setNumPages] = useState(1);
  const [toolResultData, setToolResultData] = useState<{ dataUrl: string, name: string } | null>(null);

  const pageRefs = useRef<(HTMLCanvasElement | null)[]>([]);

  const refreshDocuments = async () => {
    try {
      const docs = await db.getAllDocs();
      setDocuments(docs);
    } catch (err) {
      console.error("Failed to refresh documents:", err);
    }
  };

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        const [docs, sigs] = await Promise.all([db.getAllDocs(), db.getAllSigs()]);
        setDocuments(docs);
        setSignatures(sigs);
      } catch (err) {
        console.error("Failed to load data from IndexedDB:", err);
      }
    };
    loadInitialData();
  }, []);

  const handleDeleteDoc = useCallback(async (id: string) => {
    try {
      await db.deleteDoc(id);
      setDocuments(prev => prev.filter(doc => doc.id !== id));
    } catch (err) {
      console.error("Failed to delete document:", err);
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
    setNumPages(1);
    setToolResultData(null);
    pageRefs.current = [];
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.type !== 'application/pdf') {
        alert("SignX PDF currently only supports PDF documents for secure digital signatures.");
        return;
      }
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleReceiptGenerate = async (data: any) => {
    setIsLoading(true);
    const pdf = new jspdf.jsPDF();
    pdf.setFontSize(22);
    pdf.text("RENT RECEIPT", 105, 30, { align: "center" });
    pdf.setFontSize(12);
    pdf.text(`Date: ${new Date().toLocaleDateString('en-IN')}`, 20, 50);
    pdf.text(`Received from Mr./Ms. ${data.tenantName}`, 20, 70);
    pdf.text(`Sum of Rupees ${data.rentAmount} only`, 20, 80);
    pdf.text(`Towards Rent of Property: ${data.address}`, 20, 90);
    pdf.text(`For the month of: ${data.month}`, 20, 100);
    pdf.text("Landlord Signature:", 20, 140);
    pdf.text(`Landlord Name: ${data.landlordName}`, 20, 170);
    if (data.panNumber) pdf.text(`Landlord PAN: ${data.panNumber}`, 20, 180);

    const dataUrl = pdf.output('datauristring');
    handleToolComplete(dataUrl, `Rent_Receipt_${data.month.replace(/\s/g, '_')}.pdf`);
  };

  const handleToolComplete = async (dataUrl: string, customName?: string) => {
    setIsLoading(true);
    let toolName = customName || 'Processed_Document.pdf';
    if (!customName) {
        if (currentView === AppView.IMAGE_TO_PDF) toolName = 'Converted_Images.pdf';
        else if (currentView === AppView.MERGE_PDF) toolName = 'Merged_Document.pdf';
        else if (currentView === AppView.COMPRESS_PDF) toolName = 'Optimized_Document.pdf';
    }

    const newDoc: DocumentRecord = {
      id: Date.now().toString(),
      name: toolName,
      type: 'PDF',
      status: 'PENDING',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: dataUrl,
      placedSignatures: []
    };

    try {
      await db.saveDoc(newDoc);
      await refreshDocuments();
      setToolResultData({ dataUrl, name: toolName });
      setCurrentView(AppView.TOOL_SUCCESS);
    } catch (err) {
      console.error("Failed to save tool result:", err);
      setToolResultData({ dataUrl, name: toolName });
      setCurrentView(AppView.TOOL_SUCCESS);
    } finally {
      setIsLoading(false);
    }
  };

  const proceedToSignFromTool = () => {
    if (toolResultData) {
      setUploadFile(toolResultData.dataUrl);
      setCurrentView(AppView.SIGN_DOC);
    }
  };

  const startCompressingFromTool = () => {
    if (toolResultData) {
      setUploadFile(toolResultData.dataUrl);
      setCurrentView(AppView.COMPRESS_PDF);
    }
  };

  useEffect(() => {
    const renderAllPages = async (dataUrl: string) => {
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        setNumPages(pdf.numPages);

        setTimeout(async () => {
          for (let i = 1; i <= pdf.numPages; i++) {
            const canvas = pageRefs.current[i];
            if (!canvas) continue;
            const page = await pdf.getPage(i);
            const viewport = page.getViewport({ scale: 2 });
            const context = canvas.getContext('2d');
            if (!context) continue;
            canvas.height = viewport.height;
            canvas.width = viewport.width;
            await page.render({ canvasContext: context, viewport }).promise;
          }
        }, 150);
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data && data.startsWith('data:application/pdf')) {
      renderAllPages(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = async (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    try {
      await db.saveSig(newSign);
      setSignatures(prev => [newSign, ...prev]);
      setShowSignaturePad(false);
    } catch (err) {
      console.error("Failed to save signature:", err);
    }
  };

  const handleSignFinish = async () => {
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) return;
    setIsLoading(true);

    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || 'Signed_Doc.pdf',
      type: 'PDF',
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: fileToUse,
      placedSignatures: [...placedSignatures]
    };

    try {
      await db.saveDoc(newDoc);
      await refreshDocuments();
      setActiveDoc(newDoc);
      setIsLoading(false);
      setShowSuccessScreen(true);
    } catch (err) {
      setIsLoading(false);
      console.error("Failed to save signed document:", err);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 35, y: 40, w: 25,
      pageNumber: 1
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, initialPageNum: number, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    if (e.target.closest('.resize-handle')) return;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;

      let targetPageNum = initialPageNum;
      let targetRect = pageRefs.current[initialPageNum]?.getBoundingClientRect();

      for (let i = 1; i <= numPages; i++) {
        const canvas = pageRefs.current[i];
        if (!canvas) continue;
        const rect = canvas.getBoundingClientRect();
        if (cy >= rect.top && cy <= rect.bottom) {
          targetPageNum = i;
          targetRect = rect;
          break;
        }
      }

      if (targetRect) {
        const x = Math.max(-5, Math.min(95, ((cx - targetRect.left) / targetRect.width) * 100));
        const y = Math.max(-5, Math.min(95, ((cy - targetRect.top) / targetRect.height) * 100));
        setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y, pageNumber: targetPageNum } : p));
      }
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, pageNum: number, e: any) => {
    e.stopPropagation();
    const canvas = pageRefs.current[pageNum];
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(10, Math.min(90, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const downloadDataUrl = (dataUrl: string, fileName: string) => {
    const link = document.createElement('a');
    link.href = dataUrl;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // Helper to generate the final PDF Blob with signatures burnt in
  const generateProcessedBlob = async (doc: DocumentRecord): Promise<Blob | null> => {
    const fileToUse = doc.fileData;
    if (!fileToUse) return null;

    const docPlacedSigs = doc.placedSignatures || [];

    const pdfOutput = new jspdf.jsPDF({
      orientation: 'p',
      unit: 'pt',
      format: 'a4'
    });

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;

    const loadingTask = pdfjsLib.getDocument(fileToUse);
    const pdf = await loadingTask.promise;

    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const baseViewport = page.getViewport({ scale: 1 });
      const renderViewport = page.getViewport({ scale: 2 });

      canvas.width = renderViewport.width;
      canvas.height = renderViewport.height;
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      await page.render({ canvasContext: ctx, viewport: renderViewport }).promise;

      const orientation = baseViewport.width > baseViewport.height ? 'l' : 'p';
      if (i === 1) {
        pdfOutput.deletePage(1);
      }
      pdfOutput.addPage([baseViewport.width, baseViewport.height], orientation);

      pdfOutput.addImage(canvas.toDataURL('image/jpeg', 0.9), 'JPEG', 0, 0, baseViewport.width, baseViewport.height);

      const sigsOnPage = docPlacedSigs.filter(s => s.pageNumber === i);
      for (const s of sigsOnPage) {
        pdfOutput.addImage(s.dataUrl, 'PNG', (baseViewport.width * s.x)/100, (baseViewport.height * s.y)/100, (baseViewport.width * (s.w || 25)) / 100, ((baseViewport.width * (s.w || 25)) / 100) * 0.5);
      }
    }

    return pdfOutput.output('blob');
  };

  const processAndDownloadDoc = async (doc: DocumentRecord) => {
    setIsLoading(true);
    try {
      const blob = await generateProcessedBlob(doc);
      if (blob) {
        const url = URL.createObjectURL(blob);
        downloadDataUrl(url, `${doc.name}`);
        URL.revokeObjectURL(url);
      }
    } catch (err) {
      console.error("Critical download error:", err);
      alert("Error generating high-quality PDF. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleShare = async (isRequest: boolean = false) => {
    if (!activeDoc) return;
    setIsLoading(true);

    try {
      const blob = await generateProcessedBlob(activeDoc);
      if (!blob) throw new Error("Could not generate file");

      const fileName = activeDoc.name.endsWith('.pdf') ? activeDoc.name : `${activeDoc.name}.pdf`;
      const file = new File([blob], fileName, { type: 'application/pdf' });

      const shareData = {
        files: [file],
        title: activeDoc.name,
        text: isRequest 
          ? `Namaste! I have sent a document: ${activeDoc.name}. Please open it in your browser and sign it digitally. Thank you!`
          : `Hi, here is the signed document: ${activeDoc.name}.`
      };

      if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share(shareData);
      } else {
        const text = encodeURIComponent(shareData.text);
        window.open(`https://wa.me/?text=${text}`, '_blank');
      }
    } catch (err) {
      console.error("Sharing failed:", err);
      alert("Sharing failed. You can still download the document and send it manually.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-indigo-100 transition-transform active:scale-95">X</div>
          <div>
            <h1 className="text-lg font-bold text-gray-900 leading-none">SignX PDF</h1>
            <span className="text-[10px] text-indigo-500 font-bold uppercase tracking-widest text-center">Digital Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowProfileMenu(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/95 z-[150] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-16 h-16 border-[6px] border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-900 tracking-tight text-lg">Processing...</p>
            <p className="text-sm text-slate-500 font-medium">Please wait, ensuring maximum quality.</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Securely Signed</h2>
            <p className="text-gray-500 font-medium mb-10">Your document is ready.</p>
            <div className="space-y-3">
              <button onClick={() => activeDoc && processAndDownloadDoc(activeDoc)} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <button onClick={() => handleShare()} className="w-full bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-xl shadow-emerald-100">Attach & Share PDF</button>
              <button onClick={() => { setUploadFile(activeDoc?.fileData || null); setCurrentView(AppView.COMPRESS_PDF); }} className="w-full bg-emerald-50 text-emerald-600 font-bold py-5 rounded-2xl hover:bg-emerald-100 transition-all">Compress this PDF</button>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Dashboard</button>
            </div>
          </div>
        ) : currentView === AppView.TOOL_SUCCESS ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-emerald-500 rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Ready!</h2>
            <p className="text-gray-500 font-medium mb-10">Document processed and saved to your library.</p>
            <div className="space-y-3">
              <button onClick={() => toolResultData && downloadDataUrl(toolResultData.dataUrl, toolResultData.name)} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                <button onClick={proceedToSignFromTool} className="flex-1 bg-slate-800 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg text-xs">Add Signature</button>
                <button onClick={startCompressingFromTool} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg text-xs">Compress PDF</button>
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Go to Dashboard</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard 
                documents={documents} 
                onAction={(view) => setCurrentView(view)} 
                onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} 
                onDeleteDoc={handleDeleteDoc}
                onDownloadDoc={processAndDownloadDoc}
              />
            )}

            {currentView === AppView.CREATE_RECEIPT && (
              <RentReceiptCreator onGenerate={handleReceiptGenerate} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.IMAGE_TO_PDF && (
              <ImageToPdfConverter onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.MERGE_PDF && (
              <PdfMerger onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.COMPRESS_PDF && (
              <PdfCompressor initialFile={uploadFile} onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500 pb-32">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'Document View' : 'Signing Area'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                   <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload PDF</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">Select a PDF document to sign</p>
                    <label className="bg-indigo-600 text-white px-12 py-5 rounded-2xl font-black cursor-pointer hover:bg-indigo-700 shadow-2xl shadow-indigo-100 inline-block transition-transform active:scale-95">
                      Browse PDFs
                      <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-10">
                    <div className="flex flex-col items-center gap-8 px-2 overflow-y-auto scrollbar-hide">
                      {Array.from({ length: numPages }).map((_, idx) => {
                        const pageNum = idx + 1;
                        return (
                          <div key={pageNum} className="relative bg-white shadow-2xl leading-[0] border border-slate-200 rounded-sm">
                            <canvas 
                              ref={el => { pageRefs.current[pageNum] = el; }} 
                              className="max-w-full h-auto"
                            />
                            <div className="absolute inset-0 z-20 pointer-events-none">
                              {placedSignatures.filter(s => s.pageNumber === pageNum).map(ps => (
                                <div 
                                  key={ps.id} 
                                  style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} 
                                  className="absolute z-30 cursor-move touch-none pointer-events-auto animate-pulse-once" 
                                  onMouseDown={(e) => handleDrag(ps.id, pageNum, e)} 
                                  onTouchStart={(e) => handleDrag(ps.id, pageNum, e)}
                                >
                                  <div className="relative group">
                                    <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-indigo-500/50'} p-0.5`} />
                                    {activeDoc?.status !== 'SIGNED' && (
                                      <>
                                        <button onClick={(e) => { e.stopPropagation(); setPlacedSignatures(p => p.filter(x => x.id !== ps.id)); }} className="absolute -top-4 -right-4 bg-red-500 text-white w-8 h-8 rounded-full text-xs flex items-center justify-center shadow-lg font-bold border-2 border-white z-40">✕</button>
                                        <div onMouseDown={(e) => handleResize(ps.id, pageNum, e)} onTouchStart={(e) => handleResize(ps.id, pageNum, e)} className="resize-handle absolute -bottom-4 -right-4 w-9 h-9 bg-indigo-600 border-4 border-white rounded-full cursor-nwse-resize shadow-xl flex items-center justify-center z-40">
                                          <div className="w-2.5 h-2.5 border-r-2 border-b-2 border-white rotate-45 mb-1 mr-1"></div>
                                        </div>
                                      </>
                                    )}
                                  </div>
                                </div>
                              ))}
                            </div>
                            <div className="absolute top-2 right-2 bg-black/40 text-white text-[10px] font-black px-2 py-1 rounded backdrop-blur-sm pointer-events-none">
                              Page {pageNum} / {numPages}
                            </div>
                          </div>
                        );
                      })}
                    </div>

                    <div className="fixed bottom-0 left-0 right-0 p-6 z-40 bg-white/80 backdrop-blur-md border-t border-slate-100 flex flex-col gap-4">
                       {activeDoc?.status === 'SIGNED' ? (
                         <div className="flex gap-3 max-w-lg mx-auto w-full">
                           <button onClick={() => activeDoc && processAndDownloadDoc(activeDoc)} className="flex-[2] bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 active:scale-95 transition-all">Download PDF</button>
                           <button onClick={() => handleShare()} className="flex-1 bg-emerald-500 text-white font-black py-5 rounded-2xl active:scale-95 transition-all text-[10px] uppercase tracking-widest">Share</button>
                         </div>
                       ) : (
                         <div className="max-w-lg mx-auto w-full space-y-4">
                            <div className="flex gap-4 overflow-x-auto pb-1 scrollbar-hide">
                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-24 h-14 bg-white border-2 border-slate-100 rounded-xl flex items-center justify-center p-2 shadow-sm hover:border-indigo-300 transition-all active:scale-90 overflow-hidden">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply object-contain" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-14 h-14 bg-slate-50 text-slate-400 rounded-xl border-2 border-dashed border-slate-200 text-xl font-bold flex items-center justify-center active:bg-indigo-50 transition-colors">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedSignatures.length === 0} className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-2xl shadow-indigo-100 disabled:opacity-30 transition-all active:scale-95">Complete & Secure</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showProfileMenu && <ProfileMenu onClose={() => setShowProfileMenu(false)} />}
      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}

      <style>{`
        @keyframes pulse-once {
          0% { transform: scale(0.9); opacity: 0; }
          50% { transform: scale(1.05); opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
        .animate-pulse-once {
          animation: pulse-once 0.3s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { AppView, DocumentRecord, UserSignature, PlacedSignature } from './types';
import Dashboard from './components/Dashboard';
import SignaturePad from './components/SignaturePad';
import ProfileMenu from './components/ProfileMenu';
import RentReceiptCreator from './components/RentReceiptCreator';
import ImageToPdfConverter from './components/ImageToPdfConverter';
import PdfMerger from './components/PdfMerger';
import PdfCompressor from './components/PdfCompressor';
import * as db from './db';

declare const jspdf: any;
declare const pdfjsLib: any;

if (typeof window !== 'undefined' && pdfjsLib) {
  pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
}

const AppLogo = ({ className }: { className?: string }) => (
  <div className={`relative flex items-center justify-center ${className}`}>
    <svg viewBox="0 0 100 100" className="w-full h-full">
      <defs>
        <linearGradient id="logoGrad" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor="#14b8a6" />
          <stop offset="100%" stopColor="#2563eb" />
        </linearGradient>
      </defs>
      <rect x="25" y="15" width="50" height="70" rx="10" fill="url(#logoGrad)" />
      <path d="M75 15 L65 15 L75 25 Z" fill="rgba(255,255,255,0.3)" />
      <path 
        d="M30 45 L45 60 L80 25" 
        fill="none" 
        stroke="white" 
        strokeWidth="10" 
        strokeLinecap="round" 
        strokeLinejoin="round"
        className="drop-shadow-sm"
      />
    </svg>
  </div>
);

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [documents, setDocuments] = useState<DocumentRecord[]>([]);
  const [signatures, setSignatures] = useState<UserSignature[]>([]);
  const [showSignaturePad, setShowSignaturePad] = useState(false);
  const [showProfileMenu, setShowProfileMenu] = useState(false);
  const [uploadFile, setUploadFile] = useState<string | null>(null);
  const [activeDoc, setActiveDoc] = useState<DocumentRecord | null>(null);
  const [placedSignatures, setPlacedSignatures] = useState<PlacedSignature[]>([]);
  const [showSuccessScreen, setShowSuccessScreen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [numPages, setNumPages] = useState(1);
  const [toolResultData, setToolResultData] = useState<{ dataUrl: string, name: string } | null>(null);

  const pageRefs = useRef<(HTMLCanvasElement | null)[]>([]);

  const refreshDocuments = async () => {
    try {
      const docs = await db.getAllDocs();
      setDocuments(docs);
    } catch (err) {
      console.error("Failed to refresh documents:", err);
    }
  };

  useEffect(() => {
    const loadInitialData = async () => {
      try {
        const [docs, sigs] = await Promise.all([db.getAllDocs(), db.getAllSigs()]);
        setDocuments(docs);
        setSignatures(sigs);
      } catch (err) {
        console.error("Failed to load data from IndexedDB:", err);
      }
    };
    loadInitialData();
  }, []);

  const handleDeleteDoc = useCallback(async (id: string) => {
    try {
      await db.deleteDoc(id);
      setDocuments(prev => prev.filter(doc => doc.id !== id));
    } catch (err) {
      console.error("Failed to delete document:", err);
    }
  }, []);

  const resetSigningState = () => {
    setUploadFile(null);
    setActiveDoc(null);
    setPlacedSignatures([]);
    setShowSuccessScreen(false);
    setIsLoading(false);
    setNumPages(1);
    setToolResultData(null);
    pageRefs.current = [];
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.type !== 'application/pdf') {
        alert("SignX PDF currently only supports PDF documents for secure digital signatures.");
        return;
      }
      setIsLoading(true);
      const reader = new FileReader();
      reader.onloadend = () => {
        setUploadFile(reader.result as string);
        setCurrentView(AppView.SIGN_DOC);
        setIsLoading(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleReceiptGenerate = async (data: any) => {
    setIsLoading(true);
    const pdf = new jspdf.jsPDF();
    pdf.setFontSize(22);
    pdf.text("RENT RECEIPT", 105, 30, { align: "center" });
    pdf.setFontSize(12);
    pdf.text(`Date: ${new Date().toLocaleDateString('en-IN')}`, 20, 50);
    pdf.text(`Received from Mr./Ms. ${data.tenantName}`, 20, 70);
    pdf.text(`Sum of Rupees ${data.rentAmount} only`, 20, 80);
    pdf.text(`Towards Rent of Property: ${data.address}`, 20, 90);
    pdf.text(`For the month of: ${data.month}`, 20, 100);
    pdf.text("Landlord Signature:", 20, 140);
    pdf.text(`Landlord Name: ${data.landlordName}`, 20, 170);
    if (data.panNumber) pdf.text(`Landlord PAN: ${data.panNumber}`, 20, 180);

    const dataUrl = pdf.output('datauristring');
    handleToolComplete(dataUrl, `Rent_Receipt_${data.month.replace(/\s/g, '_')}.pdf`);
  };

  const handleToolComplete = async (dataUrl: string, customName?: string) => {
    setIsLoading(true);
    let toolName = customName || 'Processed_Document.pdf';
    if (!customName) {
        if (currentView === AppView.IMAGE_TO_PDF) toolName = 'Converted_Images.pdf';
        else if (currentView === AppView.MERGE_PDF) toolName = 'Merged_Document.pdf';
        else if (currentView === AppView.COMPRESS_PDF) toolName = 'Optimized_Document.pdf';
    }

    const newDoc: DocumentRecord = {
      id: Date.now().toString(),
      name: toolName,
      type: 'PDF',
      status: 'PENDING',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: dataUrl,
      placedSignatures: []
    };

    try {
      await db.saveDoc(newDoc);
      await refreshDocuments();
      setToolResultData({ dataUrl, name: toolName });
      setCurrentView(AppView.TOOL_SUCCESS);
    } catch (err) {
      console.error("Failed to save tool result:", err);
      setToolResultData({ dataUrl, name: toolName });
      setCurrentView(AppView.TOOL_SUCCESS);
    } finally {
      setIsLoading(false);
    }
  };

  const proceedToSignFromTool = () => {
    if (toolResultData) {
      setUploadFile(toolResultData.dataUrl);
      setCurrentView(AppView.SIGN_DOC);
    }
  };

  const startCompressingFromTool = () => {
    if (toolResultData) {
      setUploadFile(toolResultData.dataUrl);
      setCurrentView(AppView.COMPRESS_PDF);
    }
  };

  useEffect(() => {
    const renderAllPages = async (dataUrl: string) => {
      try {
        const loadingTask = pdfjsLib.getDocument(dataUrl);
        const pdf = await loadingTask.promise;
        setNumPages(pdf.numPages);

        setTimeout(async () => {
          for (let i = 1; i <= pdf.numPages; i++) {
            const canvas = pageRefs.current[i];
            if (!canvas) continue;
            const page = await pdf.getPage(i);
            const viewport = page.getViewport({ scale: 2 });
            const context = canvas.getContext('2d');
            if (!context) continue;
            canvas.height = viewport.height;
            canvas.width = viewport.width;
            await page.render({ canvasContext: context, viewport }).promise;
          }
        }, 150);
      } catch (err) {
        console.error("PDF Render Error", err);
      }
    };

    const data = uploadFile || activeDoc?.fileData;
    if (data && data.startsWith('data:application/pdf')) {
      renderAllPages(data);
    }
  }, [uploadFile, activeDoc, currentView]);

  const saveSignature = async (dataUrl: string) => {
    const newSign = { id: Date.now().toString(), dataUrl, label: 'My Sign', createdAt: new Date().toISOString() };
    try {
      await db.saveSig(newSign);
      setSignatures(prev => [newSign, ...prev]);
      setShowSignaturePad(false);
    } catch (err) {
      console.error("Failed to save signature:", err);
    }
  };

  const handleSignFinish = async () => {
    const fileToUse = uploadFile || activeDoc?.fileData;
    if (!fileToUse) return;
    setIsLoading(true);

    const newDoc: DocumentRecord = {
      id: activeDoc?.id || Date.now().toString(),
      name: activeDoc?.name || 'Signed_Doc.pdf',
      type: 'PDF',
      status: 'SIGNED',
      date: new Date().toLocaleDateString('en-IN'),
      fileData: fileToUse,
      placedSignatures: [...placedSignatures]
    };

    try {
      await db.saveDoc(newDoc);
      await refreshDocuments();
      setActiveDoc(newDoc);
      setIsLoading(false);
      setShowSuccessScreen(true);
    } catch (err) {
      setIsLoading(false);
      console.error("Failed to save signed document:", err);
    }
  };

  const placeSignature = (sig: UserSignature) => {
    if (activeDoc?.status === 'SIGNED') return;
    const newPlaced: PlacedSignature = {
      id: Date.now().toString(),
      dataUrl: sig.dataUrl,
      x: 35, y: 40, w: 25,
      pageNumber: 1
    };
    setPlacedSignatures(prev => [...prev, newPlaced]);
  };

  const handleDrag = (id: string, initialPageNum: number, e: any) => {
    if (activeDoc?.status === 'SIGNED') return;
    if (e.target.closest('.resize-handle')) return;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const cy = 'touches' in me ? me.touches[0].clientY : me.clientY;

      let targetPageNum = initialPageNum;
      let targetRect = pageRefs.current[initialPageNum]?.getBoundingClientRect();

      for (let i = 1; i <= numPages; i++) {
        const canvas = pageRefs.current[i];
        if (!canvas) continue;
        const rect = canvas.getBoundingClientRect();
        if (cy >= rect.top && cy <= rect.bottom) {
          targetPageNum = i;
          targetRect = rect;
          break;
        }
      }

      if (targetRect) {
        const x = Math.max(-5, Math.min(95, ((cx - targetRect.left) / targetRect.width) * 100));
        const y = Math.max(-5, Math.min(95, ((cy - targetRect.top) / targetRect.height) * 100));
        setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, x, y, pageNumber: targetPageNum } : p));
      }
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const handleResize = (id: string, pageNum: number, e: any) => {
    e.stopPropagation();
    const canvas = pageRefs.current[pageNum];
    if (!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const initialX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const targetSig = placedSignatures.find(p => p.id === id);
    if (!targetSig) return;
    const initialW = targetSig.w || 25;

    const move = (me: any) => {
      const cx = 'touches' in me ? me.touches[0].clientX : me.clientX;
      const newW = Math.max(10, Math.min(90, initialW + ((cx - initialX) / rect.width) * 100));
      setPlacedSignatures(prev => prev.map(p => p.id === id ? { ...p, w: newW } : p));
    };

    const end = () => { 
      window.removeEventListener('mousemove', move); 
      window.removeEventListener('touchmove', move); 
    };

    window.addEventListener('mousemove', move);
    window.addEventListener('touchmove', move, { passive: false });
    window.addEventListener('mouseup', end);
    window.addEventListener('touchend', end);
  };

  const downloadDataUrl = (dataUrl: string, fileName: string) => {
    const link = document.createElement('a');
    link.href = dataUrl;
    link.download = fileName;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const generateProcessedBlob = async (doc: DocumentRecord): Promise<Blob | null> => {
    const fileToUse = doc.fileData;
    if (!fileToUse) return null;

    const docPlacedSigs = doc.placedSignatures || [];

    const pdfOutput = new jspdf.jsPDF({
      orientation: 'p',
      unit: 'pt',
      format: 'a4'
    });

    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d')!;

    const loadingTask = pdfjsLib.getDocument(fileToUse);
    const pdf = await loadingTask.promise;

    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const baseViewport = page.getViewport({ scale: 1 });
      const renderViewport = page.getViewport({ scale: 2 });

      canvas.width = renderViewport.width;
      canvas.height = renderViewport.height;
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      await page.render({ canvasContext: ctx, viewport: renderViewport }).promise;

      const orientation = baseViewport.width > baseViewport.height ? 'l' : 'p';
      if (i === 1) {
        pdfOutput.deletePage(1);
      }
      pdfOutput.addPage([baseViewport.width, baseViewport.height], orientation);

      pdfOutput.addImage(canvas.toDataURL('image/jpeg', 0.9), 'JPEG', 0, 0, baseViewport.width, baseViewport.height);

      const sigsOnPage = docPlacedSigs.filter(s => s.pageNumber === i);
      for (const s of sigsOnPage) {
        pdfOutput.addImage(s.dataUrl, 'PNG', (baseViewport.width * s.x)/100, (baseViewport.height * s.y)/100, (baseViewport.width * (s.w || 25)) / 100, ((baseViewport.width * (s.w || 25)) / 100) * 0.5);
      }
    }

    return pdfOutput.output('blob');
  };

  const processAndDownloadDoc = async (doc: DocumentRecord) => {
    setIsLoading(true);
    try {
      const blob = await generateProcessedBlob(doc);
      if (blob) {
        const url = URL.createObjectURL(blob);
        downloadDataUrl(url, `${doc.name}`);
        URL.revokeObjectURL(url);
      }
    } catch (err) {
      console.error("Critical download error:", err);
      alert("Error generating high-quality PDF. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleShare = async (isRequest: boolean = false) => {
    if (!activeDoc) return;
    setIsLoading(true);

    try {
      const blob = await generateProcessedBlob(activeDoc);
      if (!blob) throw new Error("Could not generate file");

      const fileName = activeDoc.name.endsWith('.pdf') ? activeDoc.name : `${activeDoc.name}.pdf`;
      const file = new File([blob], fileName, { type: 'application/pdf' });

      const shareData = {
        files: [file],
        title: activeDoc.name,
        text: isRequest 
          ? `Namaste! I have sent a document: ${activeDoc.name}. Please sign it digitally using SignX. Thank you!`
          : `Hi, here is the signed document: ${activeDoc.name}.`
      };

      if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share(shareData);
      } else {
        const text = encodeURIComponent(shareData.text);
        window.open(`https://wa.me/?text=${text}`, '_blank');
      }
    } catch (err) {
      console.error("Sharing failed:", err);
      alert("Sharing failed. You can still download the document and send it manually.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      <header className="bg-white border-b px-6 py-4 sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-3 cursor-pointer" onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }}>
          <AppLogo className="w-10 h-10" />
          <div>
            <div className="flex items-center gap-1">
              <h1 className="text-xl font-black text-[#1e3a8a] leading-none tracking-tight">SignX</h1>
              <h1 className="text-xl font-bold text-[#14b8a6] leading-none tracking-tight">PDF</h1>
            </div>
            <span className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em] text-center">Digital Bharat</span>
          </div>
        </div>
        <button onClick={() => setShowProfileMenu(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all hover:bg-white">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/95 z-[150] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-16 h-16 border-[6px] border-[#14b8a6] border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-900 tracking-tight text-lg">Processing...</p>
            <p className="text-sm text-slate-500 font-medium">Ensuring maximum quality.</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-[#14b8a6] rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Securely Signed</h2>
            <p className="text-gray-500 font-medium mb-10">Your document is ready.</p>
            <div className="space-y-3">
              <button onClick={() => activeDoc && processAndDownloadDoc(activeDoc)} className="w-full bg-gradient-to-r from-[#14b8a6] to-[#2563eb] text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-100 active:scale-95 transition-all">Download PDF</button>
              <button onClick={() => handleShare()} className="w-full bg-slate-900 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-xl shadow-slate-200">Attach & Share PDF</button>
              <button onClick={() => { setUploadFile(activeDoc?.fileData || null); setCurrentView(AppView.COMPRESS_PDF); }} className="w-full bg-emerald-50 text-[#14b8a6] font-bold py-5 rounded-2xl hover:bg-emerald-100 transition-all">Compress this PDF</button>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Dashboard</button>
            </div>
          </div>
        ) : currentView === AppView.TOOL_SUCCESS ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-[#14b8a6] rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Ready!</h2>
            <p className="text-gray-500 font-medium mb-10">Document processed and saved locally.</p>
            <div className="space-y-3">
              <button onClick={() => toolResultData && downloadDataUrl(toolResultData.dataUrl, toolResultData.name)} className="w-full bg-gradient-to-r from-[#14b8a6] to-[#2563eb] text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                <button onClick={proceedToSignFromTool} className="flex-1 bg-slate-800 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg text-xs">Add Signature</button>
                <button onClick={startCompressingFromTool} className="flex-1 bg-[#14b8a6] text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg text-xs">Compress PDF</button>
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Go to Dashboard</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <Dashboard 
                documents={documents} 
                onAction={(view) => setCurrentView(view)} 
                onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedSignatures(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} 
                onDeleteDoc={handleDeleteDoc}
                onDownloadDoc={processAndDownloadDoc}
              />
            )}

            {currentView === AppView.CREATE_RECEIPT && (
              <RentReceiptCreator onGenerate={handleReceiptGenerate} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.IMAGE_TO_PDF && (
              <ImageToPdfConverter onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.MERGE_PDF && (
              <PdfMerger onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.COMPRESS_PDF && (
              <PdfCompressor initialFile={uploadFile} onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500 pb-32">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'Document View' : 'Signing Area'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                   <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload PDF</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">Select a PDF document to sign</p>
                    <label className="bg-gradient-to-r from-[#14b8a6] to-[#2563eb] text-white px-12 py-5 rounded-2xl font-black cursor-pointer shadow-2xl shadow-blue-100 inline-block transition-transform active:scale-95">
                      Browse PDFs
                      <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-10">
                    <div className="flex flex-col items-center gap-8 px-2 overflow-y-auto scrollbar-hide">
                      {Array.from({ length: numPages }).map((_, idx) => {
                        const pageNum = idx + 1;
                        return (
                          <div key={pageNum} className="relative bg-white shadow-2xl leading-[0] border border-slate-200 rounded-sm">
                            <canvas 
                              ref={el => { pageRefs.current[pageNum] = el; }} 
                              className="max-w-full h-auto"
                            />
                            <div className="absolute inset-0 z-20 pointer-events-none">
                              {placedSignatures.filter(s => s.pageNumber === pageNum).map(ps => (
                                <div 
                                  key={ps.id} 
