  };

  const handleCompressAfterSign = async () => {
    if (!activeDoc) return;
    setIsLoading(true);
    try {
      const blob = await generateProcessedBlob(activeDoc);
      if (blob) {
        const reader = new FileReader();
        reader.onloadend = () => {
          setUploadFile(reader.result as string);
