        };
        reader.readAsDataURL(blob);
      }
    } catch (err) {
      console.error(err);
      setIsLoading(false);
    }
  };

  const handleShare = async (isRequest: boolean = false) => {
    if (!activeDoc) return;
    setIsLoading(true);

    try {
      const blob = await generateProcessedBlob(activeDoc);
      if (!blob) throw new Error("Could not generate file");

      const fileName = activeDoc.name.endsWith('.pdf') ? activeDoc.name : `${activeDoc.name}.pdf`;
      const file = new File([blob], fileName, { type: 'application/pdf' });

      const shareData = {
        files: [file],
        title: activeDoc.name,
        text: isRequest 
          ? `Hello! I have sent a document for you: ${activeDoc.name}.`
          : `Hi, here is the signed document: ${activeDoc.name}.`
      };

      if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
        await navigator.share(shareData);
      } else {
        const text = encodeURIComponent(shareData.text);
        window.open(`https://wa.me/?text=${text}`, '_blank');
      }
    } catch (err) {
      console.error("Sharing failed:", err);
      alert("Sharing failed. Please download the document manually.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
