          <AppLogo className="w-10 h-10" />
          <div>
            <div className="flex items-center gap-1">
              <h1 className="text-xl font-black text-[#1e3a8a] leading-none tracking-tight">SignX</h1>
              <h1 className="text-xl font-bold text-[#14b8a6] leading-none tracking-tight">PDF</h1>
            </div>
            <span className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em] text-center">Securely Local</span>
          </div>
        </div>
        <button onClick={() => setShowProfileMenu(true)} className="w-10 h-10 rounded-full bg-slate-50 border border-slate-200 flex items-center justify-center text-xl shadow-sm active:scale-90 transition-all hover:bg-white">👤</button>
      </header>

      <main className="flex-1 max-w-5xl mx-auto w-full p-4 md:p-8">
        {isLoading && (
          <div className="fixed inset-0 bg-white/95 z-[150] flex flex-col items-center justify-center gap-4 animate-in fade-in duration-300">
            <div className="w-16 h-16 border-[6px] border-[#14b8a6] border-t-transparent rounded-full animate-spin"></div>
            <p className="font-black text-gray-900 tracking-tight text-lg">Processing...</p>
            <p className="text-sm text-slate-500 font-medium">Finalizing your document.</p>
          </div>
        )}

        {showSuccessScreen ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-[#14b8a6] rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Securely Signed</h2>
            <p className="text-gray-500 font-medium mb-10">Your document is ready.</p>
            <div className="space-y-3">
              <button onClick={() => activeDoc && processAndDownloadDoc(activeDoc)} className="w-full bg-gradient-to-r from-[#14b8a6] to-[#2563eb] text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-100 active:scale-95 transition-all">Download PDF</button>
              <button onClick={() => handleShare()} className="w-full bg-slate-900 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-xl shadow-slate-200">Attach & Share PDF</button>
              <button onClick={handleCompressAfterSign} className="w-full bg-emerald-50 text-[#14b8a6] font-bold py-5 rounded-2xl hover:bg-emerald-100 transition-all">Compress Signed PDF</button>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Dashboard</button>
            </div>
          </div>
        ) : currentView === AppView.TOOL_SUCCESS ? (
          <div className="max-w-md mx-auto text-center py-16 px-8 bg-white rounded-[3rem] shadow-2xl border mt-10 animate-in zoom-in-95 duration-500">
            <div className="w-24 h-24 bg-emerald-50 text-[#14b8a6] rounded-full flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner shadow-emerald-100">✓</div>
            <h2 className="text-3xl font-black text-gray-900 mb-2">Ready!</h2>
            <p className="text-gray-500 font-medium mb-10">Document processed and saved locally.</p>
            <div className="space-y-3">
              <button onClick={() => toolResultData && downloadDataUrl(toolResultData.dataUrl, toolResultData.name)} className="w-full bg-gradient-to-r from-[#14b8a6] to-[#2563eb] text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-100 active:scale-95 transition-all">Download PDF</button>
              <div className="flex gap-2">
                <button onClick={proceedToSignFromTool} className="flex-1 bg-slate-800 text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg text-xs">Add Signature</button>
                {/* Hide redundant compression option if we just came from compression */}
                {currentView !== AppView.COMPRESS_PDF && (
                  <button onClick={startCompressingFromTool} className="flex-1 bg-[#14b8a6] text-white font-black py-5 rounded-2xl active:scale-95 transition-all shadow-lg text-xs">Compress PDF</button>
                )}
              </div>
              <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="w-full bg-slate-100 text-slate-600 font-bold py-5 rounded-2xl hover:bg-slate-200 transition-all">Go to Dashboard</button>
            </div>
          </div>
        ) : (
          <>
            {currentView === AppView.DASHBOARD && (
              <div className="flex flex-col min-h-full">
                <Dashboard 
                  documents={documents} 
                  onAction={(view) => setCurrentView(view)} 
                  onViewDoc={(doc) => { resetSigningState(); setActiveDoc(doc); setPlacedElements(doc.placedSignatures || []); setCurrentView(AppView.SIGN_DOC); }} 
                  onDeleteDoc={handleDeleteDoc}
                  onDownloadDoc={processAndDownloadDoc}
                />
                <BannerAd />
              </div>
            )}

            {currentView === AppView.CREATE_RECEIPT && (
              <RentReceiptCreator onGenerate={handleReceiptGenerate} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.IMAGE_TO_PDF && (
              <ImageToPdfConverter onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.MERGE_PDF && (
              <PdfMerger onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.COMPRESS_PDF && (
              <PdfCompressor initialFile={uploadFile} onComplete={handleToolComplete} onCancel={() => setCurrentView(AppView.DASHBOARD)} />
            )}

            {currentView === AppView.SIGN_DOC && (
              <div className="animate-in slide-in-from-bottom-6 duration-500 pb-32">
                <div className="flex justify-between items-center mb-6 px-2">
                   <h2 className="text-2xl font-black text-gray-900">{activeDoc?.status === 'SIGNED' ? 'Document View' : 'Signing Area'}</h2>
                   <button onClick={() => { resetSigningState(); setCurrentView(AppView.DASHBOARD); }} className="p-3 bg-white rounded-2xl shadow-sm border text-gray-400 hover:text-gray-900 transition-colors">✕</button>
                </div>

                {!uploadFile && !activeDoc && (
                   <div className="bg-white border-4 border-dashed border-slate-100 rounded-[3rem] p-16 text-center shadow-sm">
                    <div className="w-24 h-24 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center text-4xl mx-auto mb-6">📄</div>
                    <h3 className="text-xl font-black text-gray-800 mb-2">Upload PDF</h3>
                    <p className="text-sm text-gray-400 font-medium mb-10">Select a PDF to sign and add text.</p>
                    <label className="bg-gradient-to-r from-[#14b8a6] to-[#2563eb] text-white px-12 py-5 rounded-2xl font-black cursor-pointer shadow-2xl shadow-blue-100 inline-block transition-transform active:scale-95">
                      Browse PDFs
                      <input type="file" className="hidden" accept=".pdf" onChange={handleFileUpload} />
                    </label>
                  </div>
                )}

                {(uploadFile || activeDoc) && (
                  <div className="flex flex-col gap-10">
                    <div className="flex flex-col items-center gap-8 px-2 overflow-y-auto scrollbar-hide">
                      {Array.from({ length: numPages }).map((_, idx) => {
                        const pageNum = idx + 1;
                        return (
                          <div key={pageNum} className="relative bg-white shadow-2xl leading-[0] border border-slate-200 rounded-sm">
                            <canvas 
                              ref={el => { pageRefs.current[pageNum] = el; }} 
                              className="max-w-full h-auto"
                            />
                            <div className="absolute inset-0 z-20 pointer-events-none">
                              {placedElements.filter(s => s.pageNumber === pageNum).map(ps => (
                                <div 
                                  key={ps.id} 
                                  style={{ left: `${ps.x}%`, top: `${ps.y}%`, width: `${ps.w || 25}%` }} 
                                  className="absolute z-30 cursor-move touch-none pointer-events-auto animate-pulse-once" 
                                  onMouseDown={(e) => handleDrag(ps.id, pageNum, e)} 
                                  onTouchStart={(e) => handleDrag(ps.id, pageNum, e)}
                                >
                                  <div className="relative group">
                                    {ps.type === 'SIGNATURE' ? (
                                      <img src={ps.dataUrl} className={`w-full h-auto mix-blend-multiply border-2 border-dashed ${activeDoc?.status === 'SIGNED' ? 'border-transparent' : 'border-[#14b8a6]/50'} p-0.5`} />
                                    ) : (
                                      <input 
                                        type="text"
                                        value={ps.text}
                                        onChange={(e) => updateText(ps.id, e.target.value)}
                                        disabled={activeDoc?.status === 'SIGNED'}
                                        className={`w-full bg-transparent border-2 border-dashed outline-none font-bold text-sm px-1 ${activeDoc?.status === 'SIGNED' ? 'border-transparent text-black' : 'border-indigo-400/50 text-indigo-700 bg-indigo-50/20'}`}
                                      />
                                    )}

                                    {activeDoc?.status !== 'SIGNED' && (
                                      <>
                                        <button onClick={(e) => { e.stopPropagation(); setPlacedElements(p => p.filter(x => x.id !== ps.id)); }} className="absolute -top-4 -right-4 bg-red-500 text-white w-8 h-8 rounded-full text-xs flex items-center justify-center shadow-lg font-bold border-2 border-white z-40">✕</button>
                                        <div onMouseDown={(e) => handleResize(ps.id, pageNum, e)} onTouchStart={(e) => handleResize(ps.id, pageNum, e)} className="resize-handle absolute -bottom-4 -right-4 w-9 h-9 bg-[#14b8a6] border-4 border-white rounded-full cursor-nwse-resize shadow-xl flex items-center justify-center z-40">
                                          <div className="w-2.5 h-2.5 border-r-2 border-b-2 border-white rotate-45 mb-1 mr-1"></div>
                                        </div>
                                      </>
                                    )}
                                  </div>
                                </div>
                              ))}
                            </div>
                            <div className="absolute top-2 right-2 bg-black/40 text-white text-[10px] font-black px-2 py-1 rounded backdrop-blur-sm pointer-events-none">
                              Page {pageNum} / {numPages}
                            </div>
                          </div>
                        );
                      })}
                    </div>

                    <div className="fixed bottom-0 left-0 right-0 p-6 z-40 bg-white/80 backdrop-blur-md border-t border-slate-100 flex flex-col gap-4">
                       {activeDoc?.status === 'SIGNED' ? (
                         <div className="flex gap-3 max-w-lg mx-auto w-full">
                           <button onClick={() => activeDoc && processAndDownloadDoc(activeDoc)} className="flex-[2] bg-gradient-to-r from-[#14b8a6] to-[#2563eb] text-white font-black py-5 rounded-2xl shadow-xl shadow-blue-100 active:scale-95 transition-all">Download PDF</button>
                           <button onClick={() => handleShare()} className="flex-1 bg-slate-900 text-white font-black py-5 rounded-2xl active:scale-95 transition-all text-[10px] uppercase tracking-widest">Share</button>
                         </div>
                       ) : (
                         <div className="max-w-lg mx-auto w-full space-y-4">
                            <div className="flex gap-4 overflow-x-auto pb-1 scrollbar-hide items-center">
                              <button onClick={placeText} className="flex-shrink-0 w-14 h-14 bg-indigo-50 text-indigo-600 rounded-xl border-2 border-indigo-200 flex flex-col items-center justify-center shadow-sm hover:bg-indigo-100 transition-all active:scale-90">
                                <span className="text-xl font-black">T</span>
                                <span className="text-[7px] font-black uppercase tracking-widest">Text</span>
                              </button>

                              <div className="h-10 w-px bg-slate-200 mx-1 flex-shrink-0"></div>

                              {signatures.map(s => (
                                <button key={s.id} onClick={() => placeSignature(s)} className="flex-shrink-0 w-24 h-14 bg-white border-2 border-slate-100 rounded-xl flex items-center justify-center p-2 shadow-sm hover:border-[#14b8a6] transition-all active:scale-90 overflow-hidden">
                                  <img src={s.dataUrl} className="max-h-full mix-blend-multiply object-contain" />
                                </button>
                              ))}
                              <button onClick={() => setShowSignaturePad(true)} className="flex-shrink-0 w-14 h-14 bg-slate-50 text-slate-400 rounded-xl border-2 border-dashed border-slate-200 text-xl font-bold flex items-center justify-center active:bg-blue-50 transition-colors">+</button>
                            </div>
                            <button onClick={handleSignFinish} disabled={placedElements.length === 0} className="w-full bg-gradient-to-r from-[#14b8a6] to-[#2563eb] text-white font-black py-5 rounded-2xl shadow-2xl shadow-blue-100 disabled:opacity-30 transition-all active:scale-95">Complete & Save</button>
                         </div>
                       )}
                    </div>
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </main>

      {showProfileMenu && <ProfileMenu onClose={() => setShowProfileMenu(false)} />}
      {showSignaturePad && <SignaturePad onSave={saveSignature} onCancel={() => setShowSignaturePad(false)} />}

      <style>{`
        @keyframes pulse-once {
          0% { transform: scale(0.9); opacity: 0; }
          50% { transform: scale(1.05); opacity: 1; }
          100% { transform: scale(1); opacity: 1; }
        }
        .animate-pulse-once {
          animation: pulse-once 0.3s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { DocumentRecord, AppView } from '../types';

interface DashboardProps {
  documents: DocumentRecord[];
  onAction: (view: AppView) => void;
  onViewDoc: (doc: DocumentRecord) => void;
  onDeleteDoc: (id: string) => void;
  onDownloadDoc: (doc: DocumentRecord) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ documents, onAction, onViewDoc, onDeleteDoc, onDownloadDoc }) => {
  const [filter, setFilter] = useState<'ALL' | 'SIGNED'>('ALL');
  const [docToDelete, setDocToDelete] = useState<string | null>(null);

  const filteredDocs = useMemo(() => {
    if (filter === 'ALL') return documents;
    return documents.filter(d => d.status === filter);
  }, [documents, filter]);

  const confirmDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setDocToDelete(id);
  };

  const handleFinalDelete = () => {
    if (docToDelete) {
      onDeleteDoc(docToDelete);
      setDocToDelete(null);
    }
  };

  const handleDownload = (e: React.MouseEvent, doc: DocumentRecord) => {
    e.stopPropagation();
    onDownloadDoc(doc);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {docToDelete && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 p-6 backdrop-blur-md animate-in fade-in duration-200">
          <div className="w-full max-sm bg-white rounded-[3rem] p-10 shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="w-20 h-20 bg-red-50 text-red-500 rounded-full flex items-center justify-center text-4xl mx-auto mb-6 shadow-inner">🗑️</div>
            <h3 className="text-2xl font-black text-gray-900 text-center mb-2 tracking-tight">Delete this?</h3>
            <p className="text-slate-500 text-center text-sm font-medium leading-relaxed mb-10 px-2">
              This will permanently remove the document from your local storage.
            </p>
            <div className="flex flex-col gap-3">
              <button onClick={handleFinalDelete} className="w-full py-5 bg-red-500 text-white font-black rounded-2xl hover:bg-red-600 transition-all active:scale-95 shadow-xl shadow-red-100">Delete Forever</button>
              <button onClick={() => setDocToDelete(null)} className="w-full py-5 bg-slate-50 text-slate-600 font-bold rounded-2xl hover:bg-slate-100 transition-all">Cancel</button>
            </div>
          </div>
        </div>
      )}

      <div className="bg-gradient-to-br from-[#14b8a6] to-[#2563eb] p-10 rounded-[3rem] text-white shadow-2xl shadow-blue-100 relative overflow-hidden group">
        <div className="relative z-10">
          <p className="text-blue-100 text-[10px] font-black uppercase tracking-[0.2em] mb-2 opacity-80">Workspace Dashboard</p>
          <h2 className="text-4xl font-black mb-8 leading-tight tracking-tight">E-Sign Anything,<br/>Anywhere.</h2>
          <div className="flex gap-4">
             <div className="bg-white/10 backdrop-blur-xl px-6 py-3 rounded-2xl border border-white/20 shadow-inner">
                <span className="block text-3xl font-black">{documents.length}</span>
                <span className="text-[9px] uppercase font-black opacity-60 tracking-widest">Total Files</span>
             </div>
             <button onClick={() => onAction(AppView.SIGN_DOC)} className="bg-white text-[#2563eb] px-8 py-4 rounded-2xl font-black hover:shadow-2xl transition-all flex items-center gap-2 hover:bg-slate-50">
                <span className="text-xl">+</span> Sign New
             </button>
          </div>
        </div>
        <div className="absolute -right-20 -top-20 w-80 h-80 bg-white/10 rounded-full blur-[100px] pointer-events-none"></div>
        <div className="absolute -left-10 -bottom-10 w-40 h-40 bg-white/10 rounded-full blur-[60px] pointer-events-none"></div>
      </div>

      <div className="space-y-4">
        <h3 className="text-lg font-black text-slate-800 tracking-tight px-2">Quick Tools</h3>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 px-1">
          <button 
            onClick={() => onAction(AppView.IMAGE_TO_PDF)}
            className="flex flex-col items-center justify-center gap-3 p-5 bg-white rounded-[2rem] border border-slate-100 shadow-sm active:scale-95 transition-all group hover:border-[#14b8a6]/30"
          >
            <div className="w-10 h-10 bg-emerald-50 text-[#14b8a6] rounded-xl flex items-center justify-center text-lg shadow-sm border border-emerald-100 group-hover:bg-emerald-100">📸</div>
            <span className="text-[9px] font-black uppercase tracking-widest text-slate-600">Image to pdf</span>
          </button>
          <button 
            onClick={() => onAction(AppView.MERGE_PDF)}
            className="flex flex-col items-center justify-center gap-3 p-5 bg-white rounded-[2rem] border border-slate-100 shadow-sm active:scale-95 transition-all group hover:border-blue-200"
          >
            <div className="w-10 h-10 bg-blue-50 text-blue-500 rounded-xl flex items-center justify-center text-lg shadow-sm border border-blue-100 group-hover:bg-blue-100">📑</div>
            <span className="text-[9px] font-black uppercase tracking-widest text-slate-600">Merge Files</span>
          </button>
          <button 
            onClick={() => onAction(AppView.COMPRESS_PDF)}
            className="flex flex-col items-center justify-center gap-3 p-5 bg-white rounded-[2rem] border border-slate-100 shadow-sm active:scale-95 transition-all group hover:border-emerald-200"
          >
            <div className="w-10 h-10 bg-emerald-50 text-[#14b8a6] rounded-xl flex items-center justify-center text-lg shadow-sm border border-emerald-100 group-hover:bg-emerald-100">🗜️</div>
            <span className="text-[9px] font-black uppercase tracking-widest text-slate-600">Compress PDF</span>
          </button>
        </div>
      </div>

      <div className="flex items-center justify-between px-2">
         <h3 className="text-lg font-black text-slate-800 tracking-tight">Recent Activity</h3>
         <div className="flex bg-slate-100 p-1.5 rounded-2xl shadow-inner border border-slate-200/50">
            {(['ALL', 'SIGNED'] as const).map(f => (
              <button key={f} onClick={() => setFilter(f)} className={`text-[9px] px-5 py-2 rounded-xl font-black transition-all ${filter === f ? 'bg-white text-[#2563eb] shadow-md border border-slate-100' : 'text-slate-400 hover:text-slate-600'}`}>
                {f}
              </button>
            ))}
         </div>
      </div>

      <div className="space-y-4 pb-20">
        {filteredDocs.length > 0 ? filteredDocs.map((doc, idx) => (
          <div key={doc.id} onClick={() => onViewDoc(doc)} className="bg-white p-5 rounded-[2rem] border border-slate-100 shadow-sm flex items-center justify-between active:bg-blue-50/30 transition-all active:scale-[0.98] animate-in fade-in slide-in-from-bottom-4 duration-500" style={{ animationDelay: `${idx * 80}ms` }}>
            <div className="flex items-center gap-5 overflow-hidden flex-1">
              <div className={`w-14 h-14 rounded-2xl flex items-center justify-center text-2xl shadow-sm flex-shrink-0 ${doc.type === 'PDF' ? 'bg-red-50 text-red-500 border border-red-100' : 'bg-blue-50 text-[#2563eb] border border-blue-100'}`}>
                {doc.type === 'PDF' ? '📄' : '🖼️'}
              </div>
              <div className="overflow-hidden">
                <h4 className="text-sm font-black text-slate-800 truncate mb-1">{doc.name}</h4>
                <div className="flex items-center gap-2">
                  <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">{doc.date}</p>
                  <span className="w-1 h-1 rounded-full bg-slate-300"></span>
                  <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest">{doc.type}</p>
                </div>
              </div>
            </div>
            <div className="flex items-center gap-2 sm:gap-3 ml-4">
              <button onClick={(e) => handleDownload(e, doc)} className="w-10 h-10 bg-blue-50 text-[#2563eb] hover:bg-blue-100 rounded-xl transition-all border border-blue-100 flex items-center justify-center">
                📥
              </button>
              <button onClick={(e) => confirmDelete(e, doc.id)} className="w-10 h-10 bg-slate-50 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all border border-transparent hover:border-red-100 flex items-center justify-center">
                🗑️
              </button>
            </div>
          </div>
        )) : (
          <div className="py-24 text-center bg-white rounded-[3rem] border-4 border-dashed border-slate-50 shadow-inner">
             <div className="text-6xl mb-6 opacity-20 grayscale">📂</div>
             <p className="text-slate-400 text-sm font-black tracking-tight mb-8">No documents in storage.</p>
             <button onClick={() => onAction(AppView.SIGN_DOC)} className="px-10 py-4 bg-blue-50 text-[#2563eb] text-xs font-black uppercase tracking-widest rounded-2xl hover:bg-blue-100 transition-colors shadow-sm shadow-blue-50">Create New Doc</button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';

interface RentReceiptData {
  tenantName: string;
  landlordName: string;
  rentAmount: string;
  month: string;
  address: string;
  panNumber: string;
}

interface RentReceiptCreatorProps {
  onGenerate: (data: RentReceiptData) => void;
  onCancel: () => void;
}

const RentReceiptCreator: React.FC<RentReceiptCreatorProps> = ({ onGenerate, onCancel }) => {
  const [data, setData] = useState<RentReceiptData>({
    tenantName: '',
    landlordName: '',
    rentAmount: '',
    month: new Date().toLocaleString('en-IN', { month: 'long', year: 'numeric' }),
    address: '',
    panNumber: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onGenerate(data);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/70 p-4 backdrop-blur-md animate-in fade-in duration-300">
      <div className="w-full max-w-xl rounded-[2.5rem] bg-white p-8 shadow-2xl max-h-[90vh] overflow-y-auto scrollbar-hide">
        <div className="flex justify-between items-center mb-8">
          <div>
            <h3 className="text-2xl font-black text-gray-900 tracking-tight">Create Rent Receipt</h3>
            <p className="text-xs font-bold text-indigo-500 uppercase tracking-widest mt-1">HRA Compliant</p>
          </div>
          <button onClick={onCancel} className="p-3 bg-slate-50 rounded-2xl text-slate-400">✕</button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Tenant Name</label>
              <input required type="text" placeholder="Full Name" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm focus:bg-white focus:border-indigo-600 outline-none transition-all" value={data.tenantName} onChange={e => setData({...data, tenantName: e.target.value})} />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Landlord Name</label>
              <input required type="text" placeholder="Owner Name" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm focus:bg-white focus:border-indigo-600 outline-none transition-all" value={data.landlordName} onChange={e => setData({...data, landlordName: e.target.value})} />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Rent Amount</label>
            <input required type="number" placeholder="5000" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm focus:bg-white focus:border-indigo-600 outline-none transition-all" value={data.rentAmount} onChange={e => setData({...data, rentAmount: e.target.value})} />
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Property Address</label>
            <textarea required placeholder="House No, City, State" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-bold text-sm focus:bg-white focus:border-indigo-600 outline-none transition-all resize-none h-24" value={data.address} onChange={e => setData({...data, address: e.target.value})} />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
